import { useState, useMemo, useRef } from "react";
import { RefreshCw, Shield, Trash2, ChevronDown, Edit3, X, Search, ChevronUp } from "lucide-react";
import ProfileEditor from "./ProfileEditor";
import { api } from "../api/client";
import { useQueryClient } from "@tanstack/react-query";
import { toast } from "sonner";
import { useQueryState } from "nuqs";
import { useVirtualizer } from "@tanstack/react-virtual";
import {
  useReactTable,
  getCoreRowModel,
  getFilteredRowModel,
  getSortedRowModel,
  flexRender,
  createColumnHelper,
  SortingState,
} from "@tanstack/react-table";

const ROLES = ["unverified", "user", "author", "admin"];
const MEMBER_TYPES = ["student", "alumni", "parent", "coach", "mentor", "sponsor"];

type User = {
  id: string;
  name: string;
  image: string | null;
  role: string;
  createdAt: number;
  nickname?: string;
  member_type?: string;
  email?: string;
};

export default function AdminUsers() {
  const [editUserId, setEditUserId] = useState<string | null>(null);
  const [sorting, setSorting] = useState<SortingState>([]);
  const [globalFilter, setGlobalFilter] = useQueryState("q", { defaultValue: "" });
  const parentRef = useRef<HTMLDivElement>(null);
  const queryClient = useQueryClient();

  const { data, isLoading, isError } = api.users.getUsers.useQuery({
    queryKey: ["admin_users"],
  });

  const users = (data?.body?.users || []) as User[];

  const patchMutation = api.users.updateUser.useMutation({
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["admin_users"] });
      toast.success("User updated");
    },
    onError: (err: Error) => {
      toast.error(err.message || "Update failed");
    }
  });

  const changeRole = (userId: string, newRole: string) => {
    patchMutation.mutate({ params: { id: userId }, body: { role: newRole } });
  };

  const removeUser = (userId: string, name: string) => {
    if (!confirm(`Remove ${name}? This cannot be undone.`)) return;
    toast.info("Delete functionality to be implemented in contract fully");
  };

  const columnHelper = createColumnHelper<User>();

  const columns = useMemo(() => [
    columnHelper.accessor("name", {
      header: "User",
      cell: info => (
        <a href={`/profile/${info.row.original.id}`} target="_blank" rel="noopener noreferrer" className="flex items-center gap-3 hover:opacity-80 transition-opacity">
          <img src={info.row.original.image || `https://api.dicebear.com/9.x/bottts/svg?seed=${info.row.original.id}`}
            alt="" className="w-8 h-8 ares-cut-sm bg-obsidian" />
          <div>
            <span className="text-sm font-bold text-white block hover:text-ares-red">{info.row.original.nickname || info.getValue() || "ARES Member"}</span>
            <span className="text-[10px] text-white/40 font-mono">{info.row.original.id.slice(0, 8)}</span>
          </div>
        </a>
      ),
    }),
    columnHelper.accessor("email", {
      header: "Email",
      cell: info => <span className="text-sm text-white/60">{info.getValue() || "—"}</span>,
    }),
    columnHelper.accessor("role", {
      header: "Role",
      cell: info => (
        <div className="relative inline-block">
          <select
            value={info.getValue() || "user"}
            onChange={e => changeRole(info.row.original.id, e.target.value)}
            title="Change user role"
            className={`appearance-none bg-transparent border ares-cut-sm px-3 py-1 pr-7 text-xs font-bold cursor-pointer focus:outline-none ${
              info.getValue() === "admin" ? "border-ares-red/50 text-ares-red" :
              info.getValue() === "author" ? "border-ares-gold/50 text-ares-gold" :
              "border-white/20 text-white/60"
            }`}
          >
            {ROLES.map(r => <option key={r} value={r}>{r.charAt(0).toUpperCase() + r.slice(1)}</option>)}
          </select>
          <ChevronDown size={12} className="absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none text-white/60" />
        </div>
      ),
    }),
    columnHelper.accessor("member_type", {
      header: "Type",
      cell: info => (
        <div className="relative inline-block">
          <select
            value={info.getValue() || "student"}
            title="Change member type"
            className={`appearance-none bg-transparent border ares-cut-sm px-3 py-1 pr-7 text-xs font-bold cursor-pointer focus:outline-none capitalize ${
              info.getValue() === "alumni" ? "border-ares-gold/50 text-ares-gold" :
              ["parent", "coach", "mentor", "sponsor"].includes(info.getValue() || "") ? "border-ares-gold/30 text-ares-gold/70" :
              "border-white/20 text-white/60"
            }`}
          >
            {MEMBER_TYPES.map(m => <option key={m} value={m}>{m}</option>)}
          </select>
          <ChevronDown size={12} className="absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none text-white/60" />
        </div>
      ),
    }),
    columnHelper.accessor("createdAt", {
      header: "Joined",
      cell: info => <span className="text-xs text-white/60">{info.getValue() ? new Date(info.getValue()).toLocaleDateString() : "—"}</span>,
    }),
    columnHelper.display({
      id: "actions",
      header: () => <div className="text-right">Actions</div>,
      cell: info => (
        <div className="text-right">
          <button onClick={() => setEditUserId(info.row.original.id)}
            title="Edit user profile"
            aria-label={`Edit profile for ${info.row.original.name}`}
            className="p-2 mr-1 text-white/60 hover:text-ares-gold transition-all ares-cut-sm hover:bg-ares-gold/10">
            <Edit3 size={18} />
          </button>
          <button onClick={() => removeUser(info.row.original.id, info.row.original.nickname || info.row.original.name || "user")}
            title="Remove user"
            aria-label={`Remove user ${info.row.original.name}`}
            className="p-2 text-white/60 hover:text-ares-red transition-all ares-cut-sm hover:bg-ares-red/10">
            <Trash2 size={18} />
          </button>
        </div>
      ),
    }),
  ], [patchMutation]);

  const table = useReactTable({
    data: users,
    columns,
    state: {
      sorting,
      globalFilter,
    },
    onSortingChange: setSorting,
    onGlobalFilterChange: setGlobalFilter,
    getCoreRowModel: getCoreRowModel(),
    getSortedRowModel: getSortedRowModel(),
    getFilteredRowModel: getFilteredRowModel(),
  });

  const { rows } = table.getRowModel();

  const rowVirtualizer = useVirtualizer({
    count: rows.length,
    getScrollElement: () => parentRef.current,
    estimateSize: () => 56,
    overscan: 10,
  });

  if (isLoading) {
    return <div className="flex items-center justify-center py-20"><RefreshCw className="animate-spin text-ares-red" size={32} /></div>;
  }

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <h2 className="text-xl font-black tracking-tight flex items-center gap-2">
          <Shield size={20} className="text-ares-red" /> User Management
        </h2>
        <div className="flex items-center gap-4">
           <div className="relative">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-white/30" size={16} />
              <input
                type="text"
                value={globalFilter}
                onChange={e => setGlobalFilter(e.target.value)}
                placeholder="Search users..."
                className="bg-white/5 border border-white/10 ares-cut-sm pl-10 pr-4 py-2 text-sm text-white focus:border-ares-red outline-none transition-all w-64"
              />
           </div>
           <span className="text-white/60 text-sm font-bold whitespace-nowrap">{users.length} registered</span>
        </div>
      </div>

      {isError && (
        <div className="bg-ares-red/10 border border-ares-red/30 p-4 ares-cut-sm text-ares-red text-xs font-bold mb-6 flex items-center gap-2">
          <span className="w-2 h-2 rounded-full bg-ares-red animate-pulse" />
          TELEMETRY FAULT: Failed to synchronize user authority records.
        </div>
      )}

      <div className="overflow-x-auto bg-black/40 border border-white/5 ares-cut-lg">
        <div ref={parentRef} className="max-h-[600px] overflow-y-auto relative scrollbar-thin scrollbar-thumb-white/10">
          <table className="w-full text-left border-collapse">
            <thead className="sticky top-0 z-20 bg-ares-gray-deep/95 backdrop-blur-md">
              {table.getHeaderGroups().map(headerGroup => (
                <tr key={headerGroup.id} className="border-b border-white/10 bg-white/5">
                  {headerGroup.headers.map(header => (
                    <th 
                      key={header.id} 
                      className="px-4 py-4 text-xs font-black uppercase tracking-widest text-white/40 cursor-pointer hover:text-white transition-colors"
                      onClick={header.column.getToggleSortingHandler()}
                    >
                      <div className="flex items-center gap-2">
                        {flexRender(header.column.columnDef.header, header.getContext())}
                        {{
                          asc: <ChevronUp size={14} />,
                          desc: <ChevronDown size={14} />,
                        }[header.column.getIsSorted() as string] ?? null}
                      </div>
                    </th>
                  ))}
                </tr>
              ))}
            </thead>
            <tbody 
              className="relative"
              style={{ height: `${rowVirtualizer.getTotalSize()}px` }}
            >
              {rowVirtualizer.getVirtualItems().map(virtualRow => {
                const row = rows[virtualRow.index];
                if (!row) return null;
                return (
                  <tr 
                    key={row.id} 
                    className="hover:bg-white/[0.03] transition-colors group absolute w-full flex border-b border-white/5"
                    style={{ 
                      height: `${virtualRow.size}px`,
                      transform: `translateY(${virtualRow.start}px)`
                    }}
                  >
                    {row.getVisibleCells().map(cell => (
                      <td key={cell.id} className="px-4 py-2 flex items-center flex-1 overflow-hidden">
                        {flexRender(cell.column.columnDef.cell, cell.getContext())}
                      </td>
                    ))}
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>

      {editUserId && (
        <div className="fixed inset-0 z-50 bg-black/80 backdrop-blur-sm flex justify-center items-center p-4 sm:p-8 overflow-y-auto">
          <div className="bg-obsidian border border-white/10 ares-cut w-full max-w-4xl max-h-[90vh] overflow-y-auto shadow-2xl relative">
            <div className="sticky top-0 right-0 z-10 flex justify-end p-4 pointer-events-none">
              <button 
                onClick={() => setEditUserId(null)} 
                title="Close editor"
                className="p-2 bg-obsidian border border-white/10 ares-cut-sm text-white/60 hover:text-white pointer-events-auto shadow-xl"
              >
                <X size={20} />
              </button>
            </div>
            <div className="px-6 pb-6 pt-2">
              <div className="mb-4 pb-4 border-b border-white/10">
                <h3 className="text-xl font-black text-ares-red flex items-center gap-2">
                  <Shield size={20} />
                  Admin Override: Managing Profile
                </h3>
                <p className="text-white/60 text-sm">You are editing another user&apos;s personal profile data.</p>
              </div>
              <ProfileEditor adminEditUserId={editUserId} />
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

import { useQuery } from "@tanstack/react-query";
import { BarChart3, TrendingUp, Users, Clock, ExternalLink } from "lucide-react";
import { Link } from "react-router-dom";
import { api } from "../api/client";
import { BarList, Card, Title, Text, DonutChart, Flex } from "@tremor/react";

interface AnalyticsSummary {
  topPages: { path: string; category: string; views: number }[];
  recentViews: { path: string; category: string; user_agent: string; referrer: string; timestamp: string }[];
  totals: { category: string; total: number }[];
}

import DashboardPageHeader from "./dashboard/DashboardPageHeader";

export default function AnalyticsDashboard() {
  const { data: analyticsData, isLoading, isError } = api.analytics.getSummary.useQuery({
    queryKey: ["analytics-summary"],
  });

  const data = analyticsData?.body;

  if (isLoading) {
    return (
      <div className="flex flex-col gap-6 animate-pulse">
        <div className="h-32 bg-white/5 ares-cut-lg" />
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="h-64 bg-white/5 ares-cut-lg" />
          <div className="h-64 bg-white/5 ares-cut-lg" />
        </div>
      </div>
    );
  }

  const categoryColors: Record<string, string> = {
    doc: "cyan",
    blog: "amber",
    event: "red",
    system: "slate",
  };

  return (
    <div className="space-y-8">
      <DashboardPageHeader 
        title="Engagement Analytics" 
        subtitle="Real-time visibility into platform traffic and content performance."
        icon={<BarChart3 className="text-ares-cyan" />}
      />

      {isError && (
        <div className="bg-ares-red/10 border border-ares-red/30 p-4 ares-cut-sm text-ares-red text-xs font-bold mb-6 flex items-center gap-2">
          <span className="w-2 h-2 rounded-full bg-ares-red animate-pulse" />
          TELEMETRY FAULT: Failed to synchronize engagement metrics.
        </div>
      )}

      {/* Overview Stats */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
         <Card className="bg-black/40 border-white/5 ares-cut-lg">
            <Flex alignItems="start">
              <div className="truncate">
                <Text className="text-marble/40 uppercase tracking-widest font-black text-[10px]">Traffic Distribution</Text>
                <Title className="text-white text-3xl font-black">{data?.totals.reduce((acc, t) => acc + t.total, 0).toLocaleString()}</Title>
              </div>
              <BarChart3 className="text-ares-cyan" size={24} />
            </Flex>
            <DonutChart
              className="mt-6 h-40"
              data={data?.totals || []}
              category="total"
              index="category"
              colors={["cyan", "amber", "red", "slate"]}
              showAnimation={true}
            />
         </Card>
         
         <Card className="md:col-span-2 bg-black/40 border-white/5 ares-cut-lg">
            <Text className="text-marble/40 uppercase tracking-widest font-black text-[10px] mb-4">Top Performing Endpoints</Text>
            <BarList
              data={data?.topPages.map(p => ({ name: p.path, value: p.views })) || []}
              className="mt-2"
              color="amber"
            />
         </Card>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* Recent Activity */}
        <Card className="bg-black/40 border-white/5 ares-cut-lg p-6">
          <h3 className="text-lg font-bold text-white mb-6 flex items-center gap-2">
            <Clock size={20} className="text-ares-cyan" />
            Real-time Feed
          </h3>
          <div className="space-y-4 max-h-[400px] overflow-y-auto pr-2 custom-scrollbar">
            {data?.recentViews.map((view, idx) => (
              <div key={idx} className="flex flex-col gap-1 border-l border-white/5 pl-4 py-1 relative">
                <div className="absolute left-[-4px] top-2 w-2 h-2 rounded-full bg-ares-red shadow-[0_0_8px_rgba(192,0,0,0.5)]" />
                <div className="flex justify-between items-start">
                  <span className="text-xs text-marble font-medium truncate max-w-[200px]">{view.path}</span>
                  <span className="text-xs text-marble/40 font-mono">
                    {new Date(view.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                  </span>
                </div>
                <div className="flex items-center gap-2 text-[9px] text-marble/40 uppercase font-bold tracking-widest">
                  <span className={view.category === 'doc' ? 'text-ares-cyan' : view.category === 'blog' ? 'text-ares-gold' : 'text-marble/50'}>
                    {view.category}
                  </span>
                  <span>&middot;</span>
                  <span className="truncate max-w-[120px]">Ref: {view.referrer.replace(/https?:\/\/[^/]+/, '') || 'direct'}</span>
                </div>
              </div>
            ))}
          </div>
        </Card>

        {/* Detailed List */}
        <Card className="bg-black/40 border-white/5 ares-cut-lg p-6">
           <h3 className="text-lg font-bold text-white mb-6 flex items-center gap-2">
            <TrendingUp size={20} className="text-ares-gold" />
            Impact Breakdown
          </h3>
          <div className="space-y-3">
            {data?.topPages.map((page, idx) => (
              <div key={page.path} className="flex items-center justify-between group">
                <div className="flex items-center gap-3 overflow-hidden">
                  <span className="text-xs font-mono text-marble/40 w-4">0{idx + 1}</span>
                  <div className="flex flex-col truncate">
                    <Link to={page.path} className="text-sm text-marble hover:text-ares-gold transition-colors truncate flex items-center gap-1">
                      {page.path}
                      <ExternalLink size={10} className="opacity-0 group-hover:opacity-100 transition-opacity" />
                    </Link>
                    <span className="text-xs uppercase text-marble/40 font-bold tracking-tighter">{page.category}</span>
                  </div>
                </div>
                <div className="text-sm font-black text-white bg-white/5 px-2 py-1 ares-cut-sm">{page.views}</div>
              </div>
            ))}
          </div>
        </Card>
      </div>
    </div>
  );
}

import { useState } from "react";
import { useQueryClient } from "@tanstack/react-query";
import { FolderOpen } from "lucide-react";
import AssetUploader from "./assets/AssetUploader";
import AssetGrid from "./assets/AssetGrid";
import AssetSyndicateModal from "./assets/AssetSyndicateModal";
import { api } from "../api/client";
import { toast } from "sonner";

export default function AssetManager() {
  const queryClient = useQueryClient();
  const [syndicateKey, setSyndicateKey] = useState<string | null>(null);
  const [syndicateCaption, setSyndicateCaption] = useState("");
  const [selectedFolderFilter, setSelectedFolderFilter] = useState<string>("All");

  const { data, isLoading, isError } = api.media.adminList.useQuery({
    queryKey: ['media'],
  });

  const assets = data?.status === 200 ? data.body.media : [];

  const deleteMutation = api.media.delete.useMutation({
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['media'] });
      toast.success("Asset deleted");
    },
    onError: (err) => {
      toast.error(err.message || "Delete failed");
    }
  });

  const uploadMutation = api.media.upload.useMutation({
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['media'] });
    },
    onError: (err) => {
      toast.error(err.message || "Upload failed");
    }
  });

  const bulkUpload = async (files: File[]) => {
    let successCount = 0;
    for (const file of files) {
      const formData = new FormData();
      formData.append("file", file);
      formData.append("folder", selectedFolderFilter === "All" ? "Library" : selectedFolderFilter);

      try {
        await uploadMutation.mutateAsync({ body: formData });
        successCount++;
      } catch (err) {
        console.error("Upload error for file", file.name, err);
      }
    }
    if (successCount > 0) toast.success(`Uploaded ${successCount} assets`);
  };

  const syndicateMutation = api.media.syndicate.useMutation({
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['media'] });
      setSyndicateKey(null);
      setSyndicateCaption("");
      toast.success("Syndicated!");
    },
    onError: (err) => {
      toast.error(err.message || "Syndication failed");
    }
  });

  const moveMutation = api.media.move.useMutation({
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['media'] });
      toast.success("Asset moved");
    },
    onError: (err) => {
      toast.error(err.message || "Move failed");
    }
  });

  const uniqueFolders = Array.from(new Set(assets.map(a => a.folder))).filter(Boolean) as string[];
  const filteredAssets = selectedFolderFilter === "All" ? assets : assets.filter((a) => a.folder === selectedFolderFilter);

  return (
    <div className="flex-1 w-full flex flex-col min-h-0">
      <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4 mb-6">
        <div>
          <h2 className="text-2xl font-bold text-white tracking-tighter">Asset Vault</h2>
          <p className="text-marble/40 text-sm mt-1">
            {assets.length} asset{assets.length !== 1 && "s"} registered in the Edge.
          </p>
        </div>
        <div className="flex items-center gap-3">
          <AssetUploader 
            activeFolder={selectedFolderFilter === "All" ? "" : selectedFolderFilter}
            setActiveFolder={setSelectedFolderFilter}
            uploadMutation={{ ...uploadMutation, mutate: bulkUpload } as any}
            uploadProgress={null}
          />
        </div>
      </div>

      {isError && (
        <div className="bg-ares-red/10 border border-ares-red/30 p-4 ares-cut-sm text-ares-red text-xs font-bold mb-6 flex items-center gap-2">
          <span className="w-2 h-2 rounded-full bg-ares-red animate-pulse" />
          TELEMETRY FAULT: Failed to synchronize R2 asset metadata.
        </div>
      )}

      {isLoading ? (
        <div className="flex-1 flex items-center justify-center min-h-[300px]">
          <div className="w-8 h-8 md:w-12 md:h-12 border-4 border-white/10 border-t-ares-gold rounded-full animate-spin"></div>
        </div>
      ) : (
        <>
          <div className="flex items-center gap-2 mb-6 overflow-x-auto pb-2 custom-scrollbar">
             <button 
                onClick={() => setSelectedFolderFilter("All")}
                className={`px-4 py-1.5 ares-cut-sm text-xs font-bold uppercase tracking-widest transition-all ${selectedFolderFilter === "All" ? "bg-white text-black" : "bg-white/5 text-marble/90 border border-white/5 hover:bg-white/10"}`}
             >
                All Assets
             </button>
             {uniqueFolders.map(folder => (
                <button 
                  key={folder}
                  onClick={() => setSelectedFolderFilter(folder)}
                  className={`px-4 py-1.5 ares-cut-sm text-xs font-bold uppercase tracking-widest transition-all flex items-center gap-2 ${selectedFolderFilter === folder ? "bg-ares-gold text-black" : "bg-white/5 text-marble/90 border border-white/5 hover:bg-white/10"}`}
                >
                  <FolderOpen size={12} />
                  {folder}
                </button>
             ))}
          </div>

          <AssetGrid 
            assets={filteredAssets as any} 
            isDeleting={deleteMutation.isPending}
            onDelete={(key) => {
              if (confirm("Permanently purge this asset from R2?")) {
                deleteMutation.mutate({ params: { key }, body: {} });
              }
            }} 
            onSyndicate={(key) => setSyndicateKey(key)}
            onMove={(key, newFolder) => moveMutation.mutate({ params: { key }, body: { folder: newFolder } })}
          />
        </>
      )}

      <AssetSyndicateModal 
        syndicateKey={syndicateKey}
        setSyndicateKey={setSyndicateKey}
        syndicateCaption={syndicateCaption}
        setSyndicateCaption={setSyndicateCaption}
        syndicateMutation={syndicateMutation as any}
      />
    </div>
  );
}

import { useState } from "react";
import { useQuery } from "@tanstack/react-query";
import { X, ImagePlus } from "lucide-react";
import * as Dialog from "@radix-ui/react-dialog";
import { api } from "../api/client";

export type R2Asset = {
  key: string;
  size: number;
  uploaded: string;
  httpEtag: string;
  url: string;
  folder: string;
  tags: string;
};

export default function AssetPickerModal({
  isOpen,
  onClose,
  onSelect,
}: {
  isOpen: boolean;
  onClose: () => void;
  onSelect: (url: string, altText: string) => void;
}) {
  const [selectedFolderFilter, setSelectedFolderFilter] = useState<string>("All");

  const { data: mediaResponse, isLoading } = api.media.adminList.useQuery({
    queryKey: ["assets"],
    enabled: isOpen,
  });

  const assets = (mediaResponse?.body as any)?.media ?? [];
  const uniqueFolders = Array.from(new Set(assets.map(a => a.folder))).filter(Boolean);
  const filteredAssets = selectedFolderFilter === "All" ? assets : assets.filter(a => a.folder === selectedFolderFilter);

  return (
    <Dialog.Root open={isOpen} onOpenChange={(open) => !open && onClose()}>
      <Dialog.Portal>
        <Dialog.Overlay className="fixed inset-0 bg-black/80 backdrop-blur-sm z-[9999] data-[state=open]:animate-in data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=open]:fade-in-0" />
        <Dialog.Content 
          aria-describedby={undefined}
          className="fixed left-[50%] top-[50%] z-[10000] translate-x-[-50%] translate-y-[-50%] bg-obsidian border border-white/10 shadow-2xl ares-cut-lg w-[calc(100%-2rem)] max-w-5xl h-[80vh] flex flex-col overflow-hidden data-[state=open]:animate-in data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=open]:fade-in-0 data-[state=closed]:zoom-out-95 data-[state=open]:zoom-in-95 data-[state=closed]:slide-out-to-left-1/2 data-[state=closed]:slide-out-to-top-[48%] data-[state=open]:slide-in-from-left-1/2 data-[state=open]:slide-in-from-top-[48%] focus:outline-none"
        >
          {/* Header */}
          <div className="flex items-center justify-between p-6 border-b border-white/10 bg-black/40">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 bg-ares-gold/20 flex items-center justify-center ares-cut-sm border border-ares-gold/30">
                <ImagePlus className="text-ares-gold" size={20} aria-hidden="true" />
              </div>
              <div>
                <Dialog.Title className="text-xl font-black text-white tracking-widest uppercase m-0">Select Asset</Dialog.Title>
                <Dialog.Description className="text-xs text-white/60 font-mono m-0">Inject multimedia into the rich text block</Dialog.Description>
              </div>
            </div>
            <Dialog.Close asChild>
              <button
                aria-label="Close modal"
                className="w-10 h-10 flex items-center justify-center rounded-full bg-white/5 hover:bg-white/10 text-white transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ares-cyan"
              >
                <X size={20} aria-hidden="true" />
              </button>
            </Dialog.Close>
          </div>

          {/* Filters */}
          {!isLoading && assets.length > 0 && (
            <div className="px-6 py-4 bg-white/5 border-b border-white/10 flex flex-wrap gap-2 shadow-inner">
              <button 
                onClick={() => setSelectedFolderFilter("All")}
                className={`px-4 py-1.5 text-xs font-bold uppercase tracking-widest rounded-full border transition-all ${selectedFolderFilter === "All" ? "bg-ares-gold border-ares-gold text-black shadow-md" : "bg-black/50 border-white/10 text-white/60 hover:text-white hover:bg-white/10 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ares-cyan"}`}
              >All Assets</button>
              {uniqueFolders.map(folder => (
                <button 
                  key={folder}
                  onClick={() => setSelectedFolderFilter(folder)}
                  className={`px-4 py-1.5 text-xs font-bold uppercase tracking-widest rounded-full border transition-all ${selectedFolderFilter === folder ? "bg-white border-white text-black shadow-md" : "bg-black/50 border-white/10 text-white/60 hover:text-white hover:bg-white/10 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ares-cyan"}`}
                >{folder}</button>
              ))}
            </div>
          )}

          {/* Content */}
          <div 
            className="flex-1 overflow-y-auto p-6 bg-obsidian"
            aria-live="polite" // ACC-L01: Announce loading states and search updates
          >
            {isLoading ? (
              <div className="w-full h-full flex flex-col items-center justify-center gap-4">
                <div className="w-10 h-10 border-4 border-white/10 border-t-ares-gold rounded-full animate-spin"></div>
                <p className="text-xs font-bold uppercase tracking-widest text-ares-gold animate-pulse">Scanning R2 Vault...</p>
              </div>
            ) : assets.length === 0 ? (
              <div className="w-full h-full flex flex-col items-center justify-center text-white/20 gap-2">
                <ImagePlus size={48} className="opacity-50" aria-hidden="true" />
                <p className="font-mono text-sm">No assets available in the ARES vault.</p>
              </div>
            ) : (
              <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-5 gap-4">
                {filteredAssets.map(asset => (
                  <button
                    key={asset.key}
                    onClick={() => onSelect(asset.url, asset.tags || "ARES Media")}
                    aria-label={`Select asset ${asset.key}`}
                    className="group relative bg-black/20 border border-white/10 ares-cut-sm overflow-hidden hover:border-ares-gold transition-colors flex flex-col text-left focus:outline-none focus-visible:ring-2 focus-visible:ring-ares-cyan"
                  >
                    <div className="relative aspect-square w-full">
                      <img src={asset.url} alt={asset.key} className="w-full h-full object-cover" loading="lazy" />
                      <div className="absolute inset-0 bg-ares-gold/20 opacity-0 group-hover:opacity-100 transition-opacity" />
                    </div>
                    <div className="p-3">
                      <p className="text-white/60 text-xs font-mono truncate">{asset.key}</p>
                      <div className="flex items-center justify-between mt-2 pt-2 border-t border-white/5">
                        <span className="text-xs text-white/60 uppercase font-bold tracking-widest">
                          {(asset.size / 1024).toFixed(0)} KB
                        </span>
                        {asset.folder && (
                           <span className="text-[9px] bg-white/10 text-white/60 px-1.5 py-0.5 rounded font-bold uppercase">{asset.folder}</span>
                        )}
                      </div>
                    </div>
                  </button>
                ))}
              </div>
            )}
          </div>

        </Dialog.Content>
      </Dialog.Portal>
    </Dialog.Root>
  );
}

import { useState } from "react";
import DashboardPageHeader from "./dashboard/DashboardPageHeader";
import DashboardEmptyState from "./dashboard/DashboardEmptyState";
import DashboardLoadingGrid from "./dashboard/DashboardLoadingGrid";
import { DashboardInput, DashboardTextarea, DashboardSubmitButton } from "./dashboard/DashboardFormInputs";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { Plus, Trash2, Trophy, Star, Calendar, MapPin, XCircle, Save } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import { api } from "../api/client";
import { useForm, useWatch } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { z } from "zod";

import SeasonPicker from "./SeasonPicker";

const awardFormSchema = z.object({
  id: z.string().optional(),
  title: z.string().min(1, "Title is required"),
  year: z.coerce.number().min(2000).max(2100),
  event_name: z.string().optional().nullable(),
  image_url: z.string().optional().nullable(),
  description: z.string().optional().nullable(),
  season_id: z.string().optional().nullable(),
});

type AwardFormValues = z.infer<typeof awardFormSchema>;

interface Award {
  id: string;
  title: string;
  year: number;
  event_name: string | null;
  image_url: string | null;
  description: string | null;
  season_id?: string;
}

export default function AwardEditor() {
  const queryClient = useQueryClient();
  const [isAdding, setIsAdding] = useState(false);

  const { register, handleSubmit, reset, setValue, control, formState: { errors } } = useForm<AwardFormValues>({
    resolver: zodResolver(awardFormSchema),
    defaultValues: {
      year: new Date().getFullYear(),
      title: "",
      event_name: "",
      image_url: "",
      description: "",
      season_id: ""
    }
  });

  const seasonId = useWatch({ control, name: "season_id" });

  const { data: awardsData, isLoading, isError } = api.awards.getAwards.useQuery({
    queryKey: ["admin-awards"],
  });
  const awards = (awardsData?.body?.awards || []) as Award[];

  const saveMutation = api.awards.saveAward.useMutation({
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["admin-awards"] });
      setIsAdding(false);
      reset();
    }
  });

  const deleteMutation = api.awards.deleteAward.useMutation({
    onSuccess: () => queryClient.invalidateQueries({ queryKey: ["admin-awards"] })
  });

  const onFormSubmit = (data: AwardFormValues) => {
    const finalId = data.id || `${data.year}-${data.title.toLowerCase().replace(/[^a-z0-9]+/g, '-')}`;
    saveMutation.mutate({ body: { ...data, id: finalId } as any });
  };

  return (
    <div className="space-y-8">
      <DashboardPageHeader
        title="Trophy Case Management"
        subtitle="Archiving the milestones of ARES 23247."
        icon={<Trophy className="text-ares-gold" />}
        italicTitle={true}
        action={
          <button
            onClick={() => {
              if (isAdding) {
                setIsAdding(false);
                reset();
              } else {
                setIsAdding(true);
              }
            }}
            className="flex items-center gap-2 px-4 py-2 bg-ares-red text-white font-bold ares-cut-sm hover:bg-ares-danger transition-colors shadow-lg shadow-ares-red/20"
          >
            {isAdding ? <XCircle size={18} /> : <Plus size={18} />}
            {isAdding ? "Cancel" : "Add Award"}
          </button>
        }
      />

      {isError && (
        <div className="bg-ares-red/10 border border-ares-red/30 p-4 ares-cut-sm text-ares-red text-xs font-bold mb-6 flex items-center gap-2">
          <span className="w-2 h-2 rounded-full bg-ares-red animate-pulse" />
          TELEMETRY FAULT: Failed to synchronize achievement records.
        </div>
      )}

      <AnimatePresence>
        {isAdding && (
          <motion.form
            initial={{ opacity: 0, scale: 0.95 }}
            animate={{ opacity: 1, scale: 1 }}
            exit={{ opacity: 0, scale: 0.95 }}
            onSubmit={handleSubmit(onFormSubmit)}
            className="bg-obsidian border border-ares-gold/30 ares-cut-lg p-8 space-y-6 shadow-2xl"
          >
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              <DashboardInput
                id="award-title"
                label="Award Title"
                {...register("title")}
                error={errors.title?.message}
                placeholder="e.g. Excellence in Engineering"
                focusColor="ares-gold"
                fullWidth
              />
              <DashboardInput
                id="award-year"
                type="number"
                label="Year"
                {...register("year")}
                error={errors.year?.message}
                focusColor="ares-gold"
              />
              <DashboardInput
                id="award-eventName"
                label="Event Name"
                {...register("event_name")}
                placeholder="e.g. West Virginia State Championship"
                focusColor="ares-gold"
              />
              <SeasonPicker value={seasonId || ""} onChange={(val) => setValue("season_id", val)} />
              <DashboardInput
                id="award-image"
                label="Image URL (Optional)"
                {...register("image_url")}
                placeholder="https://..."
                focusColor="ares-gold"
                fullWidth
              />
              <DashboardTextarea
                id="award-desc"
                label="Description"
                {...register("description")}
                placeholder="Tell the story of how we won..."
                focusColor="ares-gold"
                fullWidth
              />
            </div>
            <DashboardSubmitButton 
              isPending={saveMutation.isPending} 
              defaultText="Commemorate Achievement" 
              icon={<Save size={20} />} 
              theme="gold" 
            />
          </motion.form>
        )}
      </AnimatePresence>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {isLoading ? (
          <DashboardLoadingGrid count={2} heightClass="h-48" gridClass="grid-cols-1 lg:grid-cols-2" />
        ) : awards.map((award) => (
          <div key={award.id} className="bg-black/40 border border-white/5 rounded-[2.5rem] p-8 group hover:border-ares-gold/30 transition-all flex flex-col md:flex-row gap-8 relative overflow-hidden">
            {/* Background Glow */}
            <div className="absolute -top-12 -right-12 w-32 h-32 bg-ares-gold/5 blur-3xl rounded-full pointer-events-none" />
            
            {award.image_url ? (
              <div className="w-full md:w-32 h-32 bg-white/5 ares-cut overflow-hidden flex-shrink-0 border border-white/10">
                <img src={award.image_url} alt={award.title} className="w-full h-full object-cover" />
              </div>
            ) : (
              <div className="w-full md:w-32 h-32 bg-white/5 ares-cut flex items-center justify-center flex-shrink-0 border border-white/10">
                <Trophy size={48} className="text-ares-gold/20" />
              </div>
            )}

            <div className="flex-1">
              <div className="flex items-center gap-3 text-ares-gold text-xs font-black uppercase tracking-widest mb-2">
                 <span className="flex items-center gap-1"><Calendar size={12} /> {award.year}</span>
                 <span className="flex items-center gap-1">&middot; <Star size={12} className="fill-ares-gold" /> Blue Banner</span>
              </div>
              <h4 className="text-2xl font-black text-white mb-2 italic tracking-tighter">{award.title}</h4>
              <div className="flex items-center gap-2 text-ares-gray text-xs font-bold mb-4">
                 <MapPin size={10} /> {award.event_name}
              </div>
              <p className="text-ares-gray text-sm line-clamp-3 leading-relaxed">{award.description}</p>
            </div>

            <button
              onClick={() => { if(confirm("Purge this achievement from history?")) deleteMutation.mutate({ params: { id: award.id }, body: {} }); }}
              className="absolute top-4 right-4 p-3 text-ares-gray hover:text-ares-red transition-colors bg-white/5 ares-cut opacity-0 group-hover:opacity-100"
            >
              <Trash2 size={18} />
            </button>
          </div>
        ))}
        {awards.length === 0 && !isLoading && !isAdding && (
          <DashboardEmptyState
            className="col-span-full py-20 text-center border-2 border-dashed border-white/5 ares-cut-lg"
            icon={<Trophy size={48} />}
            message="The trophy case is currently empty. Go win some banners!"
          />
        )}
      </div>
    </div>
  );
}

import { useState, useMemo } from "react";
import { useQueryClient } from "@tanstack/react-query";
import { Award, Plus, UserPlus, Check, X } from "lucide-react";
import { toast } from "sonner";
import * as LucideIcons from "lucide-react";
import { api } from "../api/client";
import { ClickToDeleteButton } from "./ContentManager/shared";

interface BadgeDef {
  id: string;
  name: string;
  description: string;
  icon: string;
  color_theme: string;
  created_at: string;
}

import DashboardPageHeader from "./dashboard/DashboardPageHeader";

export default function BadgeManager() {
  const queryClient = useQueryClient();
  const [showCreate, setShowCreate] = useState(false);
  const [newBadgeId, setNewBadgeId] = useState("");
  const [newBadgeName, setNewBadgeName] = useState("");
  const [newBadgeDesc, setNewBadgeDesc] = useState("");
  const [newBadgeIcon, setNewBadgeIcon] = useState("Award");
  const [newBadgeColor, setNewBadgeColor] = useState("ares-gold");

  const [selectedUser, setSelectedUser] = useState<string>("");
  const [selectedBadge, setSelectedBadge] = useState<string>("");
  const [confirmId, setConfirmId] = useState<string | null>(null);

  const { data: badgesData, isLoading: badgesLoading, isError: isBadgesError } = api.badges.list.useQuery({
    queryKey: ["admin_badges"]
  });

  const { data: usersData, isError: isUsersError } = api.users.adminList.useQuery({
    queryKey: ["admin_users_list"]
  });

  const createBadgeMutation = api.badges.create.useMutation({
    onSuccess: (res) => {
      if (res.status === 200) {
        toast.success("Badge definition created.");
        queryClient.invalidateQueries({ queryKey: ["admin_badges"] });
        setShowCreate(false);
        setNewBadgeId("");
        setNewBadgeName("");
        setNewBadgeDesc("");
      } else {
        toast.error("Failed to create badge.");
      }
    }
  });

  const awardBadgeMutation = api.badges.grant.useMutation({
    onSuccess: (res) => {
      if (res.status === 200) {
        toast.success("Badge awarded successfully!");
        setSelectedUser("");
        setSelectedBadge("");
      } else {
        toast.error("Failed to award badge.");
      }
    },
    onError: (err: Error) => {
      toast.error(`Error awarding badge: ${err.message}`);
    }
  });

  const deleteBadgeMutation = api.badges.delete.useMutation({
    onSuccess: (res) => {
      if (res.status === 200) {
        toast.success("Badge definition deleted.");
        queryClient.invalidateQueries({ queryKey: ["admin_badges"] });
        setConfirmId(null);
      } else {
        toast.error("Failed to delete badge definition.");
      }
    },
    onError: (err: Error) => {
      toast.error(`Error deleting badge: ${err.message}`);
    }
  });

  const revokeBadgeMutation = api.badges.revoke.useMutation({
    onSuccess: (res) => {
      if (res.status === 200) {
        toast.success("Badge revoked successfully.");
        queryClient.invalidateQueries({ queryKey: ["admin_badges"] });
      } else {
        toast.error("Failed to revoke badge.");
      }
    },
    onError: (err: Error) => {
      toast.error(`Error revoking badge: ${err.message}`);
    }
  });

  const badges = useMemo(() => badgesData?.body?.badges || [], [badgesData]);
  const users = useMemo(() => usersData?.body?.users || [], [usersData]);

  return (
    <div className="space-y-8">
      <DashboardPageHeader 
        title="Badge Management" 
        subtitle="Define platform-wide awards and distribute them to members."
        icon={<Award className="text-ares-gold" />}
      />
      {(isBadgesError || isUsersError) && (
        <div className="bg-ares-red/10 border border-ares-red/30 p-4 ares-cut-sm text-ares-red text-xs font-bold mb-6 flex items-center gap-2">
          <span className="w-2 h-2 rounded-full bg-ares-red animate-pulse" />
          TELEMETRY FAULT: Failed to synchronize merit records.
        </div>
      )}
      {/* Creation Panel */}
      <div className="bg-ares-gray-dark border border-white/10 ares-cut overflow-hidden shadow-2xl">
        <div className="p-6 border-b border-white/10 flex justify-between items-center">
          <div>
            <h3 className="text-xl font-black text-white flex items-center gap-2">
              <Award className="text-ares-gold" size={24} /> Badge Index
            </h3>
            <p className="text-sm text-white/50 mt-1">Define platform-wide awards and training certifications.</p>
          </div>
          <button 
            onClick={() => setShowCreate(!showCreate)}
            className="px-4 py-2 bg-ares-red/10 text-ares-red hover:bg-ares-red hover:text-white transition-all ares-cut-sm text-sm font-bold flex items-center gap-2"
          >
            {showCreate ? <><X size={16}/> Cancel</> : <><Plus size={16} /> New Badge Type</>}
          </button>
        </div>

        {showCreate && (
          <div className="p-6 bg-black/40 border-b border-white/10 space-y-4">
            <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
              <div>
                <label htmlFor="badge-id" className="text-xs font-bold text-white/60 uppercase tracking-widest pl-1">Badge ID (slug)</label>
                <input id="badge-id" type="text" value={newBadgeId} onChange={e => setNewBadgeId(e.target.value)} placeholder="e.g. outreach_mvp" className="w-full bg-ares-gray-dark border border-white/5 ares-cut-sm px-4 py-2.5 text-white focus:outline-none focus:border-ares-gold mt-1" />
              </div>
              <div>
                <label htmlFor="badge-name" className="text-xs font-bold text-white/60 uppercase tracking-widest pl-1">Display Name</label>
                <input id="badge-name" type="text" value={newBadgeName} onChange={e => setNewBadgeName(e.target.value)} placeholder="Outreach MVP" className="w-full bg-ares-gray-dark border border-white/5 ares-cut-sm px-4 py-2.5 text-white focus:outline-none focus:border-ares-gold mt-1" />
              </div>
              <div>
                <label htmlFor="badge-icon" className="text-xs font-bold text-white/60 uppercase tracking-widest pl-1">Icon (Lucide Node)</label>
                <input id="badge-icon" type="text" value={newBadgeIcon} onChange={e => setNewBadgeIcon(e.target.value)} placeholder="Award" className="w-full bg-ares-gray-dark border border-white/5 ares-cut-sm px-4 py-2.5 text-white focus:outline-none focus:border-ares-gold mt-1" />
              </div>
              <div>
                <label htmlFor="badge-color" className="text-xs font-bold text-white/60 uppercase tracking-widest pl-1">Color Theme (CSS)</label>
                <input id="badge-color" type="text" value={newBadgeColor} onChange={e => setNewBadgeColor(e.target.value)} placeholder="ares-gold" className="w-full bg-ares-gray-dark border border-white/5 ares-cut-sm px-4 py-2.5 text-white focus:outline-none focus:border-ares-gold mt-1" />
              </div>
            </div>
            <div>
              <label htmlFor="badge-desc" className="text-xs font-bold text-white/60 uppercase tracking-widest pl-1">Description</label>
              <input id="badge-desc" type="text" value={newBadgeDesc} onChange={e => setNewBadgeDesc(e.target.value)} placeholder="Awarded to members who attain top 3 in outreach hours." className="w-full bg-ares-gray-dark border border-white/5 ares-cut-sm px-4 py-2.5 text-white focus:outline-none focus:border-ares-gold mt-1" />
            </div>
            <button 
              onClick={() => createBadgeMutation.mutate({ body: { id: newBadgeId, name: newBadgeName, description: newBadgeDesc, icon: newBadgeIcon, color_theme: newBadgeColor } })} 
              disabled={createBadgeMutation.isPending || !newBadgeId || !newBadgeName}
              className="px-6 py-2.5 bg-white text-black font-bold text-sm ares-cut-sm hover:bg-white transition-all disabled:opacity-50"
            >
              {createBadgeMutation.isPending ? "Creating..." : "Save Badge Definition"}
            </button>
          </div>
        )}

        {/* Existing Badges List */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 p-6 bg-ares-gray-deep">
          {badgesLoading ? (
            <p className="text-white/60 text-sm">Loading badges...</p>
          ) : badges.length === 0 ? (
            <p className="text-white/60 text-sm">No badges defined yet.</p>
          ) : (
            badges.map((b: any) => {
              const IconComp = (LucideIcons as unknown as Record<string, React.ElementType>)[b.icon] || LucideIcons.Award;
              return (
                <div key={b.id} className="bg-ares-gray-dark/50 border border-white/10 ares-cut-sm p-4 flex items-start gap-4">
                  <div className={`p-3 ares-cut-sm bg-obsidian/50 flex-shrink-0 text-${b.color_theme.replace("text-", "")}`}>
                    <IconComp size={24} />
                  </div>
                  <div className="flex-1">
                    <h4 className="text-white font-bold">{b.name}</h4>
                    <p className="text-xs text-white/60 mt-0.5">{b.description || "No description provided."}</p>
                    <p className="text-xs text-white/20 font-mono mt-2">ID: {b.id}</p>
                  </div>
                  <div className="flex-shrink-0 self-start">
                    <ClickToDeleteButton 
                      id={`badge-def-${b.id}`}
                      onDelete={() => deleteBadgeMutation.mutate({ params: { id: b.id }, body: null })}
                      isDeleting={deleteBadgeMutation.isPending && deleteBadgeMutation.variables?.params.id === b.id}
                      confirmId={confirmId}
                      setConfirmId={setConfirmId}
                    />
                  </div>
                </div>
              );
            })
          )}
        </div>
      </div>

      {/* Grant Panel */}
      <div className="bg-ares-gray-dark border border-white/10 ares-cut p-6 shadow-2xl">
        <h3 className="text-xl font-black text-white flex items-center gap-2 mb-6">
          <UserPlus className="text-ares-red" size={24} /> Manual Badge Grant
        </h3>
        <div className="flex flex-col md:flex-row gap-4">
          <div className="flex-1">
            <label htmlFor="grant-user" className="text-xs font-bold text-white/60 uppercase tracking-widest pl-1">Target Member</label>
            <select id="grant-user" value={selectedUser} onChange={e => setSelectedUser(e.target.value)} className="w-full bg-black border border-white/10 ares-cut-sm px-4 py-3 text-white focus:outline-none focus:border-ares-red mt-1">
              <option value="">-- Select Member --</option>
              {users.map((u: any) => (
                <option key={u.id} value={u.id}>{u.name || u.nickname} ({u.email})</option>
              ))}
            </select>
          </div>
          <div className="flex-1">
            <label htmlFor="grant-badge" className="text-xs font-bold text-white/60 uppercase tracking-widest pl-1">Select Badge</label>
            <select id="grant-badge" value={selectedBadge} onChange={e => setSelectedBadge(e.target.value)} className="w-full bg-black border border-white/10 ares-cut-sm px-4 py-3 text-white focus:outline-none focus:border-ares-red mt-1">
              <option value="">-- Select Badge --</option>
              {badges.map((b: any) => (
                <option key={b.id} value={b.id}>{b.name}</option>
              ))}
            </select>
          </div>
        </div>
        <button 
          onClick={() => awardBadgeMutation.mutate({ body: { userId: selectedUser, badgeId: selectedBadge } })}
          disabled={!selectedUser || !selectedBadge || awardBadgeMutation.isPending}
          className="mt-6 px-8 py-3 bg-ares-red text-white font-black uppercase tracking-widest ares-cut-sm hover:bg-ares-danger transition-all disabled:opacity-50 flex items-center gap-2"
        >
          {awardBadgeMutation.isPending ? "Processing..." : <><Check size={18} /> Grant Badge to Member</>}
        </button>
      </div>
    </div>
  );
}

