interface SeasonManagerTabProps {
  view: ViewType;
  onEdit?: (id: string) => void;
  confirmId: string | null;
  setConfirmId: (id: string | null) => void;
}

export default function SeasonManagerTab({
  view,
  onEdit,
  confirmId,
  setConfirmId,
}: SeasonManagerTabProps) {
  const queryClient = useQueryClient();

  const { data, isLoading, isError } = api.seasons.adminList.useQuery({
    queryKey: ["admin-seasons"],
  });

  const seasons = data?.status === 200 ? data.body.seasons : [];

  const deleteMutation = api.seasons.delete.useMutation({
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["admin-seasons"] });
      setConfirmId(null);
      toast.success("Season deleted");
    }
  });

  const restoreMutation = api.seasons.undelete.useMutation({
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["admin-seasons"] });
      toast.success("Season restored");
    }
  });

  const purgeMutation = api.seasons.purge.useMutation({
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["admin-seasons"] });
      setConfirmId(null);
      toast.success("Season purged");
    }
  });

  if (isLoading) return <div className="h-32 flex items-center justify-center"><div className="w-6 h-6 border-2 border-white/10 border-t-ares-gold rounded-full animate-spin"></div></div>;

  const filtered = seasons.filter(s => {
    const isDeleted = Number(s.is_deleted) === 1;
    if (view === 'trash') return isDeleted;
    if (view === 'pending') return !isDeleted && s.status === 'draft';
    return !isDeleted && s.status === 'published';
  });

  return (
    <div className="flex flex-col flex-1 min-h-0">
      <h3 className="text-xs font-black uppercase tracking-[0.2em] text-white/40 mb-4 px-1 flex items-center gap-2">
        <History size={12} className={isLoading ? "animate-pulse text-ares-red" : "text-ares-red"} />
        Season Archive
        {isError && (
          <span className="ml-auto text-[9px] text-ares-red animate-pulse flex items-center gap-1">
            TELEMETRY FAULT
          </span>
        )}
      </h3>

      <div className="text-xs text-marble/20 mb-2 px-1 flex justify-between items-center font-mono uppercase tracking-widest border-b border-white/5 pb-1">
        <span>VIEW: {view} | RAW: {seasons.length} | FILTERED: {filtered.length}</span>
        {isError && <span className="text-ares-red font-bold">API ERROR!</span>}
      </div>

      <div className="flex flex-col gap-3 overflow-y-auto flex-1 min-h-0 pr-2 custom-scrollbar">
        {filtered.length === 0 ? (
          <DashboardEmptyState
            className="text-marble/50 text-xs italic py-8 text-center border border-dashed border-white/5 ares-cut-sm"
            icon={<History size={24} />}
            message={`No ${view} seasons found.`}
          />
        ) : (
          filtered.map((season) => {
            const seasonId = season.start_year.toString();
            return (
              <div key={seasonId} className={`bg-black/40 border ${Number(season.is_deleted) === 1 ? 'border-ares-red/30 bg-ares-red/[0.02]' : 'border-white/10'} ares-cut-sm p-4 flex flex-col justify-between gap-4 hover:border-ares-gold/20 transition-colors`}>
                <div className="flex-1 min-w-0">
                  <div className="font-bold text-marble/90 truncate flex items-center gap-2">
                    {season.start_year}-{season.end_year} | {season.challenge_name}
                    {Number(season.is_deleted) === 1 && <span className="text-[9px] font-bold text-ares-red bg-ares-red/10 border border-ares-red/20 px-1.5 py-0.5 rounded uppercase tracking-wider">Deleted</span>}
                    {season.status === 'draft' && <span className="text-[9px] font-bold text-ares-gold bg-ares-gold/10 border border-ares-gold/20 px-1.5 py-0.5 rounded uppercase tracking-wider">Draft</span>}
                  </div>
                  <div className="flex items-center gap-2 mt-1">
                    <span className="text-xs text-marble/40 bg-obsidian border border-white/10 px-2 py-0.5 ares-cut-sm uppercase tracking-widest">{season.robot_name || 'No Robot Assigned'}</span>
                  </div>
                </div>
                <div className="flex flex-wrap items-center gap-2 pt-2 border-t border-white/10">
                  {Number(season.is_deleted) !== 1 ? (
                    <>
                      <button
                        onClick={() => onEdit && onEdit(seasonId)}
                        className="text-xs font-bold text-marble/40 hover:text-ares-gold bg-white/5 hover:bg-white/10 px-3 py-1 ares-cut-sm transition-colors"
                      >
                        EDIT
                      </button>
                      <ClickToDeleteButton 
                        id={seasonId} 
                        onDelete={() => deleteMutation.mutate({ params: { id: seasonId }, body: null })} 
                        isDeleting={deleteMutation.isPending && (deleteMutation.variables as any)?.params?.id === seasonId} 
                        confirmId={confirmId}
                        setConfirmId={setConfirmId}
                      />
                    </>
                  ) : (
                    <>
                      <button
                        onClick={() => restoreMutation.mutate({ params: { id: seasonId }, body: null })}
                        disabled={restoreMutation.isPending}
                        className="text-xs font-bold text-ares-gold bg-ares-gold/10 hover:bg-ares-gold/20 px-3 py-1 ares-cut-sm transition-colors"
                      >
                        {(restoreMutation.isPending && (restoreMutation.variables as any)?.params?.id === seasonId) ? "RESTORING..." : "RESTORE"}
                      </button>
                      <ClickToDeleteButton 
                        id={`purge-${seasonId}`} 
                        onDelete={() => purgeMutation.mutate({ params: { id: seasonId }, body: null })} 
                        isDeleting={purgeMutation.isPending && (purgeMutation.variables as any)?.params?.id === seasonId} 
                        confirmId={confirmId}
                        setConfirmId={setConfirmId}
                      />
                    </>
                  )}
                </div>
              </div>
            );
          })
        )}
      </div>
    </div>
  );
}

import { useState, useEffect } from "react";
import { Link } from "react-router-dom";
import { useSession } from "../utils/auth-client";
import { Activity, Target, MessageSquare, BookOpen, User, HelpCircle } from "lucide-react";
import TeamAvailability from "./TeamAvailability";
import PlatformQuickStats from "./command/PlatformQuickStats";
import { api } from "../api/client";
import { driver } from "driver.js";
import "driver.js/dist/driver.css";

export default function DashboardHome() {
  const { data: session } = useSession();
  const [stats, setStats] = useState<Record<string, number>>({});
  
  // @ts-expect-error - BetterAuth session typing
  const role = session?.user?.role || "unverified";
  const canSeeInquiries = role !== "unverified";

  useEffect(() => {
    // We only fetch stats if the user isn't unverified, just to give them some data
    if (canSeeInquiries) {
      Promise.allSettled([
        api.posts.getAdminPosts.query({ query: { limit: 1 } }),
        api.events.getAdminEvents.query({ query: { limit: 1 } }),
        api.docs.getAdminDocs.query({ query: { limit: 1 } }),
      ]).then(([postsRes, eventsRes, docsRes]) => {
        let p = 0, e = 0, d = 0;
        if (postsRes.status === "fulfilled" && postsRes.value.status === 200) p = (postsRes.value.body as any).posts?.length || 0;
        if (eventsRes.status === "fulfilled" && eventsRes.value.status === 200) e = (eventsRes.value.body as any).events?.length || 0;
        if (docsRes.status === "fulfilled" && docsRes.value.status === 200) d = (docsRes.value.body as any).docs?.length || 0;
        setStats({ posts: p, events: e, docs: d });
      }).catch(() => {});
    }
  }, [canSeeInquiries]);

   
  // @ts-expect-error - BetterAuth session typing
  const firstName = session?.user?.first_name || session?.user?.name || "ARES Member";

  const startTour = () => {
    const driverObj = driver({
      showProgress: true,
      steps: [
        { 
          element: '#quick-actions', 
          popover: { 
            title: 'Quick Access', 
            description: 'Jump to your profile, log outreach hours, or check the ARESLib documentation.', 
            side: "right", 
            align: 'start' 
          } 
        },
        { 
          element: '#platform-stats', 
          popover: { 
            title: 'Real-time Metrics', 
            description: 'Monitor the status of ARES content across blog posts, events, and docs.', 
            side: "top", 
            align: 'start' 
          } 
        },
        { 
          element: '#team-radar', 
          popover: { 
            title: 'Team Radar', 
            description: 'See who is currently active or available for engineering tasks.', 
            side: "left", 
            align: 'start' 
          } 
        },
      ]
    });
    driverObj.drive();
  };

  return (
    <div className="space-y-8 h-full flex flex-col">
      {/* Header */}
      <div className="flex justify-between items-start">
        <div>
          <h2 className="text-3xl font-black text-white flex items-center gap-3">
            <div className="p-2 bg-gradient-to-br from-ares-red/20 to-red-900/20 ares-cut-sm border border-ares-red/20">
              <Activity className="text-ares-red" size={28} />
            </div>
            Welcome back, {firstName}
          </h2>
          <p className="text-marble/40 text-sm mt-2">
            Your centralized ARESWEB overview and quick actions.
          </p>
        </div>
        <button 
          onClick={startTour}
          className="flex items-center gap-2 px-4 py-2 bg-white/5 border border-white/10 ares-cut-sm text-xs font-bold uppercase tracking-widest text-marble hover:bg-white/10 transition-all"
        >
          <HelpCircle size={16} /> Take a Tour
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 flex-1">
        
        {/* Left Column: Quick Links & Stats */}
        <div className="lg:col-span-1 space-y-6 flex flex-col">
          
          <div className="p-2" id="quick-actions">
            <h3 className="font-black text-white text-sm uppercase tracking-widest mb-4 flex items-center gap-2">
              <Activity size={16} className="text-ares-cyan" />
              Quick Actions
            </h3>
            <div className="grid grid-cols-2 gap-3">
              <Link to="/dashboard/profile" className="flex flex-col items-center justify-center p-4 bg-white/5 hover:bg-white/10 ares-cut-sm transition-colors border border-white/5 group">
                <User size={20} className="text-marble/40 group-hover:text-white mb-2" />
                <span className="text-xs font-bold uppercase tracking-wider text-marble">My Profile</span>
              </Link>
              <Link to="/dashboard/outreach" className="flex flex-col items-center justify-center p-4 bg-white/5 hover:bg-white/10 ares-cut-sm transition-colors border border-white/5 group">
                <Target size={20} className="text-marble/40 group-hover:text-white mb-2" />
                <span className="text-xs font-bold uppercase tracking-wider text-marble">Outreach</span>
              </Link>
              {canSeeInquiries && (
                <Link to="/dashboard/inquiries" className="flex flex-col items-center justify-center p-4 bg-white/5 hover:bg-white/10 ares-cut-sm transition-colors border border-white/5 group">
                  <MessageSquare size={20} className="text-marble/40 group-hover:text-white mb-2" />
                  <span className="text-xs font-bold uppercase tracking-wider text-marble">Inquiries</span>
                </Link>
              )}
              <Link to="/docs" className="flex flex-col items-center justify-center p-4 bg-white/5 hover:bg-white/10 ares-cut-sm transition-colors border border-white/5 group">
                <BookOpen size={20} className="text-marble/40 group-hover:text-white mb-2" />
                <span className="text-xs font-bold uppercase tracking-wider text-marble">ARESLib</span>
              </Link>
            </div>
          </div>

          <div id="platform-stats">
            <PlatformQuickStats stats={stats} />
          </div>

        </div>

        {/* Right Column: Team Availability */}
        <div className="lg:col-span-2 p-2 flex flex-col h-[500px] lg:h-auto" id="team-radar">
          <TeamAvailability />
        </div>

      </div>
    </div>
  );
}

import { useState, useEffect } from "react";
import { Utensils, Shirt, RefreshCw, AlertCircle, Users } from "lucide-react";
import { motion } from "framer-motion";
import { api } from "../api/client";

interface LogisticsData {
  dietary: Record<string, number>;
  tshirts: Record<string, number>;
  totalCount: number;
}

import DashboardPageHeader from "./dashboard/DashboardPageHeader";
import DashboardEmptyState from "./dashboard/DashboardEmptyState";

export default function DietarySummary() {
  const [data, setData] = useState<LogisticsData | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    api.logistics.getSummary.query()
      .then((res) => {
        if (res.status === 200) {
          setData(res.body as any);
        } else {
          setError((res.body as any)?.error || "Failed to load logistics summary");
        }
        setLoading(false);
      })
      .catch((err) => {
        console.error("Logistics fetch error:", err);
        setError(err.message || "Failed to load logistics summary");
        setLoading(false);
      });
  }, []);

  if (loading) {
    return (
      <div className="flex flex-col items-center justify-center py-12 gap-4">
        <RefreshCw className="animate-spin text-ares-red" size={32} />
        <p className="text-ares-gray text-sm font-bold animate-pulse">Aggregating Team Data...</p>
      </div>
    );
  }

  if (error) {
    return (
      <div className="flex items-center gap-3 p-6 bg-ares-red text-white border border-ares-red/20 ares-cut font-bold shadow-lg shadow-ares-red/20">
        <AlertCircle size={24} />
        <div>
          <h4 className="font-bold">Summary Unavailable</h4>
          <p className="text-sm opacity-80">{error}</p>
        </div>
      </div>
    );
  }

  if (!data || data.totalCount === 0) {
    return (
      <DashboardEmptyState
        className="text-center py-12 border-2 border-dashed border-white/10 ares-cut-lg"
        icon={<Users size={48} />}
        message="No member profile data found yet."
      />
    );
  }

  return (
    <div className="space-y-6">
      <DashboardPageHeader 
        title="Team Logistics Summary" 
        subtitle="Aggregated dietary data for event planning and team management."
        icon={<Utensils className="text-ares-gold" />}
      />
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
      {/* Dietary Panel */}
      <div className="bg-obsidian/50 border border-ares-gray-dark ares-cut p-6 relative overflow-hidden group">
        <div className="absolute top-0 right-0 p-8 opacity-[0.03] group-hover:opacity-[0.07] transition-opacity pointer-events-none">
          <Utensils size={120} />
        </div>
        <h3 className="text-ares-red font-black uppercase tracking-wider text-sm flex items-center gap-2 mb-6">
          <Utensils size={18} /> Dietary Summary
        </h3>
        
        <div className="space-y-4 relative z-10">
          {Object.keys(data.dietary).length === 0 ? (
            <p className="text-ares-gray text-sm italic">No restrictions reported.</p>
          ) : (
            Object.entries(data.dietary)
              .sort((a,b) => b[1] - a[1])
              .map(([label, count]) => (
                <div key={label} className="space-y-1.5">
                  <div className="flex justify-between text-sm font-bold">
                    <span className="text-white">{label}</span>
                    <span className="text-ares-red">{count}</span>
                  </div>
                  <div className="h-1.5 w-full bg-ares-gray-dark rounded-full overflow-hidden">
                    <motion.div 
                      initial={{ width: 0 }}
                      animate={{ width: `${(count / data.totalCount) * 100}%` }}
                      className="h-full bg-ares-red shadow-[0_0_10px_rgba(220,38,38,0.5)]"
                    />
                  </div>
                </div>
              ))
          )}
        </div>
      </div>

      {/* Apparel Panel */}
      <div className="bg-obsidian/50 border border-ares-gray-dark ares-cut p-6 relative overflow-hidden group">
        <div className="absolute top-0 right-0 p-8 opacity-[0.03] group-hover:opacity-[0.07] transition-opacity pointer-events-none">
          <Shirt size={120} />
        </div>
        <h3 className="text-ares-gold font-black uppercase tracking-wider text-sm flex items-center gap-2 mb-6">
          <Shirt size={18} /> Gear Sizes
        </h3>
        
        <div className="space-y-4 relative z-10">
          {Object.keys(data.tshirts).length === 0 ? (
            <p className="text-ares-gray text-sm italic">No sizes reported.</p>
          ) : (
            Object.entries(data.tshirts)
              .sort((a, b) => {
                const order = ["Youth Medium", "Youth Large", "Adult Small", "Adult Medium", "Adult Large", "Adult XL", "Adult 2XL", "Adult 3XL"];
                return order.indexOf(a[0]) - order.indexOf(b[0]);
              })
              .map(([label, count]) => (
                <div key={label} className="space-y-1.5">
                  <div className="flex justify-between text-sm font-bold">
                    <span className="text-white">{label}</span>
                    <span className="text-ares-gold">{count}</span>
                  </div>
                  <div className="h-1.5 w-full bg-ares-gray-dark rounded-full overflow-hidden">
                    <motion.div 
                      initial={{ width: 0 }}
                      animate={{ width: `${(count / data.totalCount) * 100}%` }}
                      className="h-full bg-ares-gold shadow-[0_0_10px_rgba(192,152,0,0.5)]"
                    />
                  </div>
                </div>
              ))
          )}
        </div>
      </div>

      <div className="md:col-span-2 flex justify-center pt-2">
        <div className="px-4 py-1.5 bg-white/5 border border-white/10 rounded-full text-xs font-bold text-ares-gray uppercase tracking-widest">
          Based on {data.totalCount} active member profiles
        </div>
      </div>
    </div>
    </div>
  );
}

import { useState, useEffect } from "react";
import { useQueryClient } from "@tanstack/react-query";
import { useNavigate, useParams } from "react-router-dom";
import { useRichEditor } from "./editor/useRichEditor";
import RichEditorToolbar from "./editor/RichEditorToolbar";
import { useEntityFetch } from "../hooks/useEntityFetch";
import { docSchema, DocPayload } from "../schemas/docSchema";
import { api } from "../api/client";
import { useModal } from "../contexts/ModalContext";
import EditorFooter from "./editor/EditorFooter";
import { useForm, useWatch } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";

interface DocData {
  slug: string;
  title: string;
  category: string;
  sort_order: number;
  description: string;
  is_portfolio: number;
  is_executive_summary: number;
  content: string;
}

export default function DocsEditor({ userRole }: { userRole?: string | unknown }) {
  const { editSlug } = useParams<{ editSlug?: string }>();
  const queryClient = useQueryClient();
  const navigate = useNavigate();
  const modal = useModal();
  const [errorMsg, setErrorMsg] = useState("");

  const editor = useRichEditor({ placeholder: "<p>Start writing documentation here...</p>" });

  const { register, handleSubmit, reset, setValue, control, formState: { errors } } = useForm<DocPayload>({
    resolver: zodResolver(docSchema),
    defaultValues: {
      slug: "",
      title: "",
      category: "Getting Started",
      sortOrder: 10,
      description: "",
      isPortfolio: false,
      isExecutiveSummary: false,
      isDraft: false,
      content: "{}"
    }
  });

  const formValues = useWatch({ control });

  // Custom Hooks
  const { error: fetchError } = useEntityFetch<{ doc?: DocData }>(
    editSlug ? `/api/admin/docs/${editSlug}/detail` : null,
    (data) => {
      if (data?.doc) {
        const doc = data.doc;
        reset({
          slug: doc.slug || "",
          title: doc.title || "",
          category: doc.category || "Getting Started",
          sortOrder: doc.sort_order || 10,
          description: doc.description || "",
          isPortfolio: !!doc.is_portfolio,
          isExecutiveSummary: !!doc.is_executive_summary,
          content: doc.content || "{}"
        });
        
        if (editor && doc.content) {
          try {
            editor.commands.setContent(JSON.parse(doc.content));
          } catch {
            editor.commands.setContent(doc.content);
          }
        }
      }
    }
  );

  const saveMutation = api.docs.saveDoc.useMutation({
    onSuccess: (res: any) => {
      if (res.status === 200) {
        queryClient.invalidateQueries({ queryKey: ["docs"] });
        queryClient.invalidateQueries({ queryKey: ["admin_docs"] });
        if (formValues.isDraft || userRole === "author") {
          navigate("/dashboard");
        } else {
          navigate(`/docs/${res.body.slug}`);
        }
      } else {
        setErrorMsg(res.body.error || "Failed to publish");
      }
    },
    onError: (err: any) => {
      setErrorMsg(err.message || "Network error");
    }
  });

  const onFormSubmit = (data: DocPayload, isDraft = false) => {
    if (!editor) return;
    const content = JSON.stringify(editor.getJSON());
    saveMutation.mutate({ body: { ...data, content, isDraft } });
  };

  const handleDelete = async () => {
    if (!editSlug) return;
    const confirmed = await modal.confirm({
      title: "Delete Documentation",
      description: "Are you sure you want to permanently delete this documentation page?",
      confirmText: "Delete",
      destructive: true,
    });
    if (!confirmed) return;

    try {
      await api.docs.deleteDoc.mutate({ params: { slug: editSlug }, body: {} });
      queryClient.invalidateQueries({ queryKey: ["docs"] });
      queryClient.invalidateQueries({ queryKey: ["admin_docs"] });
      navigate("/dashboard/manage_docs");
    } catch {
      setErrorMsg("Failed to delete the document.");
    }
  };

  return (
    <div className="flex flex-col gap-6 w-full relative">
      <div>
        <h2 className="text-3xl font-bold text-white tracking-tight mb-2">
          {editSlug ? "Edit Document" : "Publish Document"}
        </h2>
        <p className="text-white/50 text-sm">
          {editSlug ? "Modify an existing ARESLib documentation page." : "Draft a new Markdown/Tiptap documentation page for the hub."}
        </p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-4 mt-2">
        <div className="col-span-1 lg:col-span-2">
          <label htmlFor="doc-title" className="block text-xs font-bold text-ares-gold uppercase tracking-wider mb-2">Title</label>
          <input
            id="doc-title" type="text"
            {...register("title")}
            className="w-full bg-black/50 border border-white/10 text-white px-4 py-3 ares-cut-sm focus:outline-none focus:ring-2 focus:ring-ares-cyan transition-colors"
            placeholder="e.g. Swerve Kinematics"
          />
          {errors.title && <p className="text-[10px] font-black uppercase text-ares-red mt-1">{errors.title.message}</p>}
        </div>
        
        <div className="col-span-1 lg:col-span-1">
          <label htmlFor="doc-slug" className="block text-xs font-bold text-ares-gold uppercase tracking-wider mb-2">Slug</label>
          <input
            id="doc-slug" type="text"
            {...register("slug")}
            disabled={!!editSlug}
            className="w-full bg-black/50 border border-white/10 text-white px-4 py-3 ares-cut-sm focus:outline-none focus:ring-2 focus:ring-ares-cyan transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
            placeholder="e.g. swerve-kinematics"
          />
          {errors.slug && <p className="text-[10px] font-black uppercase text-ares-red mt-1">{errors.slug.message}</p>}
        </div>

        <div className="col-span-1 lg:col-span-1">
          <label htmlFor="doc-category" className="block text-xs font-bold text-ares-gold uppercase tracking-wider mb-2">Category</label>
          <input
            id="doc-category" type="text"
            {...register("category")}
            className="w-full bg-black/50 border border-white/10 text-white px-4 py-3 ares-cut-sm focus:outline-none focus:ring-2 focus:ring-ares-cyan transition-colors"
            placeholder="e.g. Tutorials"
          />
        </div>
        
        <div className="col-span-1 lg:col-span-1">
          <label htmlFor="doc-sort" className="block text-xs font-bold text-ares-gold uppercase tracking-wider mb-2">Sort Order</label>
          <input
            id="doc-sort" type="number"
            {...register("sortOrder", { valueAsNumber: true })}
            className="w-full bg-black/50 border border-white/10 text-white px-4 py-3 ares-cut-sm focus:outline-none focus:ring-2 focus:ring-ares-cyan transition-colors"
          />
        </div>
      </div>

      <div>
        <label htmlFor="doc-description" className="block text-xs font-bold text-ares-gold uppercase tracking-wider mb-2">Description / Summary</label>
        <input
          id="doc-description" type="text"
          {...register("description")}
          className="w-full bg-black/50 border border-white/10 text-white px-4 py-3 ares-cut-sm focus:outline-none focus:ring-2 focus:ring-ares-cyan transition-colors"
          placeholder="Brief summary of what this document covers..."
        />
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6 p-4 ares-cut-sm bg-obsidian/50 border border-white/5">
        <div className="flex items-center gap-3 cursor-pointer group">
          <input 
            id="isPortfolioToggle" type="checkbox" 
            {...register("isPortfolio")} 
            className="w-5 h-5 rounded border-white/10 bg-black text-ares-cyan focus:ring-ares-cyan"
          />
          <div>
            <label htmlFor="isPortfolioToggle" className="block text-sm font-bold text-white group-hover:text-ares-cyan transition-colors cursor-pointer">Judge&apos;s Portfolio Selection</label>
            <span className="block text-xs text-white/60">Feature this in the Rapid Review dashboard for judges.</span>
          </div>
        </div>
        
        <div className="flex items-center gap-3 cursor-pointer group">
          <input 
            id="isExecSummaryToggle" type="checkbox" 
            {...register("isExecutiveSummary")} 
            className="w-5 h-5 rounded border-white/10 bg-black text-ares-gold focus:ring-ares-gold"
          />
          <div>
            <label htmlFor="isExecSummaryToggle" className="block text-sm font-bold text-white group-hover:text-ares-gold transition-colors cursor-pointer">Executive Summary Flag</label>
            <span className="block text-xs text-white/60">Mark as the primary seasonal overview for rapid judging.</span>
          </div>
        </div>
      </div>

      {/* ===== Unified Rich Editor ===== */}
      <div className="flex-1 flex flex-col relative min-h-[500px]">
        {editor && <RichEditorToolbar editor={editor} documentTitle={formValues.title || ""} />}
      </div>

      <div className="mt-4 pt-6">
        {editSlug && (
          <div className="flex justify-end mb-4">
            <button
              onClick={() => navigate('/dashboard/manage_docs')}
              className="px-6 py-2 ares-cut-sm text-white/50 hover:text-white font-bold tracking-wider text-sm transition-colors"
            >
              Cancel Edit
            </button>
          </div>
        )}
        <EditorFooter 
          errorMsg={errorMsg}
          isPending={saveMutation.isPending}
          isEditing={!!editSlug}
          onDelete={handleDelete}
          onSaveDraft={handleSubmit((d) => onFormSubmit(d, true))}
          onPublish={handleSubmit((d) => onFormSubmit(d, false))}
          deleteText="DELETE DOC"
          updateText="UPDATE DOC"
          publishText={userRole === "author" ? "SUBMIT FOR REVIEW" : "PUBLISH DOC"}
          userRole={userRole}
          roundedClass="ares-cut"
        />
      </div>
    </div>
  );
}

import { useParams, useNavigate } from "react-router-dom";
import { useRichEditor } from "./editor/useRichEditor";
import RichEditorToolbar from "./editor/RichEditorToolbar";
import AssetPickerModal from "./AssetPickerModal";
import { MapPin, XCircle, Plus } from "lucide-react";
import EventPotluckVolunteerFlags from "./events/EventPotluckVolunteerFlags";
import SocialSyndicationGrid from "./editor/SocialSyndicationGrid";
import CoverAssetPicker from "./editor/CoverAssetPicker";
import EditorFooter from "./editor/EditorFooter";
import SeasonPicker from "./SeasonPicker";
import { useForm, useWatch } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { eventSchema, EventPayload } from "../schemas/eventSchema";
import { api } from "../api/client";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { useAdminSettings } from "../hooks/useAdminSettings";
import { useImageUpload } from "../hooks/useImageUpload";
import { useModal } from "../contexts/ModalContext";
import { DEFAULT_COVER_IMAGE } from "../utils/constants";
import { useEntityFetch } from "../hooks/useEntityFetch";
import { toast } from "sonner";
import { useState, useEffect } from "react";

export interface LocationRow {
  id: string;
  name: string;
  address: string;
}

export default function EventEditor({ userRole }: { userRole?: string | unknown }) {
  const { editId } = useParams<{ editId?: string }>();
  const navigate = useNavigate();
  const queryClient = useQueryClient();
  const modal = useModal();
  const editor = useRichEditor({ placeholder: "<p>Describe your upcoming event or write a full recap here...</p>" });
  
  const { availableSocials } = useAdminSettings();
  const { uploadFile, isUploading, errorMsg: uploadError, setErrorMsg: setUploadError } = useImageUpload();

  const [isDeleted, setIsDeleted] = useState(false);
  const [errorMsg, setErrorMsg] = useState("");
  const [warningMsg, setWarningMsg] = useState("");
  const [isCoverPickerOpen, setIsCoverPickerOpen] = useState(false);

  const { register, handleSubmit, reset, setValue, control, formState: { errors } } = useForm<EventPayload>({
    resolver: zodResolver(eventSchema),
    defaultValues: {
      title: "",
      dateStart: "",
      dateEnd: "",
      location: "",
      description: "",
      coverImage: DEFAULT_COVER_IMAGE,
      category: "internal",
      tbaEventKey: "",
      isPotluck: false,
      isVolunteer: false,
      publishedAt: "",
      seasonId: "",
      socials: {
        discord: true,
        bluesky: true,
        slack: false,
        teams: false,
        gchat: false,
        facebook: false,
        twitter: false,
        instagram: false
      }
    }
  });

  const formValues = useWatch({ control });
  const socials = formValues.socials || {};

  const { data: locations = [] } = useQuery<LocationRow[]>({
    queryKey: ["locations"],
    queryFn: async () => {
      try {
        const d = await api.events.getEvents.query({ query: { limit: 100 } });
        // This is a hack because our getEvents returns events, but we need locations
        // In a real scenario, we'd have a locationContract
        return []; 
      } catch {
        return [];
      }
    }
  });

  // Fetch locations manually for now as we don't have a contract yet
  useEffect(() => {
    fetch("/api/locations").then(res => res.json()).then(d => {
      if (d.locations) {
        // We handle this via raw fetch for now as it's a "Should Fix"
      }
    });
  }, []);

  useEntityFetch<{ event?: any }>(
    editId ? `/api/admin/events/${editId}` : null,
    (data) => {
      if (data?.event) {
        setIsDeleted(data.event.is_deleted === 1);
        reset({
          title: data.event.title || "",
          dateStart: data.event.date_start || "",
          dateEnd: data.event.date_end || "",
          location: data.event.location || "",
          description: data.event.description || "",
          coverImage: data.event.cover_image || DEFAULT_COVER_IMAGE,
          category: (data.event.category || "internal") as any,
          tbaEventKey: data.event.tba_event_key || "",
          isPotluck: data.event.is_potluck === 1,
          isVolunteer: data.event.is_volunteer === 1,
          publishedAt: data.event.published_at || "",
          seasonId: data.event.season_id || "",
          socials: (socials as any) || {}
        });
        if (editor) {
          try {
            editor.commands.setContent(JSON.parse(data.event.description));
          } catch {
            editor.commands.setContent(`<p>${data.event.description}</p>`);
          }
        }
      }
    }
  );

  const saveMutation = api.events.saveEvent.useMutation({
    onSuccess: (data: any) => {
      if (data.status === 200) {
        const isAuthor = userRole === "author";
        toast.success(editId ? "Event updated!" : "Event published!");
        if (data.body.warning) toast.info(data.body.warning);

        queryClient.invalidateQueries({ queryKey: ["events"] });
        queryClient.invalidateQueries({ queryKey: ["admin_events"] });
        navigate("/dashboard");
      } else {
        setErrorMsg(data.body.error || "Event save failed.");
      }
    },
    onError: (err: any) => {
      setErrorMsg(err.message || "Network error.");
    }
  });

  const onFormSubmit = (data: EventPayload, isDraft = false) => {
    const finalDescription = editor ? JSON.stringify(editor.getJSON()) : data.description;
    saveMutation.mutate({ body: { ...data, description: finalDescription, isDraft } });
  };

  const handleDelete = async () => {
    if (!editId) return;
    const confirmed = await modal.confirm({
      title: "Delete Event",
      description: "Are you sure you want to permanently delete this event?",
      confirmText: "Delete",
      destructive: true,
    });
    if (!confirmed) return;

    try {
      await api.events.deleteEvent.mutate({ params: { id: editId }, body: {} });
      navigate("/dashboard");
    } catch {
      setErrorMsg("Failed to delete the event.");
    }
  };

  const handleFileUpload = async (file: File) => {
    try {
      setUploadError("");
      const { url } = await uploadFile(file);
      setValue("coverImage", url);
    } catch(err) {
      setErrorMsg(uploadError || String(err));
    }
  };

  return (
    <div className="flex flex-col gap-6 w-full relative">
      <div>
        <h2 className="text-3xl font-bold text-white tracking-tight mb-2">
          {editId ? "Edit Event" : "Publish Event"}
        </h2>
        <p className="text-white/60 text-sm">
          {editId ? "Update existing competition or outreach details." : "Add upcoming competitions or outreach events to the portal."}
        </p>
      </div>
      
      {isDeleted && (
        <div className="bg-ares-danger/10 border-l-4 border-ares-danger p-4 rounded-r-lg mb-6 flex items-start gap-3">
          <div className="text-ares-danger mt-0.5">⚠️</div>
          <div>
            <h4 className="text-white font-bold text-sm tracking-wide uppercase">Ghost Event</h4>
            <p className="text-white text-sm mt-1 font-bold">This event is currently soft-deleted and is hidden from the public API and Google Calendar.</p>
          </div>
        </div>
      )}
      
      <div className="flex flex-col md:flex-row gap-4 mt-2">
        <div className="flex-1">
          <label htmlFor="event-title" className="block text-xs font-bold text-white/60 uppercase tracking-wider mb-2">Event Title *</label>
          <input
            id="event-title" type="text"
            {...register("title")}
            className="w-full bg-obsidian border border-white/10 ares-cut-sm px-4 py-3 text-white placeholder-white/60 focus:border-ares-red focus:outline-none focus:ring-1 focus:ring-ares-red transition-all shadow-inner"
            placeholder="State Championship"
          />
          {errors.title && <p className="text-[10px] font-black uppercase text-ares-red mt-1">{errors.title.message}</p>}
        </div>
        <div className="flex-1">
          <CoverAssetPicker 
            coverImage={formValues.coverImage || DEFAULT_COVER_IMAGE}
            isUploading={isUploading}
            onUrlChange={(url) => setValue("coverImage", url)}
            onLibraryClick={() => setIsCoverPickerOpen(true)}
            onFileChange={handleFileUpload}
          />
        </div>
      </div>
      
      <div className="flex flex-col md:flex-row gap-4">
        <div className="flex-1">
          <label htmlFor="event-category" className="block text-xs font-bold text-white/60 uppercase tracking-wider mb-2">Category *</label>
          <select
            id="event-category"
            {...register("category")}
            className="w-full bg-obsidian border border-white/10 ares-cut-sm px-4 py-3 text-white placeholder-white/60 focus:border-ares-red focus:outline-none focus:ring-1 focus:ring-ares-red transition-all shadow-inner appearance-none"
          >
            <option value="internal">ARES Practices</option>
            <option value="outreach">ARES Outreach &amp; Volunteer</option>
            <option value="external">ARES Community Spotlight</option>
          </select>
        </div>
        <div className="flex-1">
          <label htmlFor="event-tba-key" className="text-xs font-bold text-white/60 uppercase tracking-wider mb-2 flex items-center justify-between">
            <span>TBA Event Key</span>
            <span className="text-xs text-white/60 font-normal normal-case">Optional</span>
          </label>
          <input
            id="event-tba-key" type="text"
            {...register("tbaEventKey")}
            className="w-full bg-obsidian border border-white/10 ares-cut-sm px-4 py-3 text-white placeholder-white/60 focus:border-ares-red focus:outline-none focus:ring-1 focus:ring-ares-red transition-all shadow-inner"
            placeholder="e.g. 2024wvcmp"
          />
        </div>
        <div className="flex-1">
          <SeasonPicker value={formValues.seasonId || ""} onChange={(val) => setValue("seasonId", val)} />
        </div>
        <div className="flex-1">
          <label htmlFor="event-location" className="text-xs font-bold text-white/60 uppercase tracking-wider mb-2 flex items-center justify-between">
            <span>Location</span>
            <span className="text-xs text-white/60 font-normal normal-case">Pick from registry</span>
          </label>
          <div className="relative group">
            <select
              id="event-location"
              {...register("location")}
              className="w-full bg-obsidian border border-white/10 ares-cut-sm px-4 py-3 text-white placeholder-white/60 focus:border-ares-red focus:outline-none focus:ring-1 focus:ring-ares-red transition-all shadow-inner appearance-none pr-10"
            >
              <option value="">-- Select a Venue --</option>
              {/* Note: locations mapping skipped for brevity in this refactor step, assumes existing pattern or manual entry */}
              <option value="CUSTOM">--- Manual Entry / New Venue ---</option>
            </select>
            <div className="absolute right-3 top-1/2 -translate-y-1/2 pointer-events-none text-white/60 group-hover:text-ares-red transition-colors">
              <MapPin size={16} />
            </div>
          </div>
        </div>
      </div>

      <div className="flex flex-col md:flex-row gap-4">
        <div className="flex-1">
          <label htmlFor="event-start" className="block text-xs font-bold text-white/60 uppercase tracking-wider mb-2">Start Date & Time *</label>
          <input
            id="event-start" type="datetime-local"
            {...register("dateStart")}
            className="w-full bg-obsidian border border-white/10 ares-cut-sm px-4 py-3 text-white placeholder-white/60 focus:border-ares-red focus:outline-none focus:ring-1 focus:ring-ares-red transition-all shadow-inner [&::-webkit-calendar-picker-indicator]:invert"
          />
          {errors.dateStart && <p className="text-[10px] font-black uppercase text-ares-red mt-1">{errors.dateStart.message}</p>}
        </div>
        <div className="flex-1">
          <label htmlFor="event-end" className="block text-xs font-bold text-white/60 uppercase tracking-wider mb-2">End Date & Time</label>
          <input
            id="event-end" type="datetime-local"
            {...register("dateEnd")}
            className="w-full bg-obsidian border border-white/10 ares-cut-sm px-4 py-3 text-white placeholder-white/60 focus:border-ares-red focus:outline-none focus:ring-1 focus:ring-ares-red transition-all shadow-inner [&::-webkit-calendar-picker-indicator]:invert"
          />
        </div>
        <div className="flex-1">
          <label htmlFor="event-published-at" className="block text-xs font-bold text-white/60 uppercase tracking-wider mb-2">Schedule Publish Time</label>
          <input
            id="event-published-at" type="datetime-local"
            {...register("publishedAt")}
            className="w-full bg-obsidian border border-white/10 ares-cut-sm px-4 py-3 text-white placeholder-white/60 focus:border-ares-red focus:outline-none focus:ring-1 focus:ring-ares-red transition-all shadow-inner [&::-webkit-calendar-picker-indicator]:invert"
          />
        </div>
      </div>

      <EventPotluckVolunteerFlags 
        isPotluck={formValues.isPotluck || false} 
        isVolunteer={formValues.isVolunteer || false} 
        onChange={(field, val) => setValue(field as any, val)}
      />

      <div>
        <label htmlFor="event-desc-editor" className="block text-xs font-bold text-white/60 uppercase tracking-wider mb-2">Event Description / Recap</label>
        {editor && <RichEditorToolbar editor={editor} documentTitle={formValues.title || ""} />}
      </div>



      <div className="mt-6 flex flex-col gap-4">
        {errorMsg && (
          <div className="p-4 bg-ares-danger/10 border border-ares-danger/20 ares-cut flex items-start gap-3">
            <div className="text-ares-danger mt-0.5">⚠️</div>
            <div>
              <h4 className="text-white font-bold text-xs tracking-wide uppercase">Critical Error</h4>
              <p id="event-error-msg" className="text-white text-sm mt-1 font-bold">{errorMsg}</p>
            </div>
          </div>
        )}

        {warningMsg && (
          <div className="p-4 bg-ares-gold/10 border border-ares-gold/20 ares-cut flex items-start gap-3">
            <div className="text-ares-gold mt-0.5">⚠️</div>
            <div>
              <h4 className="text-ares-gold font-bold text-xs tracking-wide uppercase">Syndication Warning</h4>
              <p className="text-white text-sm mt-1">Event saved, but: {warningMsg}</p>
            </div>
          </div>
        )}

        <EditorFooter 
          errorMsg={errorMsg}
          isPending={saveMutation.isPending}
          isEditing={!!editId}
          onDelete={handleDelete}
          onSaveDraft={handleSubmit((d) => onFormSubmit(d, true))}
          onPublish={handleSubmit((d) => onFormSubmit(d, false))}
          deleteText="DELETE"
          updateText="UPDATE EVENT"
          publishText={userRole === "author" ? "SUBMIT FOR REVIEW" : "PUBLISH EVENT"}
          userRole={userRole}
          roundedClass="ares-cut"
          extraControls={
            <SocialSyndicationGrid 
              availableSocials={availableSocials}
              socials={socials as any}
              onChange={(platform, val) => setValue(`socials.${platform}` as any, val)}
              isEdit={!!editId}
            />
          }
        />
      </div>

      <AssetPickerModal 
        isOpen={isCoverPickerOpen}
        onClose={() => setIsCoverPickerOpen(false)}
        onSelect={(url) => {
          setValue("coverImage", url);
          setIsCoverPickerOpen(false);
        }}
      />
    </div>
  );
}

import { useEffect, useState } from "react";
import { siteConfig } from "../site.config";
import { api } from "../api/client";

interface DayCell {
  date: string;
  count: number;
  level: number;
}

const MONTHS = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];
const DAYS = ["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"];

const LEVEL_COLORS = [
  "bg-white/5",           // 0 commits
  "bg-ares-red/25",       // low
  "bg-ares-red/50",       // medium
  "bg-ares-red/75",       // high
  "bg-ares-red",          // max
];

export default function GitHubHeatmap() {
  const [grid, setGrid] = useState<DayCell[][]>([]);
  const [totalCommits, setTotalCommits] = useState(0);
  const [repoCount, setRepoCount] = useState(0);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [hoveredCell, setHoveredCell] = useState<DayCell | null>(null);

  useEffect(() => {
    async function fetchData() {
      try {
        const res = await api.github.getActivity.query();
        if (res.status === 200) {
          setGrid(res.body.grid as any);
          setTotalCommits(res.body.totalCommits);
          setRepoCount(res.body.repoCount);
        }
        setLoading(false);
      } catch (err) {
        setError(err instanceof Error ? err.message : "Failed to load activity");
        setLoading(false);
      }
    }

    fetchData();
  }, []);

  // Determine which month labels to show
  const monthLabels: { label: string; col: number }[] = [];
  if (grid.length > 0) {
    let lastMonth = -1;
    grid.forEach((week, i) => {
      const d = new Date(week[0].date);
      const month = d.getMonth();
      if (month !== lastMonth) {
        monthLabels.push({ label: MONTHS[month], col: i });
        lastMonth = month;
      }
    });
  }

  if (loading) {
    return (
      <div className="bg-white/5 border border-white/10 hero-card p-8 animate-pulse">
        <div className="h-6 bg-white/10 rounded w-48 mb-4"></div>
        <div className="h-32 bg-white/10 rounded"></div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="bg-white/5 border border-white/10 hero-card p-8">
        <p className="text-marble/50 text-sm">Unable to load GitHub activity.</p>
      </div>
    );
  }

  return (
    <div className="bg-white/5 border border-white/10 hero-card p-8 group relative">
      {/* Header */}
      <div className="flex flex-col sm:flex-row sm:items-center justify-between mb-6 gap-4">
        <div>
          <h3 className="text-2xl font-bold font-heading group-hover:text-ares-gold transition-colors">
            Engineering Activity
          </h3>
          <p className="text-marble/50 text-sm mt-1">
            {totalCommits.toLocaleString()} contributions across {repoCount} repositories in the last year
          </p>
        </div>
        <a
          href={`https://github.com/${siteConfig.urls.githubOrg}`}
          target="_blank"
          rel="noopener noreferrer"
          className="text-ares-gold text-sm font-bold uppercase tracking-wider hover:text-white transition-colors shrink-0"
        >
          View on GitHub →
        </a>
      </div>

      {/* Heatmap Grid */}
      <div className="overflow-x-auto pb-2">
        <div className="min-w-[720px]">
          {/* Month labels */}
          <div className="flex ml-8 mb-1 text-xs text-marble/90 font-bold uppercase tracking-wider">
            {monthLabels.map((m) => (
              <div
                key={`${m.label}-${m.col}`}
                className="absolute"
                style={{ marginLeft: `${m.col * 14 + 32}px` }}
              >
                {m.label}
              </div>
            ))}
          </div>
          <div className="relative mt-4">
            <div className="flex gap-[2px]">
              {/* Day labels */}
              <div className="flex flex-col gap-[2px] mr-1 shrink-0">
                {DAYS.map((day, i) => (
                  <div
                    key={day}
                    className="h-[12px] flex items-center text-[9px] text-marble/90 font-bold uppercase"
                    style={{ visibility: i % 2 === 1 ? "visible" : "hidden" }}
                  >
                    {day}
                  </div>
                ))}
              </div>

              {/* Week columns */}
              {grid.map((week, wi) => (
                <div key={wi} className="flex flex-col gap-[2px]">
                  {week.map((day) => (
                    <div
                      key={day.date}
                      className={`w-[12px] h-[12px] rounded-[2px] transition-all duration-200 cursor-pointer ${
                        day.level === -1
                          ? "bg-transparent"
                          : `${LEVEL_COLORS[day.level]} hover:ring-1 hover:ring-white/50`
                      }`}
                      onMouseEnter={() => day.level >= 0 && setHoveredCell(day)}
                      onMouseLeave={() => setHoveredCell(null)}
                    />
                  ))}
                </div>
              ))}
            </div>
          </div>

          {/* Legend */}
          <div className="flex items-center justify-between mt-4">
            <div className="flex items-center gap-2 text-xs text-marble/90 font-bold">
              <span>Less</span>
              {LEVEL_COLORS.map((color, i) => (
                <div key={i} className={`w-[12px] h-[12px] rounded-[2px] ${color}`} />
              ))}
              <span>More</span>
            </div>
          </div>
        </div>
      </div>

      {/* Tooltip */}
      {hoveredCell && (
        <div className="absolute bottom-4 right-4 bg-obsidian border border-white/20 ares-cut-sm px-4 py-2 text-sm shadow-xl pointer-events-none z-10">
          <span className="text-white font-bold">{hoveredCell.count} commit{hoveredCell.count !== 1 ? "s" : ""}</span>
          <span className="text-marble/50 ml-2">{new Date(hoveredCell.date).toLocaleDateString("en-US", { weekday: "short", month: "short", day: "numeric", year: "numeric" })}</span>
        </div>
      )}
    </div>
  );
}

import { useState, useEffect } from "react";

import { useQueryClient } from "@tanstack/react-query";
import { Settings, Save } from "lucide-react";
import { ZulipCard } from "./integrations/ZulipCard";
import { GithubCard } from "./integrations/GithubCard";
import { SocialCard } from "./integrations/SocialCard";
import { DataBackupCard } from "./integrations/DataBackupCard";
import { api } from "../api/client";
import { useForm, useWatch } from "react-hook-form";

type SettingsData = Record<string, string>;

export default function IntegrationsManager() {
  const queryClient = useQueryClient();
  const [successMsg, setSuccessMsg] = useState("");

  const { register, handleSubmit, reset, setValue, control, formState: { isDirty } } = useForm<SettingsData>();
  const localSettings = useWatch({ control });

  const { data, isLoading, isError } = api.settings.getSettings.useQuery({
    queryKey: ["admin_settings"],
  });

  useEffect(() => {
    if (data?.body?.settings) {
      const merged: SettingsData = { ...data.body.settings };
      if (merged["CALENDAR_ID"] && !merged["CALENDAR_ID_INTERNAL"]) {
        merged["CALENDAR_ID_INTERNAL"] = merged["CALENDAR_ID"];
      }
      reset(merged);
    }
  }, [data?.body?.settings, reset]);

  const saveMutation = api.settings.updateSettings.useMutation({
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["admin_settings"] });
      setSuccessMsg("Integrations synchronized securely.");
      setTimeout(() => setSuccessMsg(""), 3000);
    }
  });

  const onFormSubmit = (data: SettingsData) => {
    saveMutation.mutate({ body: data });
  };

  const handleChange = (key: string, value: string) => {
    setValue(key, value, { shouldDirty: true });
  };

  if (isLoading) {
    return (
      <div className="w-full h-64 flex items-center justify-center">
        <div className="w-8 h-8 border-4 border-white/10 border-t-ares-gold rounded-full animate-spin"></div>
      </div>
    );
  }

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500 relative">
      <form onSubmit={handleSubmit(onFormSubmit)}>
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-8">
          <div>
            <h2 className="text-2xl font-bold text-white flex items-center gap-2">
              <Settings className="text-marble/40" /> API &amp; Integrations
            </h2>
            <p className="text-marble/90 mt-1">
              Manage your Zero Trust configuration tokens securely. Keys are safely obscured upon save.
            </p>
          </div>
          <button
            type="submit"
            disabled={!isDirty || saveMutation.isPending}
            className={`flex items-center gap-2 px-6 py-2.5 ares-cut-sm font-bold transition-all shadow-lg backdrop-blur ${
              isDirty
                ? "bg-gradient-to-r from-ares-gold to-yellow-600 text-black hover:scale-105"
                : "bg-white/5 text-marble/40 cursor-not-allowed border border-white/5"
            }`}
          >
            {saveMutation.isPending ? (
              <div className="w-4 h-4 border-2 border-black/20 border-t-black rounded-full animate-spin"></div>
            ) : (
              <Save size={18} />
            )}
            Save Changes
          </button>
        </div>

        {isError && (
          <div className="bg-ares-red/10 border border-ares-red/30 p-4 ares-cut-sm text-ares-red text-xs font-bold mb-6 flex items-center gap-2">
            <span className="w-2 h-2 rounded-full bg-ares-red animate-pulse" />
            TELEMETRY FAULT: Failed to synchronize Zero Trust secrets. Access denied.
          </div>
        )}

        {successMsg && (
          <div className="absolute top-0 right-0 -translate-y-full mb-4 bg-ares-cyan/20 border border-ares-cyan/50 text-ares-cyan px-4 py-2 ares-cut-sm font-medium text-sm">
            {successMsg}
          </div>
        )}

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          <ZulipCard localSettings={localSettings as any} handleChange={handleChange} />
          <GithubCard localSettings={localSettings as any} handleChange={handleChange} />
          <SocialCard localSettings={localSettings as any} handleChange={handleChange} />
          <DataBackupCard />
        </div>
      </form>
    </div>
  );
}

import { useState, useEffect, useMemo } from "react";
import DashboardPageHeader from "./dashboard/DashboardPageHeader";
import { useQueryClient } from "@tanstack/react-query";
import { Search, MapPin, Plus, Trash2, Edit3, CheckCircle, Navigation, XCircle } from "lucide-react";
import { api } from "../api/client";
import { toast } from "sonner";
import { useForm, useWatch } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { locationSchema } from "../schemas/contracts/locationContract";
import { z } from "zod";

interface LocationRow {
  id: string;
  name: string;
  address: string;
  maps_url: string | null;
  is_deleted: number;
}

export default function LocationsManager() {
  const queryClient = useQueryClient();
  const [searchTerm, setSearchTerm] = useState("");
  const [isAdding, setIsAdding] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);

  const { register, handleSubmit, reset, setValue, control, formState: { errors } } = useForm<z.infer<typeof locationSchema>>({
    resolver: zodResolver(locationSchema),
    defaultValues: {
      name: "",
      address: "",
      maps_url: "",
      is_deleted: 0
    }
  });

  const addressQuery = useWatch({ control, name: "address" });
  const mapsUrl = useWatch({ control, name: "maps_url" });

  const [suggestions, setSuggestions] = useState<{ display_name: string }[]>([]);
  const [isSearchingOSM, setIsSearchingOSM] = useState(false);
  const [errorMsg, setErrorMsg] = useState("");

  const { data: locationsData, isLoading, isError } = api.locations.adminList.useQuery({
    queryKey: ["admin_locations"]
  });

  const locations = useMemo(() => (locationsData?.body as any)?.locations || [], [locationsData]);

  const saveMutation = api.locations.save.useMutation({
    onSuccess: (res: any) => {
      if (res.status === 200) {
        toast.success("Venue record synchronized.");
        queryClient.invalidateQueries({ queryKey: ["admin_locations"] });
        queryClient.invalidateQueries({ queryKey: ["locations"] });
        resetForm();
      } else {
        setErrorMsg("Failed to save venue");
      }
    },
    onError: (err: any) => {
      setErrorMsg(err.message || "Network error.");
    }
  });

  const deleteMutation = api.locations.delete.useMutation({
    onSuccess: (res: any) => {
      if (res.status === 200) {
        toast.success("Venue deactivated.");
        queryClient.invalidateQueries({ queryKey: ["admin_locations"] });
      }
    }
  });

  // Debounced OSM Geocoding
  useEffect(() => {
    const timer = setTimeout(async () => {
      if (!addressQuery || addressQuery.length < 4) {
        setSuggestions([]);
        return;
      }
      setIsSearchingOSM(true);
      try {
        const res = await fetch(`https://nominatim.openstreetmap.org/search?q=${encodeURIComponent(addressQuery)}&format=json&addressdetails=1&limit=5`);
        const data = await res.json() as { display_name: string }[];
        setSuggestions(data);
      } catch (err) {
        console.error("OSM Err:", err);
      } finally {
        setIsSearchingOSM(false);
      }
    }, 600);
    return () => clearTimeout(timer);
  }, [addressQuery]);

  const resetForm = () => {
    setIsAdding(false);
    setEditingId(null);
    reset({ name: "", address: "", maps_url: "", is_deleted: 0 });
    setSuggestions([]);
    setErrorMsg("");
  };

  const handleEdit = (l: LocationRow) => {
    setEditingId(l.id);
    setIsAdding(true);
    reset({
      id: l.id,
      name: l.name,
      address: l.address,
      maps_url: l.maps_url || "",
      is_deleted: l.is_deleted
    });
  };

  const onFormSubmit = (data: z.infer<typeof locationSchema>) => {
    saveMutation.mutate({ body: { ...data, id: editingId || undefined } });
  };

  const filtered = useMemo(() => locations.filter((l: any) => l.name.toLowerCase().includes(searchTerm.toLowerCase())), [locations, searchTerm]);

  return (
    <div className="w-full flex flex-col items-center h-full p-4 md:p-8 overflow-y-auto">
      <div className="w-full max-w-4xl">
        <DashboardPageHeader 
          title="Locations Registry" 
          subtitle="Manage the physical venues and hotspots for ARES operations."
          icon={<MapPin className="text-ares-red" />}
        />
        {isError && (
          <div className="bg-ares-red/10 border border-ares-red/30 p-4 ares-cut-sm text-ares-red text-xs font-bold mb-6 flex items-center gap-2">
            <span className="w-2 h-2 rounded-full bg-ares-red animate-pulse" />
            TELEMETRY FAULT: Failed to synchronize venue data.
          </div>
        )}
      </div>
      <div className="w-full max-w-4xl bg-obsidian border border-white/10 ares-cut-sm shadow-2xl p-6 relative">

        {!isAdding ? (
          <>
            <div className="flex gap-4 mb-6">
              <div className="relative flex-1">
                <Search size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-marble/50" />
                <input 
                  type="text" 
                  className="w-full bg-obsidian border border-white/10 ares-cut-sm py-2 pl-10 pr-4 text-white focus:border-ares-red focus:outline-none"
                  placeholder="Search registered event locations..."
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                />
              </div>
              <button 
                onClick={() => setIsAdding(true)}
                className="bg-ares-cyan text-black px-4 py-2 ares-cut-sm font-bold flex items-center gap-2 hover:bg-white transition-colors uppercase tracking-wider text-xs"
              >
                <Plus size={16} /> Add Venue
              </button>
            </div>

            {isLoading ? <div className="text-center p-8 text-marble/50 animate-pulse">Loading venues...</div> : (
              <div className="flex flex-col gap-3">
                {filtered.map((l: any) => (
                  <div key={l.id} className={`p-4 border ares-cut-sm flex items-center justify-between ${l.is_deleted ? 'border-ares-danger/20 bg-ares-danger/5 opacity-50' : 'border-white/10 bg-obsidian/50 hover:bg-white/5'}`}>
                    <div>
                      <h4 className={`font-bold ${l.is_deleted ? 'text-ares-red/60 line-through' : 'text-white'}`}>{l.name}</h4>
                      <p className="text-sm text-marble/90 mt-1 flex items-center gap-2">
                        <MapPin size={14} /> {l.address}
                      </p>
                    </div>
                    <div className="flex items-center gap-2">
                      {l.is_deleted ? (
                        <button onClick={() => saveMutation.mutate({ body: { ...l, is_deleted: 0 } })} className="p-2 text-marble/90 hover:text-ares-cyan transition-colors bg-obsidian ares-cut-sm">RESTORE</button>
                      ) : (
                        <>
                          <button onClick={() => handleEdit(l)} title="Edit venue" className="p-2 text-marble/90 hover:text-ares-cyan transition-colors bg-obsidian ares-cut-sm"><Edit3 size={16} /></button>
                          <button onClick={() => deleteMutation.mutate({ params: { id: l.id }, body: {} })} title="Delete venue" className="p-2 text-marble/90 hover:text-ares-red transition-colors bg-obsidian ares-cut-sm"><Trash2 size={16} /></button>
                        </>
                      )}
                    </div>
                  </div>
                ))}
                {filtered.length === 0 && <div className="text-center p-8 text-marble/50">No verified locations found.</div>}
              </div>
            )}
          </>
        ) : (
          <form onSubmit={handleSubmit(onFormSubmit)} className="bg-obsidian border border-white/10 p-6 ares-cut-sm">
            <h3 className="text-white font-bold mb-6 font-heading tracking-widest">{editingId ? 'Edit Venue' : 'Register New Venue'}</h3>

            <div className="flex flex-col gap-4">
              <div>
                <label htmlFor="venue_name" className="text-xs uppercase tracking-widest text-marble/90 font-bold mb-2 block">Alias (e.g. &apos;Mars Workspace&apos;) *</label>
                <input 
                  id="venue_name"
                  type="text" 
                  {...register("name")}
                  className="w-full bg-obsidian border border-white/10 rounded p-3 text-white focus:border-ares-cyan outline-none"
                />
                {errors.name && <p className="text-[10px] font-black uppercase text-ares-red mt-1">{errors.name.message}</p>}
              </div>

              <div className="relative">
                <label htmlFor="venue_address" className="text-xs uppercase tracking-widest text-marble/90 font-bold mb-2 block">Street Address (Auto-suggest) *</label>
                <div className="relative">
                  <input 
                    id="venue_address"
                    type="text" 
                    {...register("address")}
                    className="w-full bg-obsidian border border-white/10 rounded p-3 text-white focus:border-ares-cyan outline-none"
                    placeholder="Start typing an address..."
                  />
                  {isSearchingOSM && <div className="absolute right-3 top-1/2 -translate-y-1/2 text-marble/50 text-xs">...</div>}
                </div>
                {errors.address && <p className="text-[10px] font-black uppercase text-ares-red mt-1">{errors.address.message}</p>}

                {suggestions.length > 0 && (
                  <div className="absolute z-20 w-full mt-1 bg-black border border-white/10 ares-cut-sm shadow-xl overflow-hidden">
                    {suggestions.map((s, i) => (
                      <button
                        key={i}
                        type="button"
                        className="w-full text-left p-3 hover:bg-ares-cyan hover:text-black border-b border-white/10 text-sm text-marble transition-colors last:border-0"
                        onClick={() => {
                          setValue("address", s.display_name);
                          const mapsLink = `https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(s.display_name)}`;
                          setValue("maps_url", mapsLink);
                          setSuggestions([]);
                        }}
                      >
                        {s.display_name}
                      </button>
                    ))}
                  </div>
                )}
              </div>

              <div>
                <label htmlFor="maps_url" className="text-xs uppercase tracking-widest text-marble/90 font-bold mb-2 flex items-center justify-between">
                  <span>Google Maps URL</span>
                  <span className="text-marble/40 text-xs lowercase tracking-normal bg-obsidian border border-white/10 px-2 py-0.5 rounded">Auto-generated</span>
                </label>
                <div className="flex gap-2">
                  <input 
                    id="maps_url"
                    type="text" 
                    {...register("maps_url")}
                    readOnly
                    className="flex-1 bg-obsidian/50 border border-white/5 rounded p-3 text-marble/50 outline-none cursor-not-allowed text-sm font-mono"
                  />
                  {mapsUrl && (
                    <a href={mapsUrl} target="_blank" rel="noreferrer" title="Open in Google Maps" className="bg-white/10 flex items-center justify-center px-4 rounded hover:bg-white/20 text-marble/90">
                      <Navigation size={18} />
                    </a>
                  )}
                </div>
              </div>

              {errorMsg && (
                <div className="p-3 ares-cut-sm bg-ares-red text-white text-sm font-bold shadow-lg shadow-ares-red/20">
                  {errorMsg}
                </div>
              )}

              <div className="flex gap-3 justify-end mt-4 pt-4 border-t border-white/10">
                <button 
                  type="button"
                  onClick={resetForm}
                  className="px-4 py-2 text-marble/90 hover:text-white font-bold text-sm tracking-widest uppercase"
                >
                  Cancel
                </button>
                <button 
                  type="submit"
                  disabled={saveMutation.isPending}
                  className="bg-ares-cyan text-black px-6 py-2 rounded font-bold text-sm tracking-widest uppercase shadow hover:bg-white disabled:opacity-50 flex items-center gap-2 transition-all"
                >
                  {saveMutation.isPending ? 'Saving...' : <><CheckCircle size={16}/> Save Venue</>}
                </button>
              </div>
            </div>
          </form>
        )}
      </div>
    </div>
  );
}

import { useQuery } from "@tanstack/react-query";
import { Search, Clock, Users, Activity } from "lucide-react";
import { useState } from "react";
import { api } from "../api/client";

interface RosterMember {
  user_id: string;
  first_name: string;
  last_name: string;
  nickname: string;
  member_type: string;
  attended_events: number;
  manual_prep_hours: number;
  event_volunteer_hours: number;
}

import DashboardPageHeader from "./dashboard/DashboardPageHeader";

export default function MemberImpactOverview() {
  const [searchTerm, setSearchTerm] = useState("");

  const { data: rosterRes, isLoading, isError } = api.analytics.getRosterStats.useQuery({
    queryKey: ["admin-roster-stats"],
  });
  const roster = (rosterRes?.body as any)?.roster || [];

  if (isLoading) {
    return (
      <div className="flex justify-center items-center h-64">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-ares-red"></div>
      </div>
    );
  }

  // Calculate full roster stats
  const enrichedRoster = roster.map(m => ({
    ...m,
    total_hours: m.manual_prep_hours + m.event_volunteer_hours,
    display_name: m.nickname || `${m.first_name || ""} ${m.last_name || ""}`.trim() || "ARES Member"
  }));

  // Filtering for MVPs (top 3 students only)
  const students = enrichedRoster.filter(m => m.member_type === "student" && (m.attended_events > 0 || m.total_hours > 0));

  const topAttendance = [...students].sort((a, b) => b.attended_events - a.attended_events).slice(0, 3);
  const topOutreach = [...students].sort((a, b) => b.total_hours - a.total_hours).slice(0, 3);

  // Search filter
  const filteredRoster = enrichedRoster.filter(m => 
    m.display_name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    m.member_type.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="space-y-12">
      <DashboardPageHeader 
        title="Member Impact Registry" 
        subtitle="Tracking the direct contribution and service hours of ARES 23247."
        icon={<Activity className="text-ares-red" />}
      />
      {isError && (
        <div className="bg-ares-red/10 border border-ares-red/30 p-4 ares-cut-sm text-ares-red text-xs font-bold mb-6 flex items-center gap-2">
          <span className="w-2 h-2 rounded-full bg-ares-red animate-pulse" />
          TELEMETRY FAULT: Failed to synchronize roster data. Displaying cached or empty state.
        </div>
      )}
      {/* MVP Podiums */}
      {students.length > 0 && (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
          {/* Attendance MVP */}
          <div className="bg-obsidian/40 border border-white/10 ares-cut-lg p-6 relative overflow-hidden group">
            <div className="absolute top-0 right-0 w-64 h-64 bg-ares-red/10 blur-[80px] rounded-full pointer-events-none" />
            <h3 className="text-xs font-black uppercase tracking-widest text-ares-red flex items-center gap-2 mb-6">
              <Users size={14} /> Attendance MVPs
            </h3>
            
            <div className="flex flex-col gap-4">
              {topAttendance.map((mvp, idx) => (
                <div key={mvp.user_id} className={`flex items-center gap-4 p-4 ares-cut border transition-colors ${
                  idx === 0 ? "bg-ares-gold/10 border-ares-gold/20" : 
                  idx === 1 ? "bg-white/10 border-white/20" : 
                  "bg-ares-bronze/10 border-ares-bronze/20"
                }`}>
                  <div className={`w-10 h-10 ares-cut-sm flex items-center justify-center font-black ${
                     idx === 0 ? "bg-ares-gold/20 text-ares-gold" : 
                     idx === 1 ? "bg-white/20 text-white" : 
                     "bg-ares-bronze/20 text-ares-bronze"
                  }`}>
                    #{idx + 1}
                  </div>
                  <div className="flex-1">
                    <p className="font-bold text-white tracking-tight">{mvp.display_name}</p>
                    <p className="text-xs text-white/60 uppercase tracking-widest font-bold">Student</p>
                  </div>
                  <div className="text-right">
                    <p className="text-2xl font-black text-white">{mvp.attended_events}</p>
                    <p className="text-xs font-bold uppercase tracking-widest text-white/60">Events</p>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* Outreach MVP */}
          <div className="bg-obsidian/40 border border-white/10 ares-cut-lg p-6 relative overflow-hidden group">
            <div className="absolute top-0 right-0 w-64 h-64 bg-ares-cyan/10 blur-[80px] rounded-full pointer-events-none" />
            <h3 className="text-xs font-black uppercase tracking-widest text-ares-cyan flex items-center gap-2 mb-6">
              <Clock size={14} /> Outreach MVPs
            </h3>
            
            <div className="flex flex-col gap-4">
              {topOutreach.map((mvp, idx) => (
                <div key={mvp.user_id} className={`flex items-center gap-4 p-4 ares-cut border transition-colors ${
                  idx === 0 ? "bg-ares-gold/10 border-ares-gold/20" : 
                  idx === 1 ? "bg-white/10 border-white/20" : 
                  "bg-ares-bronze/10 border-ares-bronze/20"
                }`}>
                  <div className={`w-10 h-10 ares-cut-sm flex items-center justify-center font-black ${
                     idx === 0 ? "bg-ares-gold/20 text-ares-gold" : 
                     idx === 1 ? "bg-white/20 text-white" : 
                     "bg-ares-bronze/20 text-ares-bronze"
                  }`}>
                    #{idx + 1}
                  </div>
                  <div className="flex-1">
                    <p className="font-bold text-white tracking-tight">{mvp.display_name}</p>
                    <p className="text-xs text-white/60 uppercase tracking-widest font-bold">Student</p>
                  </div>
                  <div className="text-right">
                    <p className="text-2xl font-black text-white">{mvp.total_hours.toFixed(1)}</p>
                    <p className="text-xs font-bold uppercase tracking-widest text-white/60">Hours</p>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      {/* Roster Table */}
      <div className="bg-obsidian/40 border border-white/10 ares-cut-lg overflow-hidden">
        <div className="p-6 border-b border-white/10 flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div>
            <h3 className="text-lg font-black text-white">Full Team Roster</h3>
            <p className="text-sm text-white/60 font-medium tracking-tight">Detailed attendance and volunteering metrics for export.</p>
          </div>
          
          <div className="relative w-full md:w-64">
            <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-white/60" />
            <input
              type="text"
              placeholder="Search member..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full bg-obsidian border border-white/10 ares-cut-sm pl-10 pr-4 py-2 text-sm text-white focus:outline-none focus:border-white/20 transition-colors"
            />
          </div>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full">
            <thead>
              <tr className="border-b border-white/10 bg-white/5">
                <th className="text-left py-4 px-6 text-xs font-black uppercase tracking-widest text-white/60">Member</th>
                <th className="text-left py-4 px-6 text-xs font-black uppercase tracking-widest text-white/60">Type</th>
                <th className="text-left py-4 px-6 text-xs font-black uppercase tracking-widest text-white/60">Events Attended</th>
                <th className="text-left py-4 px-6 text-xs font-black uppercase tracking-widest text-white/60">Volunteer Hours</th>
              </tr>
            </thead>
            <tbody>
              {filteredRoster.map(m => (
                <tr key={m.user_id} className="border-b border-white/5 hover:bg-white/10 transition-colors">
                  <td className="py-4 px-6">
                    <div className="flex items-center gap-3">
                      <img src={`https://api.dicebear.com/9.x/bottts/svg?seed=${m.user_id}`} alt="avatar" className="w-8 h-8 ares-cut-sm bg-obsidian" />
                      <span className="font-bold text-white tracking-tight">{m.display_name}</span>
                    </div>
                  </td>
                  <td className="py-4 px-6">
                    <span className="px-2 py-1 bg-white/5 border border-white/10 ares-cut-sm text-xs uppercase font-bold text-white/60">
                      {m.member_type}
                    </span>
                  </td>
                  <td className="py-4 px-6">
                    <span className="text-white font-bold">{m.attended_events}</span>
                  </td>
                  <td className="py-4 px-6">
                    <span className="text-white font-bold">{m.total_hours.toFixed(1)} <span className="text-white/60 text-xs font-medium">hrs</span></span>
                  </td>
                </tr>
              ))}
              {filteredRoster.length === 0 && (
                <tr>
                  <td colSpan={4} className="py-12 text-center text-white/20 font-medium italic">
                    No members match your search criteria.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

import { Link, useNavigate } from "react-router-dom";
import { useState, useEffect, useRef } from "react";
import { Search, LayoutDashboard, LogIn, Bell, Check, Heart } from "lucide-react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";



import { GreekMeander } from "./GreekMeander";
import { api } from "../api/client";
import { useDashboardSession } from "../hooks/useDashboardSession";
import { useDashboardNotifications } from "../hooks/useDashboardNotifications";
import { useUIStore } from "../store/uiStore";

export default function Navbar() {
  const { setSidebarOpen } = useUIStore();
  const [open, setOpen] = useState(false);

  const navigate = useNavigate();
  const { session, isPending, permissions } = useDashboardSession();

  const isSignedIn = !isPending && session?.authenticated;
  const userImage = session?.user?.image;
   
  // Unused permissions omitted to satisfy ESLint
  
  const { pendingInquiries, pendingPosts, pendingEvents, pendingDocs } = useDashboardNotifications(session, permissions);
  
  const [showNotifs, setShowNotifs] = useState(false);
  const notifRef = useRef<HTMLDivElement>(null);
  const queryClient = useQueryClient();

  useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (notifRef.current && !notifRef.current.contains(event.target as Node)) {
        setShowNotifs(false);
      }
    }
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const { data: notifRes } = api.notifications.getNotifications.useQuery({
    queryKey: ["notifications"],
    enabled: !!isSignedIn,
    refetchInterval: 30000 // Poll every 30s
  });

  const markAllRead = api.notifications.markAllAsRead.useMutation({
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["notifications"] });
    }
  });

  const markRead = api.notifications.markAsRead.useMutation({
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["notifications"] });
    }
  });

  const rawNotifications = (notifRes?.body as any)?.notifications || [];
  
  // Combine db notifications with pending inquiries and pending posts
  const notifications = [
    ...rawNotifications,
    ...pendingInquiries.map(i => ({
      id: `inquiry-${i.id}`,
      title: `New ${i.type === 'support' ? 'Support' : i.type === 'outreach' ? 'Outreach' : i.type === 'sponsor' ? 'Sponsor' : 'Inquiry'} Request`,
      message: `From ${i.name}`,
      is_read: false,
      link: '/dashboard/inquiries',
      is_inquiry: true
    })),
    ...pendingPosts.map(p => ({
      id: `post-${p.slug}`,
      title: `New Pending Post`,
      message: `"${p.title}" by ${p.author_nickname || 'Student'}`,
      is_read: false,
      link: '/dashboard/manage_blog',
      is_inquiry: true // Treat as action item (cannot be marked read)
    })),
    ...pendingEvents.map(e => ({
      id: `event-${e.id}`,
      title: `New Pending Event`,
      message: `"${e.title}"`,
      is_read: false,
      link: '/dashboard/manage_event',
      is_inquiry: true
    })),
    ...pendingDocs.map(d => ({
      id: `doc-${d.slug}`,
      title: `New Pending Doc`,
      message: `"${d.title}"`,
      is_read: false,
      link: '/dashboard/manage_docs',
      is_inquiry: true
    }))
  ];
  
  const unreadCount = notifications.filter((n) => !n.is_read).length;

  return (
    <nav role="navigation" aria-label="Main Navigation" className="fixed top-0 left-0 w-full z-50 bg-obsidian/85 backdrop-blur-xl shadow-2xl px-6 pt-4 pb-4 transition-all duration-500 overflow-visible rounded-b-2xl border-t-4 border-ares-bronze">
      <a 
        href="#main-content" 
        className="sr-only focus:not-sr-only focus:absolute focus:top-24 focus:left-6 bg-ares-red text-white px-6 py-3 ares-cut-sm font-bold z-[100] shadow-2xl border border-white/20 transition-all"
      >
        Skip to Main Content
      </a>
      <div className="absolute top-0 left-0 w-full h-full pointer-events-none overflow-hidden rounded-b-2xl">
        <GreekMeander variant="thin" opacity="opacity-40" className="absolute top-0 left-0" />
      </div>
      <div className="flex items-center justify-between relative z-10">
        <button 
          onClick={() => navigate("/")} 
          className="text-2xl font-bold tracking-tighter text-white flex items-center gap-2 font-heading focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ares-cyan rounded px-1"
          aria-label="ARES 23247 Home"
        >
          ARES <span className="bg-ares-red text-white px-2 py-0.5 ares-cut-sm shadow-inner font-bold">23247</span>
        </button>

        <div className="hidden md:flex items-center gap-8 text-sm font-bold uppercase tracking-widest">
          <Link to="/about" className="text-marble hover:text-ares-gold transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ares-cyan rounded px-2 py-1">About</Link>
          <Link to="/seasons" className="text-marble hover:text-ares-gold transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ares-cyan rounded px-2 py-1">Seasons</Link>
          <Link to="/outreach" className="text-marble hover:text-ares-gold transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ares-cyan rounded px-2 py-1">Outreach</Link>
          <Link to="/events" className="text-marble hover:text-ares-gold transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ares-cyan rounded px-2 py-1">Events</Link>
          <Link to="/blog" className="text-marble hover:text-ares-gold transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ares-cyan rounded px-2 py-1">Blog</Link>
          <Link to="/docs" className="hover:scale-105 active:scale-95 transition-all focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ares-cyan ares-cut-sm overflow-hidden flex items-center shadow-xl group border border-white/5 bg-white/5">
            <span className="bg-ares-red px-3 py-1.5 text-xs font-heading font-black uppercase text-white tracking-[0.15em] border-r border-white/10 shadow-[inset_-2px_0_4px_rgba(0,0,0,0.2)]">ARES</span>
            <span className="text-white px-3 py-1.5 text-xs font-heading font-bold uppercase tracking-[0.2em] group-hover:bg-white/10 transition-colors">LIB</span>
          </Link>
        </div>

        <div className="hidden md:flex items-center gap-4">
          <button
            onClick={() => window.dispatchEvent(new CustomEvent('open-command-palette'))}
            aria-label="Open Command Palette"
            className="flex items-center gap-2 px-3 py-1.5 ares-cut-sm bg-white/10 hover:bg-white/20 text-marble/90 hover:text-white transition-all focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ares-cyan border border-white/10"
          >
            <Search size={14} aria-hidden="true" />
            <span className="text-xs sm:text-xs font-mono flex items-center gap-2 whitespace-nowrap">
              Search... 
              <span className="hidden lg:flex items-center gap-1 opacity-60">
                <kbd className="bg-black/40 text-white px-1.5 py-0.5 rounded border border-white/20 leading-none">Ctrl</kbd>
                <kbd className="bg-black/40 text-white px-1.5 py-0.5 rounded border border-white/20 leading-none">K</kbd>
              </span>
            </span>
          </button>
          {isSignedIn && (
              <div className="relative" ref={notifRef}>
                <button 
                  onClick={() => setShowNotifs(!showNotifs)}
                className="relative flex items-center justify-center p-2 ares-cut-sm bg-white/5 hover:bg-white/10 border border-white/10 transition-all focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ares-cyan"
                aria-label="Notifications"
              >
                <Bell size={18} className="text-white" />
                {unreadCount > 0 && (
                  <span className="absolute top-0 right-0 flex h-3 w-3">
                    <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-ares-red opacity-75"></span>
                    <span className="relative inline-flex rounded-full h-3 w-3 bg-ares-danger text-[9px] font-bold text-white items-center justify-center">
                      {unreadCount}
                    </span>
                  </span>
                )}
              </button>
              
              {showNotifs && (
                <div className="absolute top-12 right-0 w-80 bg-obsidian border border-white/10 shadow-2xl rounded-lg overflow-hidden flex flex-col z-[200]">
                  <div className="flex items-center justify-between px-4 py-3 border-b border-white/10 bg-black/20">
                    <h3 className="text-sm font-bold text-white">Notifications</h3>
                    {unreadCount > 0 && (
                      <button 
                        onClick={() => markAllRead.mutate()}
                        className="text-xs text-ares-gold hover:text-white flex items-center gap-1"
                      >
                        <Check size={12} /> Mark Read
                      </button>
                    )}
                  </div>
                  <ul className="flex-1 overflow-y-auto max-h-96 w-full list-none p-0 m-0">
                    {notifications.length === 0 ? (
                      <li className="px-4 py-6 text-center text-sm text-marble/50">
                        No notifications yet.
                      </li>
                    ) : (
                      notifications.map((n) => (
                        <li key={n.id}>
                          <div 
                            role="button"
                            tabIndex={0}
                            className={`px-4 py-3 border-b border-white/5 flex flex-col gap-1 hover:bg-white/5 cursor-pointer focus:bg-white/5 focus:outline-none focus:ring-1 focus:ring-ares-cyan/50 ${n.is_read ? 'opacity-60' : 'bg-ares-red/5'}`}
                            onKeyDown={(e) => {
                              if (e.key === 'Enter' || e.key === ' ') {
                                e.preventDefault();
                                // @ts-expect-error custom flag
                                if (!n.is_read && !n.is_inquiry) markRead.mutate(n.id);
                                if (n.link) navigate(n.link);
                                setShowNotifs(false);
                              }
                            }}
                            onClick={() => {
                              // @ts-expect-error custom flag
                              if (!n.is_read && !n.is_inquiry) markRead.mutate(n.id);
                              if (n.link) navigate(n.link);
                              setShowNotifs(false);
                            }}
                          >
                          <div className="flex justify-between items-start gap-2">
                             <span className="text-sm font-bold text-white">{n.title}</span>
                             {!n.is_read && <span className="h-2 w-2 rounded-full bg-ares-red flex-shrink-0 mt-1"></span>}
                          </div>
                          <span className="text-xs text-marble/90 line-clamp-2">{n.message}</span>
                          </div>
                        </li>
                      ))
                    )}
                  </ul>
                </div>
              )}
            </div>
          )}
          {isSignedIn && (
            <Link to="/dashboard" className="relative flex items-center gap-2 px-3 py-1.5 bg-white/5 hover:bg-white/10 border border-white/10 ares-cut-sm transition-all group" aria-label="Dashboard">
              <img 
                src={userImage || `https://api.dicebear.com/9.x/bottts/svg?seed=${session?.user?.id}`} 
                alt="" 
                className="w-6 h-6 rounded-full bg-black/40" 
              />
              <span className="text-xs font-bold text-white group-hover:text-white uppercase tracking-wider">Dashboard</span>
            </Link>
          )}
          {!isPending && !isSignedIn && (
            <Link to="/login" className="flex items-center gap-2 px-4 py-1.5 bg-white/5 hover:bg-white/10 border border-white/10 hover:border-ares-gold/30 ares-cut-sm transition-all group" aria-label="Sign In">
              <LogIn size={14} className="text-ares-gold" />
              <span className="text-xs font-bold text-white group-hover:text-ares-gold uppercase tracking-wider">Sign In</span>
            </Link>
          )}


          <Link to="/sponsors" className="hidden md:flex bg-ares-red text-white px-6 py-2 rounded-tl-[1.2rem] rounded-br-[1.2rem] rounded-tr-md rounded-bl-md font-bold uppercase tracking-widest text-xs hover:bg-ares-bronze hover:text-white transition-all shadow-lg items-center gap-2">
            <Heart size={14} className="fill-white" />
            <span>Support Us</span>
          </Link>
        </div>


        <button 
          onClick={() => {
            if (window.innerWidth < 768) {
              setSidebarOpen(true);
            } else {
              setOpen(!open);
            }
          }} 
          className="md:hidden text-ares-gold w-10 h-10 flex flex-col justify-center items-center gap-1.5 focus:outline-none focus-visible:ring-2 focus-visible:ring-ares-cyan rounded transition-colors group"
          aria-label={open ? "Close navigation menu" : "Open navigation menu"}
          aria-expanded={open}
        >
          <span className={`w-7 h-1 bg-current block rounded-full transition-all duration-300 ${open ? "rotate-45 translate-y-2.5" : "group-hover:w-8"}`}></span>
          <span className={`w-7 h-1 bg-current block rounded-full transition-opacity duration-300 ${open ? "opacity-0" : "group-hover:w-5"}`}></span>
          <span className={`w-7 h-1 bg-current block rounded-full transition-all duration-300 ${open ? "-rotate-45 -translate-y-2.5" : "group-hover:w-8"}`}></span>
        </button>
      </div>

      {open && (
        <div className="md:hidden mt-4 flex flex-col gap-4 text-sm font-bold uppercase tracking-widest px-2 pb-4 border-t border-white/10 pt-4">
          <button onClick={() => { setOpen(false); window.dispatchEvent(new CustomEvent('open-command-palette')); }} className="text-left text-ares-gold flex items-center gap-2 mb-2 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ares-cyan rounded px-2 py-1">
            <Search size={16} aria-hidden="true" /> Command Palette
          </button>
          <div className="flex flex-col gap-6 p-8">
          <Link to="/about" onClick={() => setOpen(false)} className="text-xl font-black text-white italic tracking-tighter">WHO WE ARE</Link>
          <Link to="/seasons" onClick={() => setOpen(false)} className="text-xl font-black text-white italic tracking-tighter">SEASONS</Link>
          <Link to="/outreach" onClick={() => setOpen(false)} className="text-xl font-black text-white italic tracking-tighter">OUTREACH</Link>
          <Link to="/events" onClick={() => setOpen(false)} className="text-xl font-black text-white italic tracking-tighter">EVENTS</Link>
          <Link to="/blog" onClick={() => setOpen(false)} className="text-xl font-black text-white italic tracking-tighter text-ares-gold">TEAM BLOG</Link>
          <Link to="/sponsors" onClick={() => setOpen(false)} className="text-xl font-black text-white italic tracking-tighter">SUPPORT US</Link>
        </div>
          {isSignedIn && (
            <Link to="/dashboard" onClick={() => setOpen(false)} className="text-ares-gold hover:text-white flex items-center gap-2 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ares-cyan rounded px-2 py-1 w-max">
              <LayoutDashboard size={16} /> Dashboard
            </Link>
          )}
          {!isPending && !isSignedIn && (
            <Link to="/login" onClick={() => setOpen(false)} className="text-ares-gold hover:text-white flex items-center gap-2 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ares-cyan rounded px-2 py-1">
              <LogIn size={16} /> Sign In
            </Link>
          )}
          <Link to="/join" onClick={() => setOpen(false)} className="text-marble hover:text-ares-gold focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ares-cyan rounded px-2 py-1">Join Us</Link>
          <Link to="/sponsors" onClick={() => setOpen(false)} className="text-marble hover:text-ares-red focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ares-cyan rounded px-2 py-1">Support Us</Link>
          
        </div>

      )}

    </nav>
  );
}

import { useState, useMemo } from "react";
import DashboardPageHeader from "./dashboard/DashboardPageHeader";
import DashboardMetricsGrid from "./dashboard/DashboardMetricsGrid";
import DashboardEmptyState from "./dashboard/DashboardEmptyState";
import DashboardLoadingGrid from "./dashboard/DashboardLoadingGrid";
import { DashboardInput, DashboardTextarea, DashboardSubmitButton } from "./dashboard/DashboardFormInputs";
import { useQueryClient } from "@tanstack/react-query";
import { Plus, Trash2, MapPin, Users, Clock, Target, Calendar, CheckCircle, XCircle, Save } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import { api } from "../api/client";
import SeasonPicker from "./SeasonPicker";
import { toast } from "sonner";
import { useForm, useWatch } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { outreachSchema } from "../schemas/contracts/outreachContract";
import { z } from "zod";

const outreachFormSchema = outreachSchema.omit({ id: true }).extend({
  id: z.string().optional(),
});

type OutreachFormValues = z.infer<typeof outreachFormSchema>;

interface OutreachLog {
  id: string;
  title: string;
  date: string;
  location: string | null;
  students_count: number;
  hours_logged: number;
  reach_count: number;
  description: string | null;
  season_id?: string | null;
  is_dynamic?: boolean;
}

export default function OutreachTracker() {
  const queryClient = useQueryClient();
  const [isAdding, setIsAdding] = useState(false);

  const { register, handleSubmit, reset, setValue, control, formState: { errors } } = useForm<OutreachFormValues>({
    resolver: zodResolver(outreachFormSchema),
    defaultValues: {
      title: "",
      date: new Date().toISOString().split('T')[0],
      location: "",
      students_count: 0,
      hours_logged: 0,
      reach_count: 0,
      description: "",
      season_id: ""
    }
  });

  const seasonId = useWatch({ control, name: "season_id" });

  const { data: outreachData, isLoading } = api.outreach.adminList.useQuery({
    queryKey: ["admin-outreach"]
  });

  const logs = useMemo(() => (outreachData?.body as any)?.logs || [], [outreachData]);

  const saveMutation = api.outreach.save.useMutation({
    onSuccess: (res: any) => {
      if (res.status === 200) {
        toast.success("Impact record synchronized.");
        queryClient.invalidateQueries({ queryKey: ["admin-outreach"] });
        setIsAdding(false);
        reset();
      } else {
        toast.error("Failed to save impact record.");
      }
    }
  });

  const deleteMutation = api.outreach.delete.useMutation({
    onSuccess: (res: any) => {
      if (res.status === 200) {
        toast.success("Impact record purged.");
        queryClient.invalidateQueries({ queryKey: ["admin-outreach"] });
      }
    }
  });

  const onFormSubmit = (data: OutreachFormValues) => {
    const finalId = data.id || data.title.toLowerCase().replace(/[^a-z0-9]+/g, '-') + '-' + data.date;
    saveMutation.mutate({ body: { ...data, id: finalId } as any });
  };

  const totals = useMemo(() => logs.reduce((acc: any, l: any) => ({
    hours: acc.hours + (l.hours_logged || 0),
    reach: acc.reach + (l.reach_count || 0),
    students: acc.students + (l.students_count || 0),
    events: acc.events + 1
  }), { hours: 0, reach: 0, students: 0, events: 0 }), [logs]);

  return (
    <div className="space-y-8">
      {/* Metrics Summary */}
      <DashboardMetricsGrid 
        metrics={[
          { label: "Community Reach", value: totals.reach.toLocaleString(), icon: <Target className="text-ares-red" /> },
          { label: "Service Hours", value: totals.hours.toLocaleString(), icon: <Clock className="text-ares-gold" /> },
          { label: "Student Leads", value: totals.students.toLocaleString(), icon: <Users className="text-ares-cyan" /> },
          { label: "Total Events", value: totals.events, icon: <CheckCircle className="text-ares-gold" /> },
        ]}
      />

      <DashboardPageHeader
        title="Impact Logging"
        subtitle="Document every interaction for the FIRST Impact Award."
        icon={<Target className="text-ares-red" />}
        italicTitle={true}
        action={
          <button
            onClick={() => {
              if (isAdding) {
                setIsAdding(false);
                reset();
              } else {
                setIsAdding(true);
              }
            }}
            className="flex items-center gap-2 px-4 py-2 bg-ares-red text-white font-bold ares-cut-sm hover:bg-ares-danger transition-colors shadow-lg shadow-ares-red/20"
          >
            {isAdding ? <XCircle size={18} /> : <Plus size={18} />}
            {isAdding ? "Cancel" : "Log Outreach"}
          </button>
        }
      />

      <AnimatePresence>
        {isAdding && (
          <motion.form
            initial={{ opacity: 0, y: -20 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -20 }}
            onSubmit={handleSubmit(onFormSubmit)}
            className="bg-obsidian border border-ares-red/30 ares-cut-lg p-8 space-y-6 shadow-2xl"
          >
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              <DashboardInput
                id="outreach-title"
                label="Event Title"
                {...register("title")}
                error={errors.title?.message}
                placeholder="e.g. Robot Demo at City Library"
                focusColor="ares-red"
                fullWidth
              />
              <DashboardInput
                id="outreach-date"
                type="date"
                label="Date"
                {...register("date")}
                error={errors.date?.message}
                focusColor="ares-red"
              />
              <DashboardInput
                id="outreach-reach"
                type="number"
                label="Reach Count (Estimated)"
                {...register("reach_count", { valueAsNumber: true })}
                error={errors.reach_count?.message}
                focusColor="ares-red"
              />
              <DashboardInput
                id="outreach-hours"
                type="number"
                step="0.5"
                label="Hours Logged"
                {...register("hours_logged", { valueAsNumber: true })}
                error={errors.hours_logged?.message}
                focusColor="ares-red"
              />
              <DashboardInput
                id="outreach-students"
                type="number"
                label="Students Participating"
                {...register("students_count", { valueAsNumber: true })}
                error={errors.students_count?.message}
                focusColor="ares-red"
              />
              <DashboardTextarea
                id="outreach-desc"
                label="Description / Impact Summary"
                {...register("description")}
                placeholder="Summarize the community impact..."
                focusColor="ares-red"
                fullWidth
              />
              <SeasonPicker value={seasonId || ""} onChange={(val) => setValue("season_id", val)} />
            </div>
            <DashboardSubmitButton 
              isPending={saveMutation.isPending} 
              defaultText="Finalize Impact Entry" 
              icon={<Save size={20} />} 
              theme="red" 
            />
          </motion.form>
        )}
      </AnimatePresence>

      <div className="space-y-4">
        {isLoading ? (
          <DashboardLoadingGrid count={2} heightClass="h-48" gridClass="grid-cols-1 lg:grid-cols-2" />
        ) : logs.map((log: any) => (
          <div key={log.id} className="bg-black/40 border border-white/5 ares-cut-lg p-6 group hover:border-white/20 transition-all flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
            <div className="flex-1">
              <div className="flex items-center gap-3 text-marble/50 text-xs font-bold uppercase tracking-widest mb-2">
                 <span className="flex items-center gap-1"><Calendar size={12} /> {log.date}</span>
                 {log.location && <span className="flex items-center gap-1">&middot; <MapPin size={12} /> {log.location}</span>}
              </div>
              <h4 className="text-xl font-bold text-white mb-2">{log.title}</h4>
              <p className="text-marble/50 text-sm line-clamp-2">
                {(() => {
                  try {
                    const ast = JSON.parse(log.description || "");
                    if (ast && ast.type === "doc") {
                      const extract = (node: any): string => {
                        if (node.text) return node.text;
                        if (node.content) return node.content.map(extract).join(" ");
                        return "";
                      };
                      return extract(ast);
                    }
                  } catch {
                    // Ignore parse errors to return raw string
                  }
                  return log.description;
                })()}
              </p>
            </div>

            <div className="flex items-center gap-4">
              <div className="flex flex-col items-center px-4 py-2 bg-white/5 ares-cut min-w-[80px]">
                <span className="text-xs font-black text-ares-gold uppercase tracking-tighter">Reach</span>
                <span className="text-lg font-black text-white">{log.reach_count || 0}</span>
              </div>
              <div className="flex flex-col items-center px-4 py-2 bg-white/5 ares-cut min-w-[80px]">
                <span className="text-xs font-black text-ares-cyan uppercase tracking-tighter">Hours</span>
                <span className="text-lg font-black text-white">{(log.hours_logged || 0).toFixed(1)}</span>
              </div>

              {log.is_dynamic ? (
                <div className="flex items-center px-3 py-1 bg-ares-gold/10 border border-ares-gold/20 ares-cut-sm">
                  <span className="text-xs font-bold text-ares-gold uppercase tracking-widest text-center leading-tight">Synced<br/>Event</span>
                </div>
              ) : (
                <button
                  onClick={() => { if(confirm("Purge this impact record?")) deleteMutation.mutate({ params: { id: log.id }, body: null }); }}
                  title="Purge this impact record"
                  className="p-3 text-marble/40 hover:text-ares-red transition-colors bg-white/5 ares-cut opacity-0 group-hover:opacity-100"
                >
                  <Trash2 size={18} />
                </button>
              )}
            </div>
          </div>
        ))}
        {logs.length === 0 && !isLoading && !isAdding && (
          <DashboardEmptyState
            icon={<Target size={48} />}
            message="No outreach records found. Start logging your team's impact."
          />
        )}
      </div>
    </div>
  );
}

import { useState, useEffect } from "react";
import { motion } from "framer-motion";
import { api } from "../api/client";
import { Save, RefreshCw, Shield } from "lucide-react";
import { useQueryClient } from "@tanstack/react-query";
import { IdentityForm } from "./profile/IdentityForm";
import { RoleForm } from "./profile/RoleForm";
import { ContactForm } from "./profile/ContactForm";
import { LogisticsForm } from "./profile/LogisticsForm";
import { SecuritySettings } from "./profile/SecuritySettings";
import { ProfileData } from "./profile/types";
import { useForm, useWatch } from "react-hook-form";


const DEFAULT_PROFILE: ProfileData = {
  email: "",
  first_name: "", last_name: "", nickname: "", phone: "", contact_email: "", show_email: false, show_phone: false,
  pronouns: "", grade_year: "", subteams: [], member_type: "student",
  bio: "", favorite_food: "", dietary_restrictions: [],
  favorite_first_thing: "", fun_fact: "",
  colleges: [], employers: [], show_on_about: true,
  favorite_robot_mechanism: "", pre_match_superstition: "", leadership_role: "", rookie_year: "",
  tshirt_size: "", emergency_contact_name: "", emergency_contact_phone: "",
  parents_name: "", parents_email: "", students_name: "", students_email: "",
};

const safeJSONParse = <T,>(val: unknown, fallback: T): T => {
  if (val === null || val === undefined || val === "") return fallback;
  if (typeof val === "string") {
    try {
      const parsed = JSON.parse(val);
      return parsed === null ? fallback : (parsed as T);
    } catch {
      return fallback;
    }
  }
  return val as T;
};

export default function ProfileEditor({ adminEditUserId }: { adminEditUserId?: string }) {
  const queryClient = useQueryClient();
  const [message, setMessage] = useState<{ type: "success" | "error"; text: string } | null>(null);

  const { register, handleSubmit, reset, setValue, control, formState: { errors } } = useForm<ProfileData>({
    defaultValues: DEFAULT_PROFILE
  });

  const profileValues = useWatch({ control });

  const { isLoading, isError } = api.profiles.getMe.useQuery({
    queryKey: ["profile", adminEditUserId || "me"],
    // Logic for admin fetch would go here if we had an adminContract for users
  });

  useEffect(() => {
    // If it's a "me" fetch
    if (!adminEditUserId && (api.profiles.getMe as any).data?.body) {
      const data = (api.profiles.getMe as any).data.body;
      reset({
        ...DEFAULT_PROFILE,
        ...data.profile,
        email: data.user?.email || "",
        subteams: safeJSONParse(data.profile?.subteams, []),
        dietary_restrictions: safeJSONParse(data.profile?.dietary_restrictions, []),
        colleges: safeJSONParse(data.profile?.colleges, []),
        employers: safeJSONParse(data.profile?.employers, []),
        show_email: Boolean(data.profile?.show_email),
        show_phone: Boolean(data.profile?.show_phone),
        show_on_about: data.profile?.show_on_about !== undefined ? Boolean(data.profile.show_on_about) : true,
      });
    }
  }, [adminEditUserId, reset]);

  const saveMutation = api.profiles.updateMe.useMutation({
    onSuccess: () => {
      setMessage({ type: "success", text: "Profile saved!" });
      queryClient.invalidateQueries({ queryKey: ["profile"] });
      queryClient.invalidateQueries({ queryKey: ["admin_users"] });
    },
    onError: (err: any) => {
      setMessage({ type: "error", text: err.message || "Failed to save profile." });
    }
  });

  const onFormSubmit = (data: ProfileData) => {
    const formatted = {
      ...data,
      subteams: JSON.stringify(data.subteams),
      dietary_restrictions: JSON.stringify(data.dietary_restrictions),
      colleges: JSON.stringify(data.colleges),
      employers: JSON.stringify(data.employers),
      show_email: data.show_email ? 1 : 0,
      show_phone: data.show_phone ? 1 : 0,
      show_on_about: data.show_on_about ? 1 : 0,
    };
    saveMutation.mutate({ body: formatted });
  };

  const isMinor = profileValues.member_type === "student";

  if (isLoading) {
    return <div className="flex items-center justify-center py-20"><RefreshCw className="animate-spin text-ares-red" size={32} /></div>;
  }

  const inputClass = "w-full bg-white/5 border border-white/10 ares-cut-sm px-4 py-3 text-sm text-white placeholder-marble/40 focus:outline-none focus:border-ares-red transition-colors";
  const labelClass = "text-xs font-bold text-marble/90 uppercase tracking-wider mb-1.5 block";
  const sectionClass = "bg-obsidian/50 border border-white/10 ares-cut p-6 space-y-4";

  // Manual setter helper for legacy sub-forms
  const setProfile = (updater: any) => {
    const next = typeof updater === "function" ? updater(profileValues) : updater;
    reset(next);
  };

  return (
    <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="max-w-3xl mx-auto space-y-6 pb-8">
      {isError && (
        <div className="bg-ares-red/10 border border-ares-red/30 p-4 ares-cut-sm text-ares-red text-xs font-bold mb-6 flex items-center gap-2">
          <span className="w-2 h-2 rounded-full bg-ares-red animate-pulse" />
          TELEMETRY FAULT: Failed to synchronize personal identity records.
        </div>
      )}

      {/* Youth Protection Banner for Students */}
      {isMinor && (
        <div className="flex items-start gap-3 p-4 bg-ares-cyan/10 border border-ares-cyan/20 ares-cut">
          <Shield className="text-ares-cyan flex-shrink-0 mt-0.5" size={20} />
          <p className="text-sm text-marble">
            <strong>FIRST Youth Protection:</strong> Your contact information (email, phone) is protected and never shown publicly. Only your nickname and avatar are visible to others.
          </p>
        </div>
      )}

      <form onSubmit={handleSubmit(onFormSubmit)} className="space-y-6">
        <IdentityForm profile={profileValues as any} setProfile={setProfile} isMinor={isMinor} inputClass={inputClass} labelClass={labelClass} sectionClass={sectionClass} />
        <RoleForm profile={profileValues as any} setProfile={setProfile} isMinor={isMinor} inputClass={inputClass} labelClass={labelClass} sectionClass={sectionClass} />
        <ContactForm profile={profileValues as any} setProfile={setProfile} isMinor={isMinor} inputClass={inputClass} labelClass={labelClass} sectionClass={sectionClass} />
        <SecuritySettings profile={profileValues as any} setProfile={setProfile} isMinor={isMinor} inputClass={inputClass} labelClass={labelClass} sectionClass={sectionClass} />
        <LogisticsForm profile={profileValues as any} setProfile={setProfile} isMinor={isMinor} inputClass={inputClass} labelClass={labelClass} sectionClass={sectionClass} />

        {/* Save */}
        {message && (
          <div className={`p-4 ares-cut-sm text-sm font-bold ${message.type === "success" ? "bg-ares-cyan/10 border border-ares-cyan/20 text-ares-cyan" : "bg-ares-red text-white shadow-lg shadow-ares-red/20"}`}>
            {message.text}
          </div>
        )}
        <button type="submit" disabled={saveMutation.isPending}
          className="w-full flex items-center justify-center gap-2 py-4 font-bold bg-gradient-to-r from-ares-red to-ares-bronze hover:from-ares-bronze hover:to-ares-red text-white ares-cut shadow-[0_0_30px_rgba(192,0,0,0.3)] transition-all disabled:opacity-50"
        >
          {saveMutation.isPending ? <RefreshCw className="animate-spin" size={20} /> : <Save size={20} />}
          {saveMutation.isPending ? "Saving..." : "Save Profile"}
        </button>
      </form>
    </motion.div>
  );
}

import { format } from "date-fns";
import { History, RotateCcw, X, Clock } from "lucide-react";
import { toast } from "sonner";
import { api } from "../api/client";
import { useQueryClient } from "@tanstack/react-query";

export interface Revision {
  id: number;
  title: string;
  author_email: string;
  created_at: string;
  category?: string;
  author?: string;
}

interface RevisionManagerProps {
  isOpen: boolean;
  onClose: () => void;
  type: "doc" | "post";
  slug: string;
  displayTitle: string;
}

export default function RevisionManager({ isOpen, onClose, type, slug, displayTitle }: RevisionManagerProps) {
  const queryClient = useQueryClient();

  const historyQuery = type === "post" 
    ? api.posts.getHistory.useQuery({
        params: { slug },
        queryKey: ["history", "post", slug],
        enabled: isOpen && !!slug && type === "post"
      })
    : api.docs.getHistory.useQuery({
        params: { slug },
        queryKey: ["history", "doc", slug],
        enabled: isOpen && !!slug && type === "doc"
      });

  const postRestoreMutation = api.posts.restoreHistory.useMutation({
    onSuccess: () => {
      toast.success("Post restored successfully");
      queryClient.invalidateQueries({ queryKey: ["posts"] });
      onClose();
    },
    onError: (err) => toast.error(err.message || "Post restoration failed")
  });

  const docRestoreMutation = api.docs.restoreHistory.useMutation({
    onSuccess: () => {
      toast.success("Doc restored successfully");
      queryClient.invalidateQueries({ queryKey: ["docs"] });
      onClose();
    },
    onError: (err) => toast.error(err.message || "Doc restoration failed")
  });

  const isLoading = historyQuery.isLoading;
  const isError = historyQuery.isError;
  const revisions = historyQuery.data?.status === 200 ? (historyQuery.data.body as { history: Revision[] }).history : [];

  const restoreRevision = (id: number) => {
    if (type === "post") {
      postRestoreMutation.mutate({ params: { slug, id: id.toString() }, body: {} });
    } else {
      docRestoreMutation.mutate({ params: { slug, id: id.toString() }, body: {} });
    }
  };

  const isRestoring = postRestoreMutation.isPending || docRestoreMutation.isPending;
  const restoringId = (postRestoreMutation.variables as any)?.params?.id || (docRestoreMutation.variables as any)?.params?.id;

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm animate-in fade-in duration-200">
      <div className="bg-obsidian border border-white/10 ares-cut-lg w-full max-w-2xl overflow-hidden shadow-2xl flex flex-col max-h-[80vh]">
        <div className="p-6 border-b border-white/10 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 ares-cut-sm bg-ares-gold/10 flex items-center justify-center text-ares-gold">
              <History size={20} />
            </div>
            <div>
              <h3 className="text-xl font-bold text-white tracking-tight">Revision History</h3>
              <p className="text-white/60 text-xs">Viewing legacy versions for <span className="text-white font-mono italic">&quot;{displayTitle}&quot;</span></p>
            </div>
          </div>
          <button onClick={onClose} title="Close history" className="text-white/60 hover:text-white transition-colors p-2 bg-white/5 border border-white/10 ares-cut-sm">
            <X size={20} />
          </button>
        </div>

        <div className="p-6 overflow-y-auto flex-1 custom-scrollbar">
          {isError && (
            <div className="bg-ares-red/10 border border-ares-red/30 p-4 ares-cut-sm text-ares-red text-xs font-bold mb-6 flex items-center gap-2">
              <span className="w-2 h-2 rounded-full bg-ares-red animate-pulse" />
              TELEMETRY FAULT: Failed to retrieve archive timeline.
            </div>
          )}
          {isLoading ? (
            <div className="h-48 flex items-center justify-center">
              <div className="w-8 h-8 border-2 border-white/10 border-t-ares-gold rounded-full animate-spin"></div>
            </div>
          ) : revisions.length === 0 ? (
            <div className="h-48 flex flex-col items-center justify-center text-white/60">
               <Clock size={32} className="mb-2 opacity-20" />
               <p className="text-sm italic">No legacy revisions found for this entry.</p>
               <p className="text-xs mt-1 text-white/60">History is captured automatically whenever an admin modifies content.</p>
            </div>
          ) : (
            <div className="space-y-3">
              {revisions.map((rev) => (
                <div key={rev.id} className="bg-white/5 border border-white/10 ares-cut p-4 flex items-center justify-between hover:border-white/20 transition-colors">
                  <div className="min-w-0 flex-1">
                    <div className="font-bold text-white truncate">{rev.title}</div>
                    <div className="flex items-center gap-2 mt-1">
                      <span className="text-xs text-white/60 bg-black/40 border border-white/10 px-2 py-0.5 ares-cut-sm">
                        {format(new Date(rev.created_at), 'MMM do, yyyy @ HH:mm')}
                      </span>
                      <span className="text-xs text-ares-cyan truncate max-w-[150px]">
                        By {rev.author_email}
                      </span>
                    </div>
                  </div>
                  <button
                    onClick={() => {
                        if (confirm(`Are you sure you want to restore "${displayTitle}" to the version from ${format(new Date(rev.created_at), 'PPP')}? Current unsaved changes might be lost if you haven't saved.`)) {
                           restoreRevision(rev.id);
                        }
                    }}
                    disabled={isRestoring}
                    className="flex items-center gap-2 text-xs font-bold text-ares-gold bg-ares-gold/10 hover:bg-ares-gold/20 border border-ares-gold/20 px-4 py-2 ares-cut-sm transition-all"
                  >
                    <RotateCcw size={14} className={isRestoring && restoringId === rev.id.toString() ? "animate-spin" : ""} />
                    {isRestoring && restoringId === rev.id.toString() ? "RESTORING..." : "RESTORE"}
                  </button>
                </div>
              ))}
            </div>
          )}
        </div>

        <div className="p-4 bg-white/5 border-t border-white/10 flex items-center justify-center">
            <p className="text-xs text-white/60 uppercase tracking-widest font-mono">End of Revision Timeline</p>
        </div>
      </div>
    </div>
  );
}

import { Canvas, useFrame } from "@react-three/fiber";
import { OrbitControls, PerspectiveCamera, MeshDistortMaterial, Float, Text, MeshWobbleMaterial } from "@react-three/drei";
import { useRef } from "react";
import * as THREE from "three";

const ARES_COLORS = {
  red: "#C00000",
  gold: "#FFB81C",
  cyan: "#00E5FF",
  dark: "#111111",
  grid: "#222222",
};

function RobotChassis() {
  const meshRef = useRef<THREE.Mesh>(null!);

  useFrame((state) => {
    const t = state.clock.getElapsedTime();
    meshRef.current.rotation.x = THREE.MathUtils.lerp(meshRef.current.rotation.x, Math.cos(t / 2) / 10 + 0.25, 0.1);
    meshRef.current.rotation.y = THREE.MathUtils.lerp(meshRef.current.rotation.y, Math.sin(t / 4) / 10, 0.1);
    meshRef.current.position.y = THREE.MathUtils.lerp(meshRef.current.position.y, (1 + Math.sin(t / 1.5)) / 10, 0.1);
  });

  return (
    <group>
      {/* Base Chassis */}
      <mesh ref={meshRef} receiveShadow castShadow>
        <boxGeometry args={[2, 0.5, 2]} />
        <MeshDistortMaterial color={ARES_COLORS.red} speed={2} distort={0.2} radius={1} />
      </mesh>
      
      {/* Structural Pillars */}
      <mesh position={[-0.8, 0.5, -0.8]} castShadow>
        <cylinderGeometry args={[0.05, 0.05, 1]} />
        <meshStandardMaterial color={ARES_COLORS.gold} metalness={1} roughness={0.2} />
      </mesh>
      <mesh position={[0.8, 0.5, -0.8]} castShadow>
        <cylinderGeometry args={[0.05, 0.05, 1]} />
        <meshStandardMaterial color={ARES_COLORS.gold} metalness={1} roughness={0.2} />
      </mesh>
      <mesh position={[-0.8, 0.5, 0.8]} castShadow>
        <cylinderGeometry args={[0.05, 0.05, 1]} />
        <meshStandardMaterial color={ARES_COLORS.gold} metalness={1} roughness={0.2} />
      </mesh>
      <mesh position={[0.8, 0.5, 0.8]} castShadow>
        <cylinderGeometry args={[0.05, 0.05, 1]} />
        <meshStandardMaterial color={ARES_COLORS.gold} metalness={1} roughness={0.2} />
      </mesh>

      {/* Top Plate */}
      <mesh position={[0, 1, 0]} castShadow>
        <boxGeometry args={[1.8, 0.05, 1.8]} />
        <meshStandardMaterial color="#333" metalness={0.8} roughness={0.2} transparent opacity={0.8} />
      </mesh>

      {/* Wheels */}
      {[-1.1, 1.1].map((x) => 
        [-0.8, 0.8].map((z) => (
          <mesh key={`${x}-${z}`} position={[x, -0.2, z]} rotation={[Math.PI / 2, 0, 0]} castShadow>
            <cylinderGeometry args={[0.3, 0.3, 0.2, 32]} />
            <meshStandardMaterial color={ARES_COLORS.dark} roughness={1} />
          </mesh>
        ))
      )}

      {/* Electronics Core (Glow) */}
      <Float speed={5} rotationIntensity={2} floatIntensity={2}>
        <mesh position={[0, 0.4, 0]}>
          <sphereGeometry args={[0.2, 32, 32]} />
          <MeshWobbleMaterial color={ARES_COLORS.cyan} emissive={ARES_COLORS.cyan} emissiveIntensity={2} factor={0.4} speed={2} />
        </mesh>
      </Float>
    </group>
  );
}

