        {/* Floating Technical Specs */}
        <Float speed={2} rotationIntensity={0.5} floatIntensity={0.5}>
           <Text
            position={[-2, 1.5, 0]}
            rotation={[0, Math.PI / 4, 0]}
            fontSize={0.2}
            color="white"
            font="/fonts/LeagueSpartan-Bold.woff"
            maxWidth={2}
            textAlign="left"
            anchorX="left"
            anchorY="middle"
          >
            ARES_CHASSIS_MK1
          </Text>
        </Float>
      </Canvas>
    </div>
  );
}

