import { useState, useEffect } from "react";
import { useQueryClient } from "@tanstack/react-query";
import { useNavigate, useParams } from "react-router-dom";
import { toast } from "sonner";
import { useRichEditor } from "./editor/useRichEditor";
import RichEditorToolbar from "./editor/RichEditorToolbar";
import AssetPickerModal from "./AssetPickerModal";
import { DEFAULT_COVER_IMAGE } from "../utils/constants";
import { useImageUpload } from "../hooks/useImageUpload";
import { api } from "../api/client";
import CoverAssetPicker from "./editor/CoverAssetPicker";
import EditorFooter from "./editor/EditorFooter";

export default function SeasonEditor() {
  const { editId } = useParams<{ editId?: string }>();
  const queryClient = useQueryClient();
  const navigate = useNavigate();

  const { uploadFile, isUploading: isUploadingCover } = useImageUpload();
  const { uploadFile: uploadAlbumCover, isUploading: isUploadingAlbumCover } = useImageUpload();

  // Local State
  const [isPending, setIsPending] = useState(false);
  const [startYear, setStartYear] = useState<number>(new Date().getFullYear());
  const [endYear, setEndYear] = useState<number>(new Date().getFullYear() + 1);
  const [challengeName, setChallengeName] = useState("");
  const [robotName, setRobotName] = useState("");
  const [robotImageUrl, setRobotImageUrl] = useState(DEFAULT_COVER_IMAGE);
  const [cadUrl, setCadUrl] = useState("");
  const [summary, setSummary] = useState("");
  const [albumUrl, setAlbumUrl] = useState("");
  const [albumCoverUrl, setAlbumCoverUrl] = useState("");
  const [errorMsg, setErrorMsg] = useState("");
  const [isImagePickerOpen, setIsImagePickerOpen] = useState(false);
  const [isAlbumCoverPickerOpen, setIsAlbumCoverPickerOpen] = useState(false);

  const editor = useRichEditor({ placeholder: "<p>Describe the robot's design, mechanisms, and season highlights...</p>" });

  const { data: detailData } = api.seasons.adminDetail.useQuery({
    queryKey: ["admin-season-detail", editId],
    params: { id: editId || "" },
  }, { enabled: !!editId });

  useEffect(() => {
    if (detailData?.status === 200 && detailData.body.season) {
      const s = detailData.body.season;
      setStartYear(s.start_year);
      setEndYear(s.end_year);
      setChallengeName(s.challenge_name);
      setRobotName(s.robot_name || "");
      setRobotImageUrl(s.robot_image || DEFAULT_COVER_IMAGE);
      setCadUrl(s.robot_cad_url || "");
      setSummary(s.summary || "");
      setAlbumUrl(s.album_url || "");
      setAlbumCoverUrl(s.album_cover || "");
      if (editor && s.robot_description) {
        try {
          editor.commands.setContent(JSON.parse(s.robot_description));
        } catch (e) {
          console.error("Failed to parse existing AST", e);
        }
      }
    }
  }, [detailData, editor]);

  const saveMutation = api.seasons.save.useMutation({
    onSuccess: (res) => {
      if (res.status === 200 && res.body.success) {
        toast.success(`Season ${startYear}-${endYear} saved successfully.`);
        queryClient.invalidateQueries({ queryKey: ["admin-seasons"] });
        queryClient.invalidateQueries({ queryKey: ["seasons"] });
        navigate("/dashboard/manage_seasons");
      } else {
        setErrorMsg("Save failed");
      }
    },
    onError: (err) => {
      setErrorMsg(err.message || "Failed to save season.");
    },
    onSettled: () => setIsPending(false)
  });

  const handleSave = async (isDraft: boolean = false) => {
    if (!startYear || !challengeName) {
      setErrorMsg("Start Year and Challenge Name are required.");
      return;
    }

    setIsPending(true);
    setErrorMsg("");

    const robot_description = editor ? JSON.stringify(editor.getJSON()) : null;

    const payload = {
      start_year: Number(startYear),
      end_year: Number(endYear),
      challenge_name: challengeName,
      robot_name: robotName,
      robot_image: robotImageUrl === DEFAULT_COVER_IMAGE ? null : robotImageUrl,
      robot_description,
      robot_cad_url: cadUrl,
      summary,
      album_url: albumUrl,
      album_cover: albumCoverUrl,
      status: (isDraft ? "draft" : "published") as "draft" | "published"
    };

    saveMutation.mutate({ body: payload });
  };

  if (!editor) return <div className="text-marble animate-pulse font-mono tracking-widest text-sm">Booting Legacy Systems...</div>;

  return (
    <div className="flex flex-col gap-6 w-full relative">
      <div>
        <h2 className="text-3xl font-black text-white tracking-tighter italic mb-2 uppercase">
          {editId ? "Update Legacy" : "Forge New Legacy"}
        </h2>
        <p className="text-marble/40 text-sm font-bold uppercase tracking-widest">
          Documenting the evolution of ARES 23247.
        </p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mt-2">
        <div className="space-y-4">
          <div className="flex gap-4">
            <div className="flex-1">
              <label htmlFor="start-year" className="block text-xs font-black text-ares-gold uppercase tracking-[0.2em] mb-2">Start Year</label>
              <input
                id="start-year"
                type="number"
                value={startYear}
                onChange={(e) => setStartYear(parseInt(e.target.value))}
                disabled={!!editId}
                className="w-full bg-black border border-white/10 ares-cut-sm px-4 py-3 text-marble placeholder-marble/30 focus:ring-1 focus:ring-ares-gold transition-all"
                placeholder='2025'
              />
            </div>
            <div className="flex-1">
              <label htmlFor="end-year" className="block text-xs font-black text-ares-gold uppercase tracking-[0.2em] mb-2">End Year</label>
              <input
                id="end-year"
                type="number"
                value={endYear}
                onChange={(e) => setEndYear(parseInt(e.target.value))}
                className="w-full bg-black border border-white/10 ares-cut-sm px-4 py-3 text-marble placeholder-marble/30 focus:ring-1 focus:ring-ares-gold transition-all"
                placeholder='2026'
              />
            </div>
          </div>
          <div>
            <label htmlFor="challenge-name" className="block text-xs font-black text-ares-gold uppercase tracking-[0.2em] mb-2">Challenge Name</label>
            <input
              id="challenge-name"
              type="text"
              value={challengeName}
              onChange={(e) => setChallengeName(e.target.value)}
              className="w-full bg-black border border-white/10 ares-cut-sm px-4 py-3 text-marble placeholder-marble/30 focus:ring-1 focus:ring-ares-gold transition-all"
              placeholder='e.g. CENTERSTAGE'
            />
          </div>
        </div>

        <div>
          <span className="block text-xs font-black text-ares-gold uppercase tracking-[0.2em] mb-2">Robot / Season Cover</span>
          <CoverAssetPicker 
            coverImage={robotImageUrl}
            isUploading={isUploadingCover}
            onLibraryClick={() => setIsImagePickerOpen(true)}
            onUrlChange={setRobotImageUrl}
            onFileChange={async (file) => {
              const { url } = await uploadFile(file);
              setRobotImageUrl(url);
            }}
          />
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="space-y-4">
          <div>
            <label htmlFor="album-url" className="block text-xs font-black text-marble/40 uppercase tracking-[0.2em] mb-2">Google Photos Album Link</label>
            <input
              id="album-url"
              type="text"
              value={albumUrl}
              onChange={(e) => setAlbumUrl(e.target.value)}
              className="w-full bg-black border border-white/10 ares-cut-sm px-4 py-3 text-marble placeholder-marble/30"
              placeholder='https://photos.app.goo.gl/...'
            />
          </div>
          <div>
            <label htmlFor="robot-name" className="block text-xs font-black text-marble/40 uppercase tracking-[0.2em] mb-2">Robot Name</label>
            <input
              id="robot-name"
              type="text"
              value={robotName}
              onChange={(e) => setRobotName(e.target.value)}
              className="w-full bg-black border border-white/10 ares-cut-sm px-4 py-3 text-marble placeholder-marble/30"
              placeholder='e.g. ARES-1'
            />
          </div>
          <div>
            <label htmlFor="cad-link" className="block text-xs font-black text-marble/40 uppercase tracking-[0.2em] mb-2">CAD Link</label>
            <input
              id="cad-link"
              type="text"
              value={cadUrl}
              onChange={(e) => setCadUrl(e.target.value)}
              className="w-full bg-black border border-white/10 ares-cut-sm px-4 py-3 text-marble placeholder-marble/30"
              placeholder='https://onshape.com/...'
            />
          </div>
        </div>
        <div>
          <span className="block text-xs font-black text-marble/40 uppercase tracking-[0.2em] mb-2">Album Cover / Hero Card</span>
          <CoverAssetPicker 
            coverImage={albumCoverUrl}
            isUploading={isUploadingAlbumCover}
            onLibraryClick={() => setIsAlbumCoverPickerOpen(true)}
            onUrlChange={setAlbumCoverUrl}
            onFileChange={async (file) => {
              const { url } = await uploadAlbumCover(file);
              setAlbumCoverUrl(url);
            }}
          />
        </div>
      </div>

      <div>
        <label htmlFor="summary" className="block text-xs font-black text-marble/40 uppercase tracking-[0.2em] mb-2">Brief Summary</label>
        <textarea
          id="summary"
          value={summary}
          onChange={(e) => setSummary(e.target.value)}
          className="w-full bg-black border border-white/10 ares-cut-sm px-4 py-3 text-marble h-20"
          placeholder="One sentence summary of the season's legacy..."
        />
      </div>

      <div className="space-y-2">
        <span className="block text-xs font-black text-ares-gold uppercase tracking-[0.2em]">Robot Design & Season Highlights</span>
        <RichEditorToolbar editor={editor} documentTitle={challengeName} />
      </div>

      <AssetPickerModal 
        isOpen={isImagePickerOpen}
        onClose={() => setIsImagePickerOpen(false)}
        onSelect={(url) => {
          setRobotImageUrl(url);
          setIsImagePickerOpen(false);
        }}
      />

      <AssetPickerModal 
        isOpen={isAlbumCoverPickerOpen}
        onClose={() => setIsAlbumCoverPickerOpen(false)}
        onSelect={(url) => {
          setAlbumCoverUrl(url);
          setIsAlbumCoverPickerOpen(false);
        }}
      />

      <EditorFooter 
        errorMsg={errorMsg}
        isPending={isPending}
        isEditing={!!editId}
        onDelete={() => {}} 
        onSaveDraft={() => handleSave(true)}
        onPublish={() => handleSave(false)}
        updateText="UPDATE LEGACY"
        publishText="ESTABLISH LEGACY"
        roundedClass="ares-cut"
      />
    </div>
  );
}

import { useState } from "react";
import DashboardPageHeader from "./dashboard/DashboardPageHeader";
import DashboardEmptyState from "./dashboard/DashboardEmptyState";
import DashboardLoadingGrid from "./dashboard/DashboardLoadingGrid";
import { DashboardInput, DashboardSubmitButton } from "./dashboard/DashboardFormInputs";
import { useQueryClient } from "@tanstack/react-query";
import { Plus, Trash2, Globe, ShieldCheck, Award, Zap, Gem, CheckCircle2, XCircle, Edit2, Package } from "lucide-react";
import { toast } from "sonner";
import { motion, AnimatePresence } from "framer-motion";
import confetti from "canvas-confetti";

import { useModal } from "../contexts/ModalContext";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { sponsorSchema, SponsorPayload } from "../schemas/sponsorSchema";

import { api } from "../api/client";

const TIERS = [
  { name: "Titanium", icon: <Gem className="text-ares-cyan" />, color: "text-ares-cyan", border: "border-ares-cyan/30" },
  { name: "Gold", icon: <Award className="text-ares-gold" />, color: "text-ares-gold", border: "border-ares-gold/30" },
  { name: "Silver", icon: <ShieldCheck className="text-marble/90" />, color: "text-marble/90", border: "border-marble/20" },
  { name: "Bronze", icon: <Zap className="text-ares-bronze" />, color: "text-ares-bronze", border: "border-ares-bronze/30" },
  { name: "In-Kind", icon: <Package className="text-marble/40" />, color: "text-marble/40", border: "border-marble/10" },
];

export default function SponsorEditor() {
  const queryClient = useQueryClient();
  const modal = useModal();
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);

  const { register, handleSubmit, reset, formState: { errors } } = useForm<SponsorPayload>({
    resolver: zodResolver(sponsorSchema),
    defaultValues: {
      tier: "Gold",
      is_active: 1
    }
  });

  const { data, isLoading, isError } = api.sponsors.adminList.useQuery({
    queryKey: ["admin-sponsors"],
  });
  const sponsors = data?.status === 200 ? data.body.sponsors : [];

  const saveMutation = api.sponsors.saveSponsor.useMutation({
    onSuccess: (res) => {
      if (res.status === 200 && res.body.success) {
        queryClient.invalidateQueries({ queryKey: ["admin-sponsors"] });
        setIsFormOpen(false);
        setEditingId(null);
        reset();

        confetti({
          particleCount: 150,
          spread: 70,
          origin: { y: 0.6 },
          colors: ['#C00000', '#FFB81C', '#CD7F32']
        });

        toast.success("Partner synchronization successful.");
      } else {
        toast.error("Sync failed");
      }
    },
    onError: (err: Error) => {
      toast.error(`[Failure Exposure] Sponsor sync failed: \n${err.message}`);
    }
  });

  const deleteMutation = api.sponsors.deleteSponsor.useMutation({
    onSuccess: () => queryClient.invalidateQueries({ queryKey: ["admin-sponsors"] })
  });

  const onFormSubmit = (data: SponsorPayload) => {
    const finalId = editingId || data.name.toLowerCase().replace(/[^a-z0-9]+/g, '-');
    saveMutation.mutate({ body: { ...data, id: finalId } });
  };

  const handleEdit = (s: { id: string; name: string; tier: string; logo_url?: string | null; website_url?: string | null; is_active?: number }) => {
    setEditingId(s.id);
    reset({
      id: s.id,
      name: s.name,
      tier: s.tier as any,
      logo_url: s.logo_url || "",
      website_url: s.website_url || "",
      is_active: s.is_active ?? 1
    });
    setIsFormOpen(true);
  };

  const handleDelete = async (s: { id: string; name: string }) => {
    const confirmed = await modal.confirm({
      title: "Delete Partner",
      description: `Are you sure you want to permanently remove ${s.name} from the ARES registry?`,
      confirmText: "Delete",
      destructive: true
    });
    if (confirmed) {
      deleteMutation.mutate({ params: { id: s.id }, body: {} });
    }
  };

  return (
    <div className="space-y-8">
      <DashboardPageHeader
        title="Sponsor Management"
        subtitle="Recognize the partners who make ARES possible."
        icon={<Gem className="text-ares-cyan" />}
        action={
          <button
            onClick={() => {
              if (isFormOpen) {
                setIsFormOpen(false);
                setEditingId(null);
                reset();
              } else {
                setIsFormOpen(true);
              }
            }}
            className="flex items-center gap-2 px-4 py-2 bg-ares-red text-white font-bold ares-cut-sm hover:bg-ares-danger transition-colors shadow-lg shadow-ares-red/20"
          >
            {isFormOpen ? <XCircle size={18} /> : <Plus size={18} />}
            {isFormOpen ? "Cancel" : "Add Partner"}
          </button>
        }
      />

      {isError && (
        <div className="bg-ares-red/10 border border-ares-red/30 p-4 ares-cut-sm text-ares-red text-xs font-bold mb-6 flex items-center gap-2">
          <span className="w-2 h-2 rounded-full bg-ares-red animate-pulse" />
          TELEMETRY FAULT: Failed to synchronize partner registry.
        </div>
      )}

      <AnimatePresence>
        {isFormOpen && (
          <motion.form
            initial={{ opacity: 0, height: 0 }}
            animate={{ opacity: 1, height: "auto" }}
            exit={{ opacity: 0, height: 0 }}
            onSubmit={handleSubmit(onFormSubmit as any)}
            className="bg-black/40 border border-white/10 ares-cut-lg p-6 space-y-4 overflow-hidden"
          >
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <DashboardInput
                id="sponsor-name"
                label="Partner Name"
                {...register("name")}
                error={errors.name?.message as string}
                placeholder="e.g. Google DeepMind"
                focusColor="ares-red"
              />
              <div className="space-y-1">
                <label htmlFor="sponsor-tier" className="text-xs font-bold uppercase tracking-widest text-marble/40">Tier</label>
                <select
                  id="sponsor-tier"
                  {...register("tier")}
                  className="w-full bg-white/5 border border-white/10 ares-cut-sm px-4 py-3 text-white focus:border-ares-red outline-none transition-colors"
                >
                  {TIERS.map(t => <option key={t.name} value={t.name} className="bg-obsidian">{t.name}</option>)}
                </select>
                {errors.tier && <p className="text-[10px] font-black uppercase tracking-tighter text-ares-red">{errors.tier.message as string}</p>}
              </div>
              <DashboardInput
                id="sponsor-logo"
                label="Logo URL"
                {...register("logo_url")}
                error={errors.logo_url?.message as string}
                placeholder="https://..."
                focusColor="ares-red"
              />
              <DashboardInput
                id="sponsor-link"
                label="Website URL"
                {...register("website_url")}
                error={errors.website_url?.message as string}
                placeholder="https://..."
                focusColor="ares-red"
              />
            </div>
            <DashboardSubmitButton 
              isPending={saveMutation.isPending} 
              defaultText={editingId ? "Update Partner in D1" : "Commit Partner to D1"} 
              theme="red" 
            />
          </motion.form>
        )}
      </AnimatePresence>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {isLoading ? (
           <DashboardLoadingGrid count={3} heightClass="h-32" gridClass="grid-cols-1 md:grid-cols-2 lg:grid-cols-3" />
        ) : (sponsors as { id: string; name: string; tier: string; logo_url?: string | null; website_url?: string | null }[]).map((s) => (
          <div key={s.id} className="bg-black/40 border border-white/5 ares-cut-lg p-6 relative group transition-all hover:border-white/20">
            <div className="flex justify-between items-start mb-4">
              <div className="flex items-center gap-2">
                {TIERS.find(t => t.name === s.tier)?.icon}
                <span className={`text-xs font-bold uppercase tracking-widest ${TIERS.find(t => t.name === s.tier)?.color}`}>
                  {s.tier}
                </span>
              </div>
              <div className="flex items-center gap-2 transition-opacity">
                <button
                  onClick={() => handleEdit(s)}
                  aria-label={`Edit ${s.name}`}
                  className="text-white/60 hover:text-ares-cyan transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ares-cyan rounded"
                >
                  <Edit2 size={16} />
                </button>
                <button
                  onClick={() => handleDelete(s)}
                  aria-label={`Delete ${s.name}`}
                  className="text-white/60 hover:text-ares-red transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ares-red rounded"
                >
                  <Trash2 size={16} />
                </button>
              </div>
            </div>

            <h4 className="text-lg font-bold text-white mb-1">{s.name}</h4>

            <div className="flex items-center gap-3 mt-4">
              {s.website_url && (
                <a href={s.website_url} target="_blank" rel="noreferrer" title={`Visit ${s.name} website`} className="text-marble/40 hover:text-ares-gold transition-colors">
                  <Globe size={16} />
                </a>
              )}
              {s.logo_url && (
                <div className="h-6 w-px bg-white/5" />
              )}
              {s.logo_url && (
                <div className="text-xs font-bold uppercase tracking-widest text-ares-gold flex items-center gap-1">
                  <CheckCircle2 size={12} /> Logo Linked
                </div>
              )}
            </div>
          </div>
        ))}
        {sponsors.length === 0 && !isLoading && !isFormOpen && (
          <DashboardEmptyState
            className="col-span-full py-12 text-center border-2 border-dashed border-white/10 ares-cut-lg"
            icon={<Package size={48} />}
            message="No sponsors logged. Start by adding your titanium partners."
          />
        )}
      </div>
    </div>
  );
}

