              />
              <Route
                path="sponsor_tokens"
                element={isAdmin ? <SponsorTokensManager /> : <div className="text-center py-20">Access Denied</div>}
              />
              <Route
                path="outreach"
                element={<OutreachTracker />}
              />
              <Route
                path="legacy"
