interface R2MediaResponse {
  media: {
    key: string;
    httpMetadata: {
      contentType: string;
    };
  }[];
}

export default function ScreenshotGallery() {
  const { data: mediaRes, isLoading } = api.media.getMedia.useQuery({
    queryKey: ["media"],
  });

  const data = mediaRes?.status === 200 ? mediaRes.body : null;

  const [index, setIndex] = useState(0);

  // Filter only images and reverse to show newest first
  const images = data?.media
    ?.filter(m => m.httpMetadata?.contentType?.startsWith("image/"))
    ?.reverse()
    .map(m => `/api/media/${m.key}`) || ["/hero_bg.png", "/gallery_4.png", "/news_1.png"]; // fallbacks

  const next = () => setIndex((i) => (i + 1) % images.length);
  const prev = () => setIndex((i) => (i - 1 + images.length) % images.length);

  return (
    <div className="my-6 relative border border-white/10 ares-cut-sm overflow-hidden bg-black aspect-video group shadow-xl">
      {isLoading ? (
        <div className="absolute inset-0 flex items-center justify-center">
          <div className="w-8 h-8 border-4 border-white/10 border-t-ares-gold rounded-full animate-spin"></div>
        </div>
      ) : (
        <AnimatePresence mode="wait">
          <motion.img
            key={index}
            src={images[index]}
            initial={{ opacity: 0, scale: 1.05 }}
            animate={{ opacity: 1, scale: 1 }}
            exit={{ opacity: 0 }}
            transition={{ duration: 0.3 }}
            className="w-full h-full object-cover opacity-80"
            alt="Telemetry Dashboard"
          />
        </AnimatePresence>
      )}

      {!isLoading && images.length > 1 && (
        <div className="absolute inset-0 flex items-center justify-between p-4 opacity-0 group-hover:opacity-100 transition-opacity">
          <button onClick={prev} className="p-2 bg-black/50 hover:bg-ares-red/80 text-white rounded-full backdrop-blur transition-colors"><ChevronLeft size={24} /></button>
          <button onClick={next} className="p-2 bg-black/50 hover:bg-ares-cyan/80 text-white rounded-full backdrop-blur transition-colors"><ChevronRight size={24} /></button>
        </div>
      )}

      {!isLoading && images.length > 1 && (
        <div className="absolute bottom-4 left-0 right-0 flex justify-center gap-2">
          {images.map((_, i) => (
            <div key={i} className={`w-2 h-2 rounded-full transition-all ${i === index ? "bg-ares-gold scale-125" : "bg-white/60"}`} />
          ))}
        </div>
      )}
    </div>
  );
}

/**
 * RichEditorToolbar – a single, shared floating toolbar for every Tiptap editor
 * in the ARES dashboard (Docs, Blog, Events).
 *
 * Sticks just below the navbar (top: 64px) as the user scrolls, giving a
 * word-processor feel. Includes Export .HTML / .JSON and Import .DOCX / .JSON.
 */
import { useState, useRef, useCallback } from "react";
import type { Editor } from "@tiptap/react";
import { EditorContent } from "@tiptap/react";
import { toast } from "sonner";
import mammoth from "mammoth";
import { compressImage } from "../../utils/imageProcessor";
import AssetPickerModal from "../AssetPickerModal";
import SimPickerModal from "../SimPickerModal";
import { api, uploadFile } from "../../api/client";
import { useModal } from "../../contexts/ModalContext";

/* ---------- Props ---------- */
export interface RichEditorToolbarProps {
  editor: Editor;
  /** Used as the filename stem for exports. */
  documentTitle?: string;
}

/* ---------- Helper: file upload ---------- */
const internalUpload = async (file: File): Promise<{url: string, altText?: string}> => {
  const { blob: compressedBlob, ext } = await compressImage(file);
  const formData = new FormData();
  formData.append("file", compressedBlob, file.name.replace(/\.[^/.]+$/, ext));
  const data = await uploadFile<{ url?: string, error?: string, altText?: string }>("/api/admin/upload", formData);
  if (!data.url) throw new Error(data.error || "Upload failed");
  return { url: data.url, altText: data.altText };
};

/* ---------- Helper: export HTML document ---------- */
function exportAsHtml(editor: Editor, title: string) {
  const html = editor.getHTML();
  const doc = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>${title || "ARES Document"}</title>
  <style>
    body { font-family: system-ui, -apple-system, sans-serif; max-width: 800px; margin: 2rem auto; padding: 0 1rem; color: #e6edf3; background: #0d1117; line-height: 1.7; }
    h1, h2, h3 { color: #fff; }
    a { color: #58a6ff; }
    code { background: #161b22; padding: 0.15em 0.4em; border-radius: 6px; font-size: 0.9em; }
    pre { background: #161b22; padding: 1rem; border-radius: 8px; overflow-x: auto; }
    blockquote { border-left: 4px solid rgba(192,40,40,0.6); padding: 0.5rem 1rem; color: rgba(255,255,255,0.7); font-style: italic; }
    table { border-collapse: collapse; width: 100%; }
    th, td { border: 1px solid #30363d; padding: 0.75rem; text-align: left; }
    th { background: #161b22; color: #FFB81C; text-transform: uppercase; font-size: 0.85em; letter-spacing: 0.05em; }
    img { max-width: 100%; height: auto; border-radius: 8px; }
    details { border: 1px solid #30363d; border-radius: 8px; padding: 0.5rem; margin: 1rem 0; }
    summary { cursor: pointer; font-weight: 600; }
    .callout-block { border-left: 4px solid #58a6ff; padding: 1rem; margin: 1rem 0; border-radius: 0 8px 8px 0; background: rgba(88,166,255,0.05); }
    .callout-block[data-type="warning"] { border-color: #c02828; background: rgba(192,40,40,0.05); }
    .callout-block[data-type="tip"] { border-color: #FFB81C; background: rgba(255,184,28,0.05); }
  </style>
</head>
<body>
  <h1>${title || "ARES Document"}</h1>
  ${html}
  <footer style="margin-top:4rem;padding-top:1rem;border-top:1px solid #30363d;font-size:0.8em;color:#8b949e;">
    Exported from ARES 23247 Web Portal — ${new Date().toLocaleDateString()}
  </footer>
</body>
</html>`;

  const blob = new Blob([doc], { type: "text/html;charset=utf-8" });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = `${(title || "ares-document").replace(/[^a-zA-Z0-9-_ ]/g, "").replace(/\s+/g, "-").toLowerCase()}.html`;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
}

/* ---------- Helper: export JSON AST (lossless, for site-to-site sharing) ---------- */
function exportAsJson(editor: Editor, title: string) {
  const ast = editor.getJSON();
  const payload = { title: title || "ARES Document", exportedAt: new Date().toISOString(), ast };
  const blob = new Blob([JSON.stringify(payload, null, 2)], { type: "application/json;charset=utf-8" });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = `${(title || "ares-document").replace(/[^a-zA-Z0-9-_ ]/g, "").replace(/\s+/g, "-").toLowerCase()}.json`;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
}

/* ---- Button helper ---- */
const Btn = ({ active, onClick, children, className = "", disabled = false, ariaLabel }: {
  active?: boolean; onClick: () => void; children: React.ReactNode; className?: string; disabled?: boolean; ariaLabel?: string;
}) => (
  <button
    type="button"
    onClick={onClick}
    disabled={disabled}
    aria-label={ariaLabel}
    className={`px-3 py-2 ares-cut-sm text-sm font-bold transition-all ${
      active
        ? "bg-ares-gray-dark text-white"
        : "text-marble/40 hover:bg-ares-gray-dark hover:text-white"
    } disabled:opacity-30 ${className}`}
  >
    {children}
  </button>
);

const Sep = () => <div className="w-px h-6 bg-white/10 mx-1" />;

/* ---------- Component ---------- */
export default function RichEditorToolbar({ editor, documentTitle }: RichEditorToolbarProps) {
  const modal = useModal();
  const [isImporting, setIsImporting] = useState(false);
  const [isPickerOpen, setIsPickerOpen] = useState(false);
  const [isSimPickerOpen, setIsSimPickerOpen] = useState(false);
  const importRef = useRef<HTMLInputElement>(null);
  const jsonImportRef = useRef<HTMLInputElement>(null);

  const handleDocImport = useCallback(async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !editor) return;
    setIsImporting(true);
    try {
      const arrayBuffer = await file.arrayBuffer();
      const result = await mammoth.convertToHtml({ arrayBuffer }, {
        // @ts-expect-error - mammoth types do not expose images.inline directly
        convertImage: mammoth.images.inline(async (element: { read: () => Promise<ArrayBuffer>, contentType: string }) => {
          const buffer = await element.read();
          const blob = new Blob([buffer], { type: element.contentType });
          const imageFile = new File([blob], `imported_image_${Date.now()}.${element.contentType.split('/')[1]}`, { type: element.contentType });
          try {
            const { url } = await uploadFile(imageFile);
            return { src: url };
          } catch (err) {
            console.error("Failed to upload imported image", err);
            return { src: "" };
          }
        })
      });
      editor.commands.setContent(result.value);
    } catch (err) {
      console.error(err);
    } finally {
      setIsImporting(false);
      e.target.value = "";
    }
  }, [editor]);

  const handleJsonImport = useCallback(async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !editor) return;
    try {
      const text = await file.text();
      const parsed = JSON.parse(text);
      // Support both raw AST and our export wrapper format
      const ast = parsed.ast || parsed;
      editor.commands.setContent(ast);
    } catch (err) {
      console.error("Failed to import JSON:", err);
      toast.error("Invalid JSON file. Expected an ARES export (.json) or raw Tiptap AST.");
    } finally {
      e.target.value = "";
    }
  }, [editor]);

  // Components Btn and Sep moved outside.

  return (
    <>
      {/* ===== FLOATING TOOLBAR ===== */}
      <div className="flex flex-wrap items-center gap-1 bg-obsidian/95 backdrop-blur-md border border-white/10 ares-cut-sm p-2 z-50 w-full mb-0 sticky top-24 overflow-x-auto shadow-lg">
        {/* Undo / Redo */}
        <Btn onClick={() => editor.chain().focus().undo().run()} disabled={!editor.can().undo()} ariaLabel="Undo">↶</Btn>
        <Btn onClick={() => editor.chain().focus().redo().run()} disabled={!editor.can().redo()} ariaLabel="Redo">↷</Btn>
        <Sep />

        {/* Headings */}
        <Btn active={editor.isActive("heading", { level: 1 })} onClick={() => editor.chain().focus().toggleHeading({ level: 1 }).run()} ariaLabel="Heading 1">H1</Btn>
        <Btn active={editor.isActive("heading", { level: 2 })} onClick={() => editor.chain().focus().toggleHeading({ level: 2 }).run()} ariaLabel="Heading 2">H2</Btn>

        {/* Inline formatting */}
        <Btn active={editor.isActive("bold")} onClick={() => editor.chain().focus().toggleBold().run()} ariaLabel="Bold">B</Btn>
        <Btn active={editor.isActive("italic")} onClick={() => editor.chain().focus().toggleItalic().run()} className="italic" ariaLabel="Italic">I</Btn>
        <Btn active={editor.isActive("strike")} onClick={() => editor.chain().focus().toggleStrike().run()} className="line-through" ariaLabel="Strikethrough">S</Btn>
        <Sep />

        {/* FIRST® */}
        <button type="button" aria-label="Insert FIRST symbol" onClick={() => editor.chain().focus().insertContent('<em>FIRST</em>&reg; ').run()} className="px-3 py-2 ares-cut-sm text-sm font-black italic transition-all text-ares-red hover:bg-ares-red hover:text-white border border-ares-red/30 shadow-sm">FIRST</button>
        <Sep />

