import { useState, useEffect } from "react";
import { api } from "../api/client";

export function useAdminSettings() {
  const [availableSocials, setAvailableSocials] = useState<string[]>([]);
  const [isPending, setIsPending] = useState(true);

  const { data, isLoading } = api.settings.getSettings.useQuery({
    queryKey: ["admin_settings_hook"],
  });

  useEffect(() => {
    if (data?.body?.settings) {
      const config = data.body.settings;
      const available = [];
      if (config.DISCORD_WEBHOOK_URL) available.push("discord");
      if (config.BLUESKY_HANDLE && config.BLUESKY_APP_PASSWORD) available.push("bluesky");
      if (config.SLACK_WEBHOOK_URL) available.push("slack");
      if (config.TEAMS_WEBHOOK_URL) available.push("teams");
      if (config.GCHAT_WEBHOOK_URL) available.push("gchat");
      if (config.FACEBOOK_ACCESS_TOKEN) available.push("facebook");
      if (config.TWITTER_ACCESS_TOKEN) available.push("twitter");
      if (config.INSTAGRAM_ACCESS_TOKEN) available.push("instagram");
      if (config.ZULIP_BOT_EMAIL && config.ZULIP_API_KEY) available.push("zulip");
      setAvailableSocials(available);
      setIsPending(false);
    } else if (!isLoading) {
      setIsPending(false);
    }
  }, [data, isLoading]);

  return { availableSocials, isPending };
}

import { useQuery } from "@tanstack/react-query";
import { DashboardSession, DashboardPermissions } from "./useDashboardSession";
import { api } from "../api/client";

export function useDashboardNotifications(
  session: DashboardSession | null,
  permissions: DashboardPermissions
) {
  const { data: inquiriesRes } = api.inquiries.list.useQuery({
    queryKey: ["admin-inquiries-notifs"],
    enabled: !!(session && permissions.canSeeInquiries),
    refetchInterval: 30000,
  });

  const { data: postsRes } = api.posts.getAdminPosts.useQuery({
    queryKey: ["admin_posts_notifs"],
    enabled: !!(session && permissions.isAuthorized),
    refetchInterval: 30000,
  });

  const { data: eventsRes } = api.events.getAdminEvents.useQuery({
    queryKey: ["admin_events_notifs"],
    enabled: !!(session && permissions.isAuthorized),
    refetchInterval: 30000,
  });

  // Docs contract currently missing getAdminDocs list, will use generic if needed or just skip
  // For now I'll use the existing one or assuming it exists in contract
  const { data: docsRes } = (api as any).docs?.getAdminDocs?.useQuery({
    queryKey: ["admin_docs_notifs"],
    enabled: !!(session && permissions.isAuthorized),
    refetchInterval: 30000,
  }) || { data: null };

  const inquiriesData = (inquiriesRes?.body as any)?.inquiries || [];
  const postsData = (postsRes?.body as any)?.posts || [];
  const eventsData = (eventsRes?.body as any)?.events || [];
  const docsData = (docsRes?.body as any)?.docs || [];

  const pendingInquiries = inquiriesData?.filter((i: any) => i.status === "pending") || [];
  const pendingPosts = postsData?.filter((p: any) => p.status === "pending" && !p.is_deleted) || [];
  const pendingEvents = eventsData?.filter((e: any) => e.status === "pending" && !e.is_deleted) || [];
  const pendingDocs = docsData?.filter((d: any) => d.status === "pending" && !d.is_deleted) || [];

  return {
    pendingInquiriesCount: pendingInquiries.length,
    pendingPostsCount: pendingPosts.length,
    pendingEventsCount: pendingEvents.length,
    pendingDocsCount: pendingDocs.length,
    pendingInquiries,
    pendingPosts,
    pendingEvents,
    pendingDocs,
  };
}

import { useState, useEffect, useMemo } from "react";
import { useNavigate } from "react-router-dom";
import { useQuery } from "@tanstack/react-query";
import { api } from "../api/client";
import { trackPageView } from "../utils/analytics";

export interface DocRecord {
  slug: string;
  title: string;
  category: string;
  sort_order: number;
  description: string;
  content?: string;
  updated_at?: string;
  snippet?: string;
  cf_email?: string;
  original_author_nickname?: string;
  original_author_avatar?: string;
}

export interface Contributor {
  author_email: string;
  nickname?: string;
  avatar?: string;
}

export interface SearchResult {
  slug: string;
  title: string;
  category: string;
  snippet: string;
}

const SIDEBAR_ORDER = [
  "Getting Started",
  "Migration Guides",
  "Support",
  "Community",
  "Reference",
  "The ARESLib Standard",
  "Foundation Track",
  "Precision Track",
  "Reliability Track",
  "HMI & Control",
];

export function useDocs(slug: string | undefined) {
  const navigate = useNavigate();
  const [searchQuery, setSearchQuery] = useState("");
  const [searchOpen, setSearchOpen] = useState(false);
  const [feedbackToken, setFeedbackToken] = useState("");

  const { data: allDocsRes } = api.docs.getDocs.useQuery({
    queryKey: ["docs-list"],
  });
  const allDocs = allDocsRes?.status === 200 ? allDocsRes.body.docs : [];

  const ObjectQuery = api.docs.getDoc.useQuery({
    queryKey: ["doc", slug],
    params: { slug: slug || "" },
    enabled: !!slug,
  });

  const currentDoc = ObjectQuery.data?.status === 200 ? ObjectQuery.data.body.doc : undefined;
  const contributors = ObjectQuery.data?.status === 200 ? ObjectQuery.data.body.contributors : [];
  const docLoading = ObjectQuery.isLoading;

  const { data: searchRes } = api.docs.searchDocs.useQuery({
    queryKey: ["docs-search", searchQuery],
    query: { q: searchQuery },
    enabled: searchQuery.length >= 2,
  });
  const searchResults = searchRes?.status === 200 ? searchRes.body.results : [];

  const groupedDocs = useMemo(() => {
    const groups: Record<string, DocRecord[]> = {};
    for (const doc of allDocs) {
      if (!groups[doc.category]) groups[doc.category] = [];
      groups[doc.category].push(doc);
    }
    const ordered: [string, DocRecord[]][] = [];
    for (const cat of SIDEBAR_ORDER) {
      if (groups[cat]) ordered.push([cat, groups[cat]]);
    }
    for (const [cat, docs] of Object.entries(groups)) {
      if (!SIDEBAR_ORDER.includes(cat)) ordered.push([cat, docs]);
    }
    return ordered;
  }, [allDocs]);

  useEffect(() => {
    const handler = (e: KeyboardEvent) => {
      if ((e.ctrlKey || e.metaKey) && e.key === "k") {
        e.preventDefault();
        setSearchOpen((o) => !o);
      }
      if (e.key === "Escape") {
        setSearchOpen(false);
        setSearchQuery("");
      }
    };
    window.addEventListener("keydown", handler);
    return () => window.removeEventListener("keydown", handler);
  }, []);

  useEffect(() => {
    if (currentDoc) {
      trackPageView(`/docs/${currentDoc.slug}`, 'doc');
    }
  }, [currentDoc]);

  useEffect(() => {
    if (!slug && allDocs.length > 0) {
      navigate(`/docs/${allDocs[0].slug}`, { replace: true });
    }
  }, [slug, allDocs, navigate]);

  return {
    allDocs,
    currentDoc,
    contributors,
    docLoading,
    searchResults,
    groupedDocs,
    searchQuery,
    setSearchQuery,
    searchOpen,
    setSearchOpen,
    feedbackToken,
    setFeedbackToken,
  };
}

import { useState } from "react";
import { compressImage } from "../utils/imageProcessor";
import { api } from "../api/client";

export function useImageUpload() {
  const [isUploading, setIsUploading] = useState(false);
  const [errorMsg, setErrorMsg] = useState("");

  const uploadFile = async (file: File): Promise<{url: string, altText?: string}> => {
    if (isUploading) throw new Error("An upload is already in progress.");
    setIsUploading(true);
    setErrorMsg("");
    try {
      const { blob: compressedBlob, ext } = await compressImage(file);
      const formData = new FormData();
      formData.append("file", compressedBlob, file.name.replace(/\.[^/.]+$/, ext));
      
      const res = await api.media.upload.mutation({
        body: formData
      });
      
      if (res.status === 200) {
        return { url: res.body.url, altText: res.body.altText };
      } else {
        throw new Error((res.body as any).error || "Upload failed");
      }
    } catch (err) {
      const msg = String(err);
      setErrorMsg(msg);
      throw new Error(msg, { cause: err });
    } finally {
      setIsUploading(false);
    }
  };

  return { uploadFile, isUploading, errorMsg, setErrorMsg };
}

