              </div>
            </Link>
          ))}
          {!isLoading && posts.length === 0 && (
            <div className="text-white p-6 glass-card hero-card col-span-full border-dashed">
              No posts published yet. Head to the <Link to="/dashboard" className="text-ares-gold underline focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ares-cyan rounded px-1">Dashboard</Link> to create one.
            </div>
          )}
          {isLoading && (
            <div className="flex justify-center items-center py-20 col-span-full">
              <div className="w-12 h-12 border-4 border-ares-red/30 border-t-ares-red rounded-full animate-spin"></div>
            </div>
          )}
        </motion.div>
      </div>
    </motion.div>
  );
}

import { useEffect } from "react";
import { useParams, Link } from "react-router-dom";
import { useQuery } from "@tanstack/react-query";
import { motion } from "framer-motion";
import { format } from "date-fns";
import { trackPageView } from "../utils/analytics";
import { useSession } from "../utils/auth-client";
import { Edit2 } from "lucide-react";

import TiptapRenderer, { type ASTNode } from "../components/TiptapRenderer";
import CommentSection from "../components/CommentSection";
import { api } from "../api/client";

interface PostRow {
  slug: string;
  title: string;
  date: string;
  ast: string;
  thumbnail?: string;
  author_nickname?: string;
  author_avatar?: string;
  cf_email?: string;
}

export default function BlogPost() {
  const { slug } = useParams<{ slug: string }>();
  const { data: session } = useSession();
  
  const userRole = (session?.user as Record<string, unknown>)?.role || "user";
  const isEditor = userRole === "admin" || userRole === "author";

  const { data: postRes, isLoading, isError } = api.posts.getPost.useQuery({
    queryKey: ["post", slug],
    params: { slug: slug || "" },
    enabled: !!slug,
    retry: false,
  });

  const post = postRes?.status === 200 ? postRes.body.post : null;

  useEffect(() => {
    if (post && slug) {
      trackPageView(`/blog/${slug}`, 'blog');
    }
  }, [post, slug]);

  if (isLoading) return <div className="w-full max-w-4xl mx-auto px-6 py-24 text-white animate-pulse">Loading post...</div>;
  if (isError || !post) return <div className="w-full max-w-4xl mx-auto px-6 py-24 text-white">Post not found.</div>;

  let parsedAst: ASTNode = { type: "doc", content: [] };
  try { parsedAst = JSON.parse(post.ast); } catch { /* Ignore parse error */ }

  return (
    <motion.div 
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      exit={{ opacity: 0 }}
      className="w-full min-h-screen bg-obsidian text-marble"
    >
      {/* ─── STANDALONE BLOG HERO ─── */}
      <section className="relative w-full h-[50vh] min-h-[400px] flex items-center overflow-hidden bg-obsidian border-b-4 border-ares-cyan">
        <img src={post.thumbnail || "/api/media/1776551060548-favicon.webp"} alt={post.title} className={`absolute inset-0 w-full h-full opacity-60 mix-blend-luminosity ${post.thumbnail ? 'object-cover' : 'object-contain p-16 bg-black/80'}`} />
        <div className="absolute inset-0 bg-gradient-to-t from-obsidian via-obsidian/70 to-transparent"></div>
        
        {/* Motif: Glowing orb overlay */}
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[80vh] h-[80vh] rounded-full border border-ares-cyan/10 shadow-[0_0_120px_rgba(0,192,192,0.15)] pointer-events-none mix-blend-screen animate-pulse-slow" aria-hidden="true"></div>
        
        <motion.div 
          initial={{ y: 20, opacity: 0 }}
          animate={{ y: 0, opacity: 1 }}
          transition={{ delay: 0.1 }}
          className="relative z-10 max-w-4xl mx-auto px-6 w-full mt-16"
        >
          <Link to="/blog" className="text-ares-gold hover:text-white uppercase tracking-widest text-xs font-bold transition-all flex items-center gap-2 mb-6 w-fit">
            <span>&larr;</span> Back to all posts
          </Link>
          <div className="flex flex-col md:flex-row md:items-center gap-4 mb-4">
             <span className="w-fit px-4 py-1.5 rounded-full text-xs font-bold uppercase tracking-widest bg-ares-cyan/20 text-ares-cyan border border-ares-cyan/50 shadow-[0_0_15px_rgba(0,192,192,0.4)]">
               {post.date && !isNaN(new Date(post.date).getTime()) ? format(new Date(post.date), 'MMMM do, yyyy') : "Unpublished"}
             </span>
             {(post.author_avatar || post.author_nickname) && (
               <div className="flex items-center gap-2 px-3 py-1.5 rounded-full bg-white/5 border border-white/10 w-fit">
                 <img 
                   src={post.author_avatar || `https://api.dicebear.com/7.x/bottts/svg?seed=${post.author_nickname || post.slug}`}
                   alt="Author"
                   className="w-6 h-6 rounded-full object-cover border border-white/20"
                 />
                 <span className="text-sm text-white">{post.author_nickname || "ARES Author"}</span>
               </div>
             )}
            {isEditor && (
              <Link 
                to={`/dashboard/blog/${post.slug}`}
                className="w-fit flex items-center gap-2 md:ml-auto px-4 py-1.5 rounded-full text-xs font-bold uppercase tracking-widest bg-ares-gold/10 hover:bg-ares-gold text-ares-gold hover:text-black border border-ares-gold/30 transition-all shadow-lg backdrop-blur-sm"
              >
                <Edit2 size={14} /> Edit Post
              </Link>
            )}
          </div>
          <h1 className="text-4xl md:text-6xl font-bold text-white tracking-tighter drop-shadow-2xl">
            {post.title}
          </h1>
        </motion.div>
      </section>

      {/* ─── BLOG CONTENT BODY ─── */}
      <div className="w-full max-w-4xl mx-auto px-6 py-12 md:py-24">
        <motion.article
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.2 }}
          className="prose prose-invert lg:prose-lg max-w-none prose-headings:text-white prose-p:text-white prose-a:text-ares-gold prose-a:focus-visible:outline-none prose-a:focus-visible:ring-2 prose-a:focus-visible:ring-ares-cyan prose-a:rounded"
        >
          <TiptapRenderer node={parsedAst} />

          {/* Comments (auth-gated) */}
          {slug && <CommentSection targetType="post" targetId={slug} />}
        </motion.article>
      </div>
    </motion.div>
  );
}

import { useParams, Link } from "react-router-dom";
import { useQuery } from "@tanstack/react-query";
import { format, isBefore } from "date-fns";
import { motion } from "framer-motion";
import TiptapRenderer, { type ASTNode } from "../components/TiptapRenderer";
import CommentSection from "../components/CommentSection";
import EventSignups from "../components/EventSignups";
import { DEFAULT_COVER_IMAGE } from "../utils/constants";
import { api } from "../api/client";

interface EventRow {
  id: string;
  title: string;
  date_start: string;
  date_end: string | null;
  location: string | null;
  description: string;
  cover_image: string | null;
  is_potluck: number | null;
  is_volunteer: number | null;
}

import { Calendar, Edit2 } from "lucide-react";
import { GreekMeander } from "../components/GreekMeander";
import { useSession } from "../utils/auth-client";
import { downloadICS } from "../utils/calendar";

export default function EventDetail() {
  const { id } = useParams<{ id: string }>();
  const { data: session } = useSession();

  const userRole = (session?.user as Record<string, unknown>)?.role || "user";
  const isEditor = userRole === "admin" || userRole === "author";

  const { data: eventRes, isLoading, isError } = api.events.getEvent.useQuery({
    queryKey: ["event", id],
    params: { id: id || "" },
    enabled: !!id,
    retry: false,
  });

  const event = eventRes?.status === 200 ? eventRes.body.event : null;

  if (isLoading) return <div className="w-full min-h-[50vh] flex items-center justify-center text-ares-gold animate-pulse font-heading tracking-widest">Consulting the Oracle...</div>;
  if (isError || !event) return <div className="w-full max-w-4xl mx-auto px-6 py-24 text-white font-mono text-center">Event Record Erased or Unfound.</div>;

  const isPast = isBefore(new Date(event.date_start), new Date());
  
  const handleSaveToCalendar = () => {
    if (event) {
      downloadICS(event);
    }
  };

  // Try to parse description as Tiptap AST. If it fails, treat as a legacy plain-text description.
  let parsedAst: ASTNode | null;
  try {
    parsedAst = JSON.parse(event.description);
    if (!parsedAst || parsedAst.type !== "doc") parsedAst = null;
  } catch {
    parsedAst = null;
  }

  const startDate = new Date(event.date_start);

  return (
    <motion.div 
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      exit={{ opacity: 0 }}
      className="w-full min-h-screen bg-obsidian text-marble"
    >
      {/* ─── STANDALONE EVENT HERO ─── */}
      <section className="relative w-full h-[50vh] min-h-[400px] flex items-center overflow-hidden bg-obsidian border-b-4 border-ares-bronze">
        <GreekMeander variant="thick" opacity="opacity-60" className="absolute bottom-[-1px] left-0 z-10" />
        <img src={event.cover_image || DEFAULT_COVER_IMAGE} alt={event.title} className={`absolute inset-0 w-full h-full opacity-60 mix-blend-luminosity ${event.cover_image ? 'object-cover' : 'object-contain p-16 bg-black/80'}`} />
        <div className="absolute inset-0 bg-gradient-to-t from-obsidian via-obsidian/70 to-transparent"></div>
        
        {/* Motif: Glowing shield orb (Aegis) overlay */}
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[80vh] h-[80vh] rounded-full border border-ares-gold/10 shadow-[0_0_120px_rgba(192,0,0,0.15)] pointer-events-none mix-blend-screen animate-pulse-slow" aria-hidden="true"></div>
        
        <motion.div 
          initial={{ y: 20, opacity: 0 }}
          animate={{ y: 0, opacity: 1 }}
          transition={{ delay: 0.1 }}
          className="relative z-10 max-w-5xl mx-auto px-6 w-full mt-16"
        >
          <Link to="/events" className="text-ares-gold hover:text-white uppercase tracking-widest text-xs font-bold transition-all flex items-center gap-2 mb-6 w-fit">
            <span>&larr;</span> Back to Archive
          </Link>
          <div className="flex flex-col md:flex-row md:items-center gap-4 mb-4">
            <span className={`w-fit px-4 py-1.5 rounded-full text-xs font-bold uppercase tracking-widest ${isPast ? "bg-obsidian text-white/60" : "bg-ares-red/20 text-ares-red border border-ares-red/50 shadow-[0_0_15px_rgba(192,0,0,0.4)]"}`}>
              {isPast ? "Historical Record" : "Upcoming Event"}
            </span>
            
            {!isPast && (
              <button 
                onClick={handleSaveToCalendar}
                className="w-fit flex items-center gap-2 px-4 py-1.5 rounded-full text-xs font-bold uppercase tracking-widest bg-obsidian/80 hover:bg-ares-gold text-white hover:text-black border border-white/10 hover:border-ares-gold transition-all shadow-lg backdrop-blur-sm"
              >
                <Calendar size={14} /> Add to Calendar
              </button>
            )}
            {isEditor && (
              <Link 
                to={`/dashboard/event/${event.id}`}
                className="w-fit flex items-center gap-2 px-4 py-1.5 rounded-full text-xs font-bold uppercase tracking-widest bg-ares-cyan/10 hover:bg-ares-cyan text-ares-cyan hover:text-black border border-ares-cyan/30 transition-all shadow-lg backdrop-blur-sm"
              >
                <Edit2 size={14} /> Edit Event
              </Link>
            )}
          </div>
          <h1 className="text-5xl md:text-7xl font-bold text-white leading-tight uppercase font-heading drop-shadow-2xl">
            {event.title}
          </h1>
          <div className="mt-8 flex flex-col md:flex-row gap-6 text-ares-bronze font-medium text-lg lg:text-xl">
            <p className="flex items-center gap-2">
              <span className="text-white">Date:</span> {format(startDate, 'EEEE, MMMM do, yyyy')}
            </p>
            {event.location && (
              <p className="flex items-center gap-2">
                <span className="text-white">Location:</span> {event.location}
              </p>
            )}
          </div>
        </motion.div>
      </section>

      {/* ─── EVENT CONTENT BODY ─── */}
      <section className="relative w-full max-w-5xl mx-auto px-6 py-16 flex flex-col md:flex-row gap-12">
        {/* Motif: Ionic Pillar Divider on Desktop */}
        <div className="hidden md:flex flex-col items-center shrink-0 w-8 opacity-20" aria-hidden="true">
          <div className="w-8 h-4 border-b-2 border-ares-gold rounded-t-lg mb-2"></div>
          <div className="w-2 flex-1 bg-gradient-to-b from-ares-gold to-ares-bronze/10 rounded-full"></div>
          <div className="w-8 h-4 border-t-2 border-ares-bronze/10 rounded-b-lg mt-2"></div>
        </div>

        <motion.article 
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.2 }}
          className="prose prose-invert lg:prose-lg max-w-none w-full prose-headings:text-white prose-headings:font-heading prose-headings:uppercase prose-p:text-white prose-a:text-ares-gold prose-img:ares-cut prose-img:border prose-img:border-white/10"
        >
          {parsedAst ? (
            <TiptapRenderer node={parsedAst} />
          ) : (
            <p className="whitespace-pre-wrap text-xl leading-relaxed">{event.description}</p>
          )}

          {/* Sign-Up Sheet & Comments (auth-gated) */}
          {id && <EventSignups eventId={id} isPotluck={event.is_potluck === 1} isVolunteer={event.is_volunteer === 1} />}
          {id && <CommentSection targetType="event" targetId={id} />}
        </motion.article>
      </section>
    </motion.div>
  );
}

import { useMemo } from "react";
import { useQuery } from "@tanstack/react-query";
import { isAfter, subDays, addDays, parseISO } from "date-fns";
import { motion } from "framer-motion";
import SEO from "../components/SEO";
import { api } from "../api/client";

import { EventCard, EventItem } from "../components/events/EventCard";
import CompetitionBanner from "../components/CompetitionBanner";

export default function Events() {
  const { data: eventsRes, isLoading } = api.events.getEvents.useQuery({
    queryKey: ["events"],
  });
  const events = (eventsRes?.body as any)?.events || [];

  const { data: calendarRes } = api.events.getCalendarConfig.useQuery({
    queryKey: ["calendar_config"],
  });
  const calendarData = calendarRes?.status === 200 ? calendarRes.body : null;

  // EFF-N01: Memoize calendar configuration mapping
  const calendars = useMemo(() => {
    if (!calendarData) return [];
    return [
      { id: calendarData.calendarIdInternal, color: "%23A32929" },
      { id: calendarData.calendarIdOutreach, color: "%23BE6D00" },
      { id: calendarData.calendarIdExternal, color: "%2329527A" }
    ].filter(c => c.id);
  }, [calendarData]);

  const iframeSrc = useMemo(() => {
    if (calendars.length === 0) return "";
    return `https://calendar.google.com/calendar/embed?${calendars.map(c => `src=${encodeURIComponent(c.id as string)}&color=${c.color}`).join("&")}&ctz=${encodeURIComponent(Intl.DateTimeFormat().resolvedOptions().timeZone)}&bgcolor=%23ffffff&showPrint=0&showTabs=1&showCalendars=1`;
  }, [calendars]);
  
  // EFF-N02: Memoize complex filtering and sorting
  const { 
    upcomingOutreach, 
    upcomingPractices, 
    upcomingExternal, 
    pastOutreach, 
    pastPractices,
    activeCompetition
  } = useMemo(() => {
    const now = new Date();
    const bufferTime = subDays(now, 1);

    const outreach = events.filter(e => e.category === "outreach");
    const internal = events.filter(e => e.category === "internal");
    const external = events.filter(e => e.category === "external");

    const sortAsc = (a: EventItem, b: EventItem) => parseISO(a.date_start).getTime() - parseISO(b.date_start).getTime();

    return {
      upcomingOutreach: outreach.filter(e => isAfter(parseISO(e.date_start), bufferTime)).sort(sortAsc),
      upcomingPractices: internal.filter(e => isAfter(parseISO(e.date_start), bufferTime)).sort(sortAsc),
      upcomingExternal: external.filter(e => isAfter(parseISO(e.date_start), bufferTime)).sort(sortAsc),
      pastOutreach: outreach.filter(e => !isAfter(parseISO(e.date_start), bufferTime)).sort(sortAsc).reverse(),
      pastPractices: internal.filter(e => !isAfter(parseISO(e.date_start), bufferTime)).sort(sortAsc).reverse(),
      activeCompetition: events.find(e => {
        if (!e.tba_event_key) return false;
        const start = parseISO(e.date_start);
        const end = e.date_end ? parseISO(e.date_end) : addDays(start, 3);
        return now >= start && now <= end;
      })
    };
  }, [events]);

  return (
    <motion.div 
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      exit={{ opacity: 0 }}
      className="w-full flex-grow flex flex-col bg-obsidian min-h-screen"
    >
      <SEO title="Event Schedule" description="Upcoming competitions, outreach demos, and build sessions for ARES 23247." />
      {/* ─── HEADER ─── */}
      <section className="relative w-full py-24 px-6 overflow-hidden flex flex-col items-center text-center">
        <div className="absolute inset-0 w-full h-full">
          <div className="absolute inset-0 bg-ares-red/10 mix-blend-screen pointer-events-none"></div>
          <div className="absolute top-0 left-0 w-full h-96 bg-gradient-to-b from-ares-red/20 to-transparent pointer-events-none blur-3xl"></div>
        </div>

        <motion.div 
          initial={{ y: 20, opacity: 0 }}
          animate={{ y: 0, opacity: 1 }}
          transition={{ delay: 0.1 }}
          className="relative z-10 max-w-4xl mx-auto space-y-6 bg-obsidian p-8 rounded-2xl border border-white/10 shadow-2xl"
        >
          {/* ACC-F01: Fixed H1 for screen readers while maintaining visual style */}
          <h1 className="text-5xl md:text-7xl font-bold text-white tracking-tight">
            Team <span className="text-ares-gold">Events</span>
          </h1>
          <p className="text-xl md:text-2xl text-marble font-medium max-w-2xl mx-auto">
            Join us at our upcoming competitions, community outreach demos, and robotics workshops.
          </p>
        </motion.div>
      </section>

      {/* ─── EVENTS CONTAINER ─── */}
      <section className="w-full max-w-5xl mx-auto px-6 pb-32 flex flex-col gap-16">
        {isLoading ? (
          <div className="flex justify-center items-center py-20">
            <div className="w-12 h-12 border-4 border-ares-gold/30 border-t-ares-gold rounded-full animate-spin"></div>
          </div>
        ) : (
          <motion.div
            initial={{ opacity: 0, y: 30 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.2 }}
          >
            {/* Google Calendar Native IFrame */}
            <div className="flex flex-col gap-8 mb-16">
              <div className="flex items-center gap-4">
                <h2 className="text-3xl font-bold text-white">Full Calendar</h2>
                <div className="h-px flex-1 bg-gradient-to-r from-ares-gold/50 to-transparent"></div>
              </div>
              {calendars.length > 0 ? (
                <div className="w-full bg-black/40 border border-white/10 ares-cut-sm overflow-hidden shadow-lg">
                  <iframe 
                    title="Google Calendar"
                    src={iframeSrc} 
                    className="w-full h-[600px] md:h-[700px] border-0"
                    style={{ filter: "invert(1) hue-rotate(180deg) opacity(0.85) contrast(1.05)" }}
                    allowFullScreen
                    // SEC-F04: Added sandbox for security hardening
                    sandbox="allow-scripts allow-same-origin allow-popups allow-forms"
                  />
                </div>
              ) : (
                <div className="w-full h-[600px] bg-black/40 border border-white/10 ares-cut-sm flex items-center justify-center text-marble/50">
                  <div className="w-8 h-8 border-2 border-ares-gold/30 border-t-ares-gold rounded-full animate-spin"></div>
                </div>
              )}

              {/* Subscribe Buttons */}
              {calendars.length > 0 && (
                <div className="bg-black/40 border border-white/10 ares-cut-sm p-6">
                  <h3 className="text-sm font-black uppercase tracking-widest text-marble/50 mb-4">Subscribe to Our Calendars</h3>
                  <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
                    {[
                      { id: calendarData?.calendarIdInternal, name: "ARES Practices", color: "ares-red" },
                      { id: calendarData?.calendarIdOutreach, name: "ARES Outreach & Volunteer", color: "ares-gold" },
                      { id: calendarData?.calendarIdExternal, name: "ARES Community Spotlight", color: "ares-cyan" },
                    ].filter(c => c.id).map((cal) => (
                      <div key={cal.name} className="flex flex-col gap-2 bg-black/40 ares-cut-sm p-4 border border-white/5">
                        <span className="text-xs font-bold text-white uppercase tracking-wider">{cal.name}</span>
                        <div className="flex gap-2">
                          <a
                            href={`https://calendar.google.com/calendar/r?cid=${encodeURIComponent(cal.id as string)}`}
                            target="_blank"
                            rel="noreferrer"
                            className={`flex-1 text-center px-3 py-2 bg-${cal.color}/20 hover:bg-${cal.color}/40 text-${cal.color} border border-${cal.color}/30 ares-cut-sm text-xs font-black uppercase tracking-widest transition-all`}
                          >
                            + Google
                          </a>
                          <a
                            href={`https://calendar.google.com/calendar/ical/${encodeURIComponent(cal.id as string)}/public/basic.ics`}
                            target="_blank"
                            rel="noreferrer"
                            className="flex-1 text-center px-3 py-2 bg-white/5 hover:bg-white/10 text-white border border-white/10 ares-cut-sm text-xs font-black uppercase tracking-widest transition-all"
                          >
                            + iCal
                          </a>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </div>

            {/* Upcoming Outreach Events */}
            <div className="flex flex-col gap-8">
              <div className="flex items-center gap-4">
                <h2 className="text-3xl font-bold text-white">Upcoming Outreach</h2>
                <div className="h-px flex-1 bg-gradient-to-r from-ares-gold/50 to-transparent"></div>
              </div>
              
              {upcomingOutreach.length === 0 ? (
                <div className="bg-white/5 border border-white/10 hero-card p-12 text-center">
                  <p className="text-marble text-lg">No upcoming outreach events are currently scheduled.</p>
                </div>
              ) : (
                <div className="flex flex-col gap-6">
                  {upcomingOutreach.map(evt => <EventCard key={evt.id} event={evt} isPast={false} />)}
                </div>
              )}
            </div>

            {/* Upcoming External / Community Events */}
            {upcomingExternal.length > 0 && (
              <div className="flex flex-col gap-8 mt-12">
                <div className="flex items-center gap-4">
                  <h2 className="text-2xl font-bold text-white">External & Community Events</h2>
                  <div className="h-px flex-1 bg-gradient-to-r from-ares-cyan/50 to-transparent"></div>
                </div>
                
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  {upcomingExternal.map(evt => <EventCard key={evt.id} event={evt} isPast={false} />)}
                </div>
              </div>
            )}

            {/* Upcoming Practices */}
            {upcomingPractices.length > 0 && (
              <div className="flex flex-col gap-8 mt-12">
                <div className="flex items-center gap-4">
                  <h2 className="text-2xl font-bold text-white">Upcoming Practices</h2>
                  <div className="h-px flex-1 bg-gradient-to-r from-ares-red/50 to-transparent"></div>
                </div>
                
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  {upcomingPractices.map(evt => <EventCard key={evt.id} event={evt} isPast={false} />)}
                </div>
              </div>
            )}

            {/* Archival - Past Events */}
            {(pastOutreach.length > 0 || pastPractices.length > 0) && (
              <div className="mt-16 bg-white/5 border border-white/10 ares-cut p-8 backdrop-blur-sm">
                <h2 className="text-4xl font-black text-white tracking-tight mb-8">Event Archive</h2>
                
                {pastOutreach.length > 0 && (
                  <div className="flex flex-col gap-6 mb-12">
                    <div className="flex items-center gap-4">
                      <h3 className="text-xl font-bold text-ares-gold uppercase tracking-widest">Past Outreach</h3>
                      <div className="h-px flex-1 bg-gradient-to-r from-ares-gold/30 to-transparent"></div>
                    </div>
                    <div className="flex flex-col gap-4">
                      {pastOutreach.map(evt => <EventCard key={evt.id} event={evt} isPast={true} />)}
                    </div>
                  </div>
                )}

                {pastPractices.length > 0 && (
                  <div className="flex flex-col gap-6">
                    <div className="flex items-center gap-4">
                      <h3 className="text-xl font-bold text-ares-red uppercase tracking-widest">Past Practices</h3>
                      <div className="h-px flex-1 bg-gradient-to-r from-ares-red/30 to-transparent"></div>
                    </div>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                      {pastPractices.map(evt => <EventCard key={evt.id} event={evt} isPast={true} />)}
                    </div>
                  </div>
                )}
              </div>
            )}
          </motion.div>
        )}
      </section>

      {activeCompetition?.tba_event_key && (
        <CompetitionBanner eventKey={activeCompetition.tba_event_key} />
      )}
    </motion.div>
  );
}

import SEO from "../components/SEO";
import LazyImage from "../components/LazyImage";
import { useQuery } from "@tanstack/react-query";
import { api } from "../api/client";

interface R2MediaResponse {
  media: {
    key: string;
    size: number;
    uploaded: string;
    httpMetadata: {
      contentType: string;
    };
  }[];
}

export default function Gallery() {
  const { data: mediaRes, isLoading, isError } = api.media.getMedia.useQuery({
    queryKey: ["media"],
  });

  const data = mediaRes?.status === 200 ? mediaRes.body : null;

  // Filter only images and reverse to show newest first
  const photos = data?.media
    ?.filter(m => m.httpMetadata?.contentType?.startsWith("image/"))
    ?.reverse() || [];

  return (
    <div className="w-full min-h-screen bg-obsidian text-marble py-8">
      <SEO title="Team Gallery" description="Explore behind the scenes of ARES 23247. From raw CAD prototypes and machining directly to the qualification arenas." />
      <div className="w-full max-w-7xl mx-auto px-6 py-12 md:py-24">
      <div className="mb-12">
        <h3 className="text-ares-gold font-bold uppercase tracking-widest text-sm mb-2">Build Season &amp; Comps</h3>
        <h1 className="text-4xl md:text-6xl font-bold text-white tracking-tighter shadow-sm">
          Team <span className="text-ares-red">Gallery</span>
        </h1>
        <p className="text-white/60 mt-4 max-w-2xl text-balance">
          Explore behind the scenes of ARES 23247. From raw CAD prototypes and machining all the way to performing under the bright lights of our qualification arenas.
        </p>
      </div>

      {isLoading ? (
        <div className="flex justify-center py-20">
          <div className="w-12 h-12 border-4 border-white/10 border-t-ares-red rounded-full animate-spin"></div>
        </div>
      ) : isError ? (
        <div className="text-ares-red bg-ares-red/10 border border-ares-red ares-cut-sm p-4 font-bold text-center">
          Failed to load gallery images. Please try again later.
        </div>
      ) : photos.length === 0 ? (
        <div className="text-marble/50 italic text-center py-12 font-medium">No photos found in the ARES gallery.</div>
      ) : (
        <div className="columns-1 sm:columns-2 lg:columns-3 gap-6 space-y-6">
          {photos.map((photo, index) => {
            // Assign varying aspect ratios for masonry visualization
            const aspects = ["aspect-video", "aspect-[3/4]", "aspect-[4/5]", "aspect-square"];
            const assignedAspect = aspects[index % aspects.length];

            return (
              <div
                key={photo.key}
                className={`relative w-full overflow-hidden ares-cut glass-card group cursor-pointer transition-transform duration-500 hover:-translate-y-2 hover:shadow-[0_15px_30px_rgba(220,38,38,0.1)] ${assignedAspect}`}
              >
                <LazyImage 
                   src={`/api/media/${photo.key}`} 
                   alt={photo.key} 
                   className="absolute inset-0 w-full h-full"
                   imgClassName="transition-transform duration-700 group-hover:scale-105"
                />
                <div className="absolute inset-0 z-20 bg-gradient-to-t from-black/80 via-black/0 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300 flex items-end p-6">
                  <p className="text-white font-medium text-sm drop-shadow-md truncate w-full">{photo.key.split("-").slice(1).join("-")}</p>
                </div>
              </div>
            );
          })}
        </div>
      )}
      </div>
    </div>
  );
}

import { useState } from "react";
import { motion } from "framer-motion";
import { Rocket, Wrench, Code, PenTool, CheckCircle, GraduationCap } from "lucide-react";
import SEO from "../components/SEO";
import { GreekMeander } from "../components/GreekMeander";
import Turnstile from "../components/Turnstile";
import { api } from "../api/client";
import { inquirySchema } from "../schemas/inquirySchema";

export default function Join() {
  const [role, setRole] = useState<"student" | "mentor">("student");
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [phone, setPhone] = useState("");
  const [school, setSchool] = useState("");
  const [grade, setGrade] = useState("");
  const [occupation, setOccupation] = useState("");
  const [interests, setInterests] = useState<string[]>([]);
  const [additional, setAdditional] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitStatus, setSubmitStatus] = useState<"idle" | "success" | "error">("idle");
  const [errorMessage, setErrorMessage] = useState("");
  const [turnstileToken, setTurnstileToken] = useState("");

  const submitMutation = api.inquiries.submit.useMutation({
    onSuccess: (res) => {
      if (res.status === 200 || res.status === 207) {
        setSubmitStatus("success");
        setName(""); setEmail(""); setPhone(""); setSchool(""); setGrade(""); setOccupation(""); setInterests([]); setAdditional("");
      } else {
        setSubmitStatus("error");
        setErrorMessage((res.body as any).error || "Something went wrong");
      }
    },
    onError: (err) => {
      setSubmitStatus("error");
      setErrorMessage(err.message || "Network error");
    }
  });

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setSubmitStatus("idle");
    try {
      const metadata = role === "student" 
        ? { school, grade, interests, additional, phone: phone || undefined }
        : { occupation, interests, additional, phone: phone || undefined };

      const payloadResult = inquirySchema.safeParse({ type: role, name, email, metadata, turnstileToken });
      if (!payloadResult.success) {
        throw new Error(payloadResult.error.issues[0].message);
      }

      submitMutation.mutate({ body: payloadResult.data as any });
    } catch (err) {
      setSubmitStatus("error");
      setErrorMessage(err instanceof Error ? err.message : "Something went wrong. Please try again.");
    }
  };

  return (
    <div className="flex flex-col w-full min-h-screen bg-obsidian text-marble">
      <SEO title="Join the Team — ARES 23247" description="Become a student or mentor for the ARES 23247 robotics team." />

      <section className="relative py-24 overflow-hidden border-b border-white/5">
        <div className="absolute inset-0 bg-ares-red/5 bg-[radial-gradient(ellipse_at_center,rgba(220,38,38,0.15)_0,rgba(0,0,0,0)_70%)] opacity-50 blur-[80px]" />
        
        <div className="max-w-5xl mx-auto px-6 relative z-10 text-center">
          <motion.div
            initial={{ opacity: 0, y: 30 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6 }}
            className="bg-obsidian p-8 rounded-2xl border border-white/10 shadow-2xl inline-block"
          >
            <p aria-hidden="true" className="bg-ares-red text-white inline-block px-4 py-1 rounded-full uppercase tracking-[0.3em] font-bold text-xs mb-6 shadow-lg shadow-ares-red/20 before:content-['Enrollment_Open']"></p>
            <p className="sr-only">Enrollment Open</p>
            <h1 className="text-5xl md:text-7xl font-black text-white mb-6 uppercase tracking-tighter italic">
              Join <span aria-hidden="true" className="bg-ares-red px-6 py-1 ares-cut shadow-xl inline-block text-white ml-2 before:content-['ARES.']"></span>
              <span className="sr-only">ARES.</span>
            </h1>
            <p className="text-marble text-xl max-w-2xl mx-auto leading-relaxed border-t border-white/10 pt-8">
              We are actively looking for forward-thinking students and dedicated mentors to expand our operations. No prior experience is required—only the drive to learn and the grit to succeed.
            </p>
          </motion.div>
        </div>
      </section>

      <section className="py-20 bg-obsidian relative">
        <GreekMeander variant="thin" opacity="opacity-50" className="absolute top-0 left-0" />
        
        <div className="max-w-6xl mx-auto px-6 grid grid-cols-1 lg:grid-cols-12 gap-16">
          <motion.div 
            initial={{ opacity: 0, x: -30 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ duration: 0.6, delay: 0.2 }}
            className="lg:col-span-4"
          >
            <h2 className="text-3xl font-black text-white mb-6 uppercase tracking-tight">The ARES <span className="bg-ares-red px-4 py-1 ares-cut shadow-xl inline-block text-white">Advantage</span></h2>
            
            <div className="space-y-6">
              <div className="flex gap-4">
                <div className="mt-1 flex-shrink-0 w-10 h-10 rounded-full bg-ares-red/10 flex items-center justify-center text-ares-red border border-ares-red/20 shadow-[0_0_15px_rgba(220,38,38,0.2)]">
                  <Wrench size={18} />
